window.COMPLIANCE_REF = window.COMPLIANCE_REF || {};
window.COMPLIANCE_REF["dora_detailed"] = {"label": "DORA (détaillé)","description": "Digital Operational Resilience Act (UE 2022/2554) — 211 exigences au niveau paragraphe","description_en": "Digital Operational Resilience Act (EU 2022/2554) — 211 paragraph-level requirements","color": "#3a7ca5","measures": [{"ref": "DORA-5.1","theme": "Gouvernance TIC","theme_en": "ICT Governance","mesure": "Les entités financières disposent d'un cadre de gouvernance et de contrôle interne garantissant une gestion efficace et prudente du risque TIC","mesure_en": "Financial entities shall have in place an internal governance and control framework that ensures an effective and prudent management of ICT risk, in a","description": "Les entités financières disposent d'un cadre de gouvernance et de contrôle interne garantissant une gestion efficace et prudente du risque TIC, conformément à l'article 6, paragraphe 4, afin d'atteindre un niveau élevé de résilience opérationnelle numérique.","description_en": "Financial entities shall have in place an internal governance and control framework that ensures an effective and prudent management of ICT risk, in accordance with Article 6(4), in order to achieve a high level of digital operational resilience."},{"ref": "DORA-5.2","theme": "Gouvernance TIC","theme_en": "ICT Governance","mesure": "L'organe de direction de l'entité financière définit, approuve, supervise et est responsable de la mise en œuvre de toutes les dispositions relatives","mesure_en": "The management body of the financial entity shall define, approve, oversee and be responsible for the implementation of all arrangements related to th","description": "L'organe de direction de l'entité financière définit, approuve, supervise et est responsable de la mise en œuvre de toutes les dispositions relatives au cadre de gestion du risque TIC visé à l'article 6, paragraphe 1.\n(a) assumer la responsabilité ultime de la gestion du risque TIC de l'entité financière ;\n(b) mettre en place des politiques visant à garantir le maintien de normes élevées de disponibilité, d'authenticité, d'intégrité et de confidentialité des données ;\n(c) définir des rôles et responsabilités clairs pour toutes les fonctions liées aux TIC et mettre en place des dispositifs de gouvernance appropriés garantissant une communication, une coopération et une coordination efficaces et rapides entre ces fonctions ;\n(d) assumer la responsabilité globale de la définition et de l'approbation de la stratégie de résilience opérationnelle numérique visée à l'article 6, paragraphe 8, y compris la détermination du niveau de tolérance au risque TIC approprié de l'entité financière, visé à l'article 6, paragraphe 8, point b) ;\n(e) approuver, superviser et réexaminer périodiquement la mise en œuvre de la politique de continuité des activités TIC et des plans de réponse et de reprise TIC de l'entité financière, qui peuvent être adoptés en tant que politique spécifique dédiée, conformément à l'article 11, paragraphe 1 ;\n(f) approuver et réexaminer périodiquement les plans d'audit TIC internes de l'entité financière, les audits TIC et les modifications substantielles qui y sont apportées ;\n(g) allouer et réexaminer périodiquement le budget approprié pour satisfaire les besoins de résilience opérationnelle numérique de l'entité financière au regard de tous les types de ressources, y compris les programmes de formation pertinents en matière de sensibilisation à la sécurité TIC et les compétences en résilience opérationnelle numérique pour l'ensemble du personnel ;\n(h) approuver et réexaminer périodiquement la politique de l'entité financière relative aux arrangements d'utilisation de services TIC fournis par des prestataires tiers TIC ;\n(i) mettre en place, au niveau de l'entité, des canaux de notification leur permettant d'être dûment informés des arrangements conclus avec des prestataires tiers TIC, de toute modification substantielle prévue, de l'impact potentiel de ces modifications, et des incidents liés aux TIC et des cybermenaces significatives.","description_en": "The management body of the financial entity shall define, approve, oversee and be responsible for the implementation of all arrangements related to the ICT risk management framework referred to in Article 6(1).\n(a) bear the ultimate responsibility for managing the financial entity’s ICT risk;\n(b) put in place policies that aim to ensure the maintenance of high standards of availability, authenticity, integrity and confidentiality, of data;\n(c) set clear roles and responsibilities for all ICT-related functions and establish appropriate governance arrangements to ensure effective and timely communication, cooperation and coordination among those functions;\n(d) bear the overall responsibility for setting and approving the digital operational resilience strategy as referred to in Article 6(8), including the determination of the appropriate risk tolerance level of ICT risk of the financial entity, as referred to in Article 6(8), point (b);\n(e) approve, oversee and periodically review the im"},{"ref": "DORA-5.3","theme": "Gouvernance TIC","theme_en": "ICT Governance","mesure": "Les entités financières, autres que les micro-entreprises, créent un poste pour le suivi des arrangements conclus avec les prestataires tiers TIC","mesure_en": "Financial entities, other than microenterprises, shall establish a role in order to monitor the arrangements concluded with ICT third-party service pr","description": "Les entités financières, autres que les micro-entreprises, créent un poste afin de surveiller les arrangements conclus avec les prestataires tiers de services TIC concernant l'utilisation de services TIC, ou désignent un membre de la direction générale chargé de superviser l'exposition aux risques y afférente et la documentation pertinente.","description_en": "Financial entities, other than microenterprises, shall establish a role in order to monitor the arrangements concluded with ICT third-party service providers on the use of ICT services, or shall designate a member of senior management as responsible for overseeing the related risk exposure and relevant documentation."},{"ref": "DORA-5.4","theme": "Gouvernance TIC","theme_en": "ICT Governance","mesure": "Les membres de l'organe de direction de l'entité financière maintiennent activement à jour des connaissances et compétences suffisantes pour comprend","mesure_en": "Members of the management body of the financial entity shall actively keep up to date with sufficient knowledge and skills to understand and assess IC","description": "Les membres de l'organe de direction de l'entité financière maintiennent activement à jour des connaissances et compétences suffisantes pour comprendre et évaluer le risque TIC et son impact sur les opérations de l'entité financière, notamment en suivant régulièrement des formations spécifiques, proportionnées au risque TIC géré.","description_en": "Members of the management body of the financial entity shall actively keep up to date with sufficient knowledge and skills to understand and assess ICT risk and its impact on the operations of the financial entity, including by following specific training on a regular basis, commensurate to the ICT risk being managed."},{"ref": "DORA-6.1","theme": "Cadre de gestion des risques TIC","theme_en": "ICT Risk Management Framework","mesure": "Les entités financières disposent d'un cadre de gestion du risque TIC solide, complet et bien documenté, intégré à leur système global de gestion des","mesure_en": "Financial entities shall have a sound, comprehensive and well-documented ICT risk management framework as part of their overall risk management system","description": "Les entités financières disposent d'un cadre de gestion du risque TIC solide, complet et bien documenté, intégré à leur système global de gestion des risques, leur permettant de traiter le risque TIC rapidement, efficacement et de manière exhaustive et de garantir un niveau élevé de résilience opérationnelle numérique.","description_en": "Financial entities shall have a sound, comprehensive and well-documented ICT risk management framework as part of their overall risk management system, which enables them to address ICT risk quickly, efficiently and comprehensively and to ensure a high level of digital operational resilience."},{"ref": "DORA-6.2","theme": "Cadre de gestion des risques TIC","theme_en": "ICT Risk Management Framework","mesure": "Le cadre de gestion du risque TIC comprend au minimum les stratégies, politiques, procédures, protocoles et outils TIC nécessaires pour protéger dûme","mesure_en": "The ICT risk management framework shall include at least strategies, policies, procedures, ICT protocols and tools that are necessary to duly and adeq","description": "Le cadre de gestion du risque TIC comprend au minimum les stratégies, politiques, procédures, protocoles et outils TIC nécessaires pour protéger dûment et adéquatement l'ensemble des actifs informationnels et des actifs TIC, y compris les logiciels, le matériel informatique, les serveurs, ainsi que pour protéger toutes les composantes physiques et infrastructures pertinentes, telles que les locaux, les centres de données et les zones sensibles désignées, afin de garantir que tous les actifs informationnels et actifs TIC sont correctement protégés contre les risques, y compris les dommages et les accès ou utilisations non autorisés.","description_en": "The ICT risk management framework shall include at least strategies, policies, procedures, ICT protocols and tools that are necessary to duly and adequately protect all information assets and ICT assets, including computer software, hardware, servers, as well as to protect all relevant physical components and infrastructures, such as premises, data centres and sensitive designated areas, to ensure that all information assets and ICT assets are adequately protected from risks including damage and unauthorised access or usage."},{"ref": "DORA-6.3","theme": "Cadre de gestion des risques TIC","theme_en": "ICT Risk Management Framework","mesure": "Conformément à leur cadre de gestion du risque TIC, les entités financières minimisent l'impact du risque TIC en déployant des stratégies, politiques","mesure_en": "In accordance with their ICT risk management framework, financial entities shall minimise the impact of ICT risk by deploying appropriate strategies, ","description": "Conformément à leur cadre de gestion du risque TIC, les entités financières minimisent l'impact du risque TIC en déployant des stratégies, politiques, procédures, protocoles et outils TIC appropriés. Elles fournissent des informations complètes et actualisées sur le risque TIC et sur leur cadre de gestion du risque TIC aux autorités compétentes, sur demande de celles-ci.","description_en": "In accordance with their ICT risk management framework, financial entities shall minimise the impact of ICT risk by deploying appropriate strategies, policies, procedures, ICT protocols and tools. They shall provide complete and updated information on ICT risk and on their ICT risk management framework to the competent authorities upon their request."},{"ref": "DORA-6.4","theme": "Cadre de gestion des risques TIC","theme_en": "ICT Risk Management Framework","mesure": "Les entités financières, autres que les micro-entreprises, confient la responsabilité de la gestion et de la supervision du risque TIC à une fonction","mesure_en": "Financial entities, other than microenterprises, shall assign the responsibility for managing and overseeing ICT risk to a control function and ensure","description": "Les entités financières, autres que les micro-entreprises, confient la responsabilité de la gestion et de la supervision du risque TIC à une fonction de contrôle et garantissent un niveau approprié d'indépendance de cette fonction de contrôle afin d'éviter les conflits d'intérêts. Les entités financières veillent à la séparation et à l'indépendance appropriées des fonctions de gestion du risque TIC, des fonctions de contrôle et des fonctions d'audit interne, conformément au modèle des trois lignes de défense ou à un modèle interne de gestion et de contrôle des risques.","description_en": "Financial entities, other than microenterprises, shall assign the responsibility for managing and overseeing ICT risk to a control function and ensure an appropriate level of independence of such control function in order to avoid conflicts of interest. Financial entities shall ensure appropriate segregation and independence of ICT risk management functions, control functions, and internal audit functions, according to the three lines of defence model, or an internal risk management and control model."},{"ref": "DORA-6.5","theme": "Cadre de gestion des risques TIC","theme_en": "ICT Risk Management Framework","mesure": "Le cadre de gestion du risque TIC est documenté et réexaminé au moins une fois par an, ou périodiquement pour les micro-entreprises, ainsi qu'à la su","mesure_en": "The ICT risk management framework shall be documented and reviewed at least once a year, or periodically in the case of microenterprises, as well as u","description": "Le cadre de gestion du risque TIC est documenté et réexaminé au moins une fois par an, ou périodiquement dans le cas des micro-entreprises, ainsi qu'à la suite d'incidents majeurs liés aux TIC, et conformément aux instructions prudentielles ou aux conclusions tirées des tests de résilience opérationnelle numérique ou des processus d'audit pertinents. Il est amélioré en permanence sur la base des enseignements tirés de la mise en œuvre et du suivi. Un rapport sur le réexamen du cadre de gestion du risque TIC est soumis à l'autorité compétente sur demande.","description_en": "The ICT risk management framework shall be documented and reviewed at least once a year, or periodically in the case of microenterprises, as well as upon the occurrence of major ICT-related incidents, and following supervisory instructions or conclusions derived from relevant digital operational resilience testing or audit processes. It shall be continuously improved on the basis of lessons derived from implementation and monitoring. A report on the review of the ICT risk management framework shall be submitted to the competent authority upon its request."},{"ref": "DORA-6.6","theme": "Cadre de gestion des risques TIC","theme_en": "ICT Risk Management Framework","mesure": "Le cadre de gestion du risque TIC des entités financières, autres que les micro-entreprises, fait l'objet d'un audit interne par des auditeurs de man","mesure_en": "The ICT risk management framework of financial entities, other than microenterprises, shall be subject to internal audit by auditors on a regular basi","description": "Le cadre de gestion du risque TIC des entités financières, autres que les micro-entreprises, fait l'objet d'un audit interne par des auditeurs de manière régulière, conformément au plan d'audit des entités financières. Ces auditeurs possèdent des connaissances, des compétences et une expertise suffisantes en matière de risque TIC, ainsi qu'une indépendance appropriée. La fréquence et l'orientation des audits TIC sont proportionnées au risque TIC de l'entité financière.","description_en": "The ICT risk management framework of financial entities, other than microenterprises, shall be subject to internal audit by auditors on a regular basis in line with the financial entities’ audit plan. Those auditors shall possess sufficient knowledge, skills and expertise in ICT risk, as well as appropriate independence. The frequency and focus of ICT audits shall be commensurate to the ICT risk of the financial entity."},{"ref": "DORA-6.7","theme": "Cadre de gestion des risques TIC","theme_en": "ICT Risk Management Framework","mesure": "Sur la base des conclusions du réexamen de l'audit interne, les entités financières établissent un processus formel de suivi, comprenant des règles po","mesure_en": "Based on the conclusions from the internal audit review, financial entities shall establish a formal follow-up process, including rules for the timely","description": "Sur la base des conclusions du réexamen de l'audit interne, les entités financières établissent un processus formel de suivi, comprenant des règles pour la vérification et la correction en temps utile des constatations critiques de l'audit TIC.","description_en": "Based on the conclusions from the internal audit review, financial entities shall establish a formal follow-up process, including rules for the timely verification and remediation of critical ICT audit findings."},{"ref": "DORA-6.8","theme": "Cadre de gestion des risques TIC","theme_en": "ICT Risk Management Framework","mesure": "Le cadre de gestion du risque TIC comprend une stratégie de résilience opérationnelle numérique définissant les modalités de mise en œuvre du cadre","mesure_en": "The ICT risk management framework shall include a digital operational resilience strategy setting out how the framework shall be implemented. To that ","description": "Le cadre de gestion du risque TIC comprend une stratégie de résilience opérationnelle numérique définissant les modalités de mise en œuvre du cadre. À cette fin, la stratégie de résilience opérationnelle numérique comprend des méthodes pour traiter le risque TIC et atteindre des objectifs TIC spécifiques, en :\n(a) expliquant comment le cadre de gestion du risque TIC soutient la stratégie et les objectifs commerciaux de l'entité financière ;\n(b) établissant le niveau de tolérance au risque TIC, conformément à l'appétit pour le risque de l'entité financière, et en analysant la tolérance d'impact pour les perturbations TIC ;\n(c) définissant des objectifs clairs de sécurité de l'information, y compris des indicateurs clés de performance et des métriques de risque clés ;\n(d) expliquant l'architecture TIC de référence et les modifications nécessaires pour atteindre des objectifs commerciaux spécifiques ;\n(e) décrivant les différents mécanismes mis en place pour détecter les incidents liés aux TIC, prévenir leur impact et s'en protéger ;\n(f) attestant de la situation actuelle de résilience opérationnelle numérique sur la base du nombre d'incidents majeurs liés aux TIC signalés et de l'efficacité des mesures préventives ;\n(g) mettant en œuvre des tests de résilience opérationnelle numérique conformément au chapitre IV du présent règlement ;\n(h) décrivant une stratégie de communication en cas d'incidents liés aux TIC dont la divulgation est requise conformément à l'article 14.","description_en": "The ICT risk management framework shall include a digital operational resilience strategy setting out how the framework shall be implemented. To that end, the digital operational resilience strategy shall include methods to address ICT risk and attain specific ICT objectives, by:\n(a) explaining how the ICT risk management framework supports the financial entity’s business strategy and objectives;\n(b) establishing the risk tolerance level for ICT risk, in accordance with the risk appetite of the financial entity, and analysing the impact tolerance for ICT disruptions;\n(c) setting out clear information security objectives, including key performance indicators and key risk metrics;\n(d) explaining the ICT reference architecture and any changes needed to reach specific business objectives;\n(e) outlining the different mechanisms put in place to detect ICT-related incidents, prevent their impact and provide protection from it;\n(f) evidencing the current digital operational resilience situatio"},{"ref": "DORA-6.9","theme": "Cadre de gestion des risques TIC","theme_en": "ICT Risk Management Framework","mesure": "Les entités financières peuvent, dans le cadre de la stratégie de résilience opérationnelle numérique visée au paragraphe 8, définir une stratégie gl","mesure_en": "Financial entities may, in the context of the digital operational resilience strategy referred to in paragraph 8, define a holistic ICT multi-vendor s","description": "Les entités financières peuvent, dans le cadre de la stratégie de résilience opérationnelle numérique visée au paragraphe 8, définir une stratégie globale TIC multi-fournisseurs, au niveau du groupe ou de l'entité, présentant les dépendances clés vis-à-vis des prestataires tiers de services TIC et expliquant la logique du mix d'approvisionnement auprès de prestataires tiers de services TIC.","description_en": "Financial entities may, in the context of the digital operational resilience strategy referred to in paragraph 8, define a holistic ICT multi-vendor strategy, at group or entity level, showing key dependencies on ICT third-party service providers and explaining the rationale behind the procurement mix of ICT third-party service providers."},{"ref": "DORA-6.10","theme": "Cadre de gestion des risques TIC","theme_en": "ICT Risk Management Framework","mesure": "Les entités financières peuvent, conformément au droit sectoriel de l'Union et national, externaliser les tâches de vérification de la conformité aux","mesure_en": "Financial entities may, in accordance with Union and national sectoral law, outsource the tasks of verifying compliance with ICT risk management requi","description": "Les entités financières peuvent, conformément au droit sectoriel de l'Union et national, externaliser les tâches de vérification de la conformité aux exigences de gestion du risque TIC à des entreprises intragroupe ou externes. En cas d'une telle externalisation, l'entité financière reste pleinement responsable de la vérification de la conformité aux exigences de gestion du risque TIC.","description_en": "Financial entities may, in accordance with Union and national sectoral law, outsource the tasks of verifying compliance with ICT risk management requirements to intra-group or external undertakings. In case of such outsourcing, the financial entity remains fully responsible for the verification of compliance with the ICT risk management requirements."},{"ref": "DORA-7.a","theme": "Systèmes TIC","theme_en": "ICT Systems","mesure": "adaptés à l'ampleur des opérations soutenant l'exercice de leurs activités, conformément au principe de proportionnalité visé à l'article 4","mesure_en": "appropriate to the magnitude of operations supporting the conduct of their activities, in accordance with the proportionality principle as referred to","description": "adaptés à l'ampleur des opérations soutenant l'exercice de leurs activités, conformément au principe de proportionnalité visé à l'article 4 ;","description_en": "appropriate to the magnitude of operations supporting the conduct of their activities, in accordance with the proportionality principle as referred to in Article 4;"},{"ref": "DORA-7.b","theme": "Systèmes TIC","theme_en": "ICT Systems","mesure": "fiables ;","mesure_en": "reliable;","description": "fiables ;","description_en": "reliable;"},{"ref": "DORA-7.c","theme": "Systèmes TIC","theme_en": "ICT Systems","mesure": "dotés d'une capacité suffisante pour traiter avec précision les données nécessaires à l'exercice des activités et à la fourniture rapide des services","mesure_en": "equipped with sufficient capacity to accurately process the data necessary for the performance of activities and the timely provision of services, and","description": "dotés d'une capacité suffisante pour traiter avec précision les données nécessaires à l'exercice des activités et à la fourniture rapide des services, et pour faire face aux volumes de pointe de commandes, de messages ou de transactions, selon les besoins, y compris lorsque de nouvelles technologies sont introduites ;","description_en": "equipped with sufficient capacity to accurately process the data necessary for the performance of activities and the timely provision of services, and to deal with peak orders, message or transaction volumes, as needed, including where new technology is introduced;"},{"ref": "DORA-7.d","theme": "Systèmes TIC","theme_en": "ICT Systems","mesure": "technologiquement résilients afin de faire face adéquatement aux besoins supplémentaires de traitement de l'information requis en conditions de marché","mesure_en": "technologically resilient in order to adequately deal with additional information processing needs as required under stressed market conditions or oth","description": "technologiquement résilients afin de faire face adéquatement aux besoins supplémentaires de traitement de l'information requis en conditions de marché tendues ou dans d'autres situations défavorables.","description_en": "technologically resilient in order to adequately deal with additional information processing needs as required under stressed market conditions or other adverse situations."},{"ref": "DORA-8.1","theme": "Identification des risques","theme_en": "Risk Identification","mesure": "Dans le cadre du cadre de gestion du risque TIC visé à l'article 6(1), les entités financières identifient, classifient et documentent toutes les fonc","mesure_en": "As part of the ICT risk management framework referred to in Article 6(1), financial entities shall identify, classify and adequately document all ICT ","description": "Dans le cadre du cadre de gestion du risque TIC visé à l'article 6, paragraphe 1, les entités financières identifient, classifient et documentent de manière adéquate toutes les fonctions métier supportées par les TIC, les rôles et responsabilités, les actifs informationnels et les actifs TIC qui soutiennent ces fonctions, ainsi que leurs rôles et dépendances en matière de risque TIC. Les entités financières réexaminent si nécessaire, et au moins une fois par an, la pertinence de cette classification et de toute documentation y afférente.","description_en": "As part of the ICT risk management framework referred to in Article 6(1), financial entities shall identify, classify and adequately document all ICT supported business functions, roles and responsibilities, the information assets and ICT assets supporting those functions, and their roles and dependencies in relation to ICT risk. Financial entities shall review as needed, and at least yearly, the adequacy of this classification and of any relevant documentation."},{"ref": "DORA-8.2","theme": "Identification des risques","theme_en": "Risk Identification","mesure": "Les entités financières identifient en permanence toutes les sources de risque TIC, notamment l'exposition aux risques vis-à-vis d'autres entités fina","mesure_en": "Financial entities shall, on a continuous basis, identify all sources of ICT risk, in particular the risk exposure to and from other financial entitie","description": "Les entités financières identifient en permanence toutes les sources de risque TIC, notamment l'exposition aux risques vis-à-vis d'autres entités financières et en provenance de celles-ci, et évaluent les cybermenaces et les vulnérabilités TIC pertinentes pour leurs fonctions métier supportées par les TIC, leurs actifs informationnels et leurs actifs TIC. Les entités financières réexaminent régulièrement, et au moins une fois par an, les scénarios de risque qui les concernent.","description_en": "Financial entities shall, on a continuous basis, identify all sources of ICT risk, in particular the risk exposure to and from other financial entities, and assess cyber threats and ICT vulnerabilities relevant to their ICT supported business functions, information assets and ICT assets. Financial entities shall review on a regular basis, and at least yearly, the risk scenarios impacting them."},{"ref": "DORA-8.3","theme": "Identification des risques","theme_en": "Risk Identification","mesure": "Les entités financières, autres que les micro-entreprises, procèdent à une évaluation des risques lors de tout changement majeur de l'infrastructure r","mesure_en": "Financial entities, other than microenterprises, shall perform a risk assessment upon each major change in the network and information system infrastr","description": "Les entités financières, autres que les micro-entreprises, procèdent à une évaluation des risques lors de tout changement majeur de l'infrastructure de réseau et de systèmes d'information, des processus ou des procédures affectant leurs fonctions métier supportées par les TIC, leurs actifs informationnels ou leurs actifs TIC.","description_en": "Financial entities, other than microenterprises, shall perform a risk assessment upon each major change in the network and information system infrastructure, in the processes or procedures affecting their ICT supported business functions, information assets or ICT assets."},{"ref": "DORA-8.4","theme": "Identification des risques","theme_en": "Risk Identification","mesure": "Les entités financières identifient tous les actifs informationnels et les actifs TIC, y compris ceux situés sur des sites distants, les ressources rés","mesure_en": "Financial entities shall identify all information assets and ICT assets, including those on remote sites, network resources and hardware equipment, an","description": "Les entités financières identifient tous les actifs informationnels et les actifs TIC, y compris ceux situés sur des sites distants, les ressources réseau et le matériel informatique, et cartographient ceux considérés comme critiques. Elles cartographient la configuration des actifs informationnels et des actifs TIC ainsi que les liens et interdépendances entre les différents actifs informationnels et actifs TIC.","description_en": "Financial entities shall identify all information assets and ICT assets, including those on remote sites, network resources and hardware equipment, and shall map those considered critical. They shall map the configuration of the information assets and ICT assets and the links and interdependencies between the different information assets and ICT assets."},{"ref": "DORA-8.5","theme": "Identification des risques","theme_en": "Risk Identification","mesure": "Les entités financières identifient et documentent tous les processus dépendant de prestataires tiers de services TIC et identifient les interconnexio","mesure_en": "Financial entities shall identify and document all processes that are dependent on ICT third-party service providers, and shall identify interconnecti","description": "Les entités financières identifient et documentent tous les processus dépendant de prestataires tiers de services TIC et identifient les interconnexions avec les prestataires tiers de services TIC fournissant des services soutenant des fonctions critiques ou importantes.","description_en": "Financial entities shall identify and document all processes that are dependent on ICT third-party service providers, and shall identify interconnections with ICT third-party service providers that provide services that support critical or important functions."},{"ref": "DORA-8.6","theme": "Identification des risques","theme_en": "Risk Identification","mesure": "Aux fins des paragraphes 1, 4 et 5, les entités financières tiennent des inventaires pertinents et les mettent à jour périodiquement et à chaque modif","mesure_en": "For the purposes of paragraphs 1, 4 and 5, financial entities shall maintain relevant inventories and update them periodically and every time any majo","description": "Aux fins des paragraphes 1, 4 et 5, les entités financières tiennent des inventaires pertinents et les mettent à jour périodiquement et chaque fois qu'un changement majeur tel que visé au paragraphe 3 se produit.","description_en": "For the purposes of paragraphs 1, 4 and 5, financial entities shall maintain relevant inventories and update them periodically and every time any major change as referred to in paragraph 3 occurs."},{"ref": "DORA-8.7","theme": "Identification des risques","theme_en": "Risk Identification","mesure": "Les entités financières, autres que les micro-entreprises, procèdent régulièrement, et au moins une fois par an, à une évaluation spécifique du risque","mesure_en": "Financial entities, other than microenterprises, shall on a regular basis, and at least yearly, conduct a specific ICT risk assessment on all legacy I","description": "Les entités financières, autres que les micro-entreprises, procèdent régulièrement, et au moins une fois par an, à une évaluation spécifique du risque TIC sur tous les systèmes TIC anciens (legacy), et en tout état de cause avant et après la connexion de technologies, d'applications ou de systèmes.","description_en": "Financial entities, other than microenterprises, shall on a regular basis, and at least yearly, conduct a specific ICT risk assessment on all legacy ICT systems and, in any case before and after connecting technologies, applications or systems."},{"ref": "DORA-9.1","theme": "Protection et prévention","theme_en": "Protection and Prevention","mesure": "Aux fins de la protection adéquate des systèmes TIC et en vue d'organiser des mesures de réponse, les entités financières surveillent et contrôlent en","mesure_en": "For the purposes of adequately protecting ICT systems and with a view to organising response measures, financial entities shall continuously monitor a","description": "Aux fins de la protection adéquate des systèmes TIC et en vue d'organiser des mesures de réponse, les entités financières surveillent et contrôlent en permanence la sécurité et le fonctionnement des systèmes et outils TIC et minimisent l'impact du risque TIC sur les systèmes TIC par le déploiement d'outils, politiques et procédures de sécurité TIC appropriés.","description_en": "For the purposes of adequately protecting ICT systems and with a view to organising response measures, financial entities shall continuously monitor and control the security and functioning of ICT systems and tools and shall minimise the impact of ICT risk on ICT systems through the deployment of appropriate ICT security tools, policies and procedures."},{"ref": "DORA-9.2","theme": "Protection et prévention","theme_en": "Protection and Prevention","mesure": "Les entités financières conçoivent, acquièrent et mettent en œuvre des politiques, procédures, protocoles et outils de sécurité TIC visant à garantir","mesure_en": "Financial entities shall design, procure and implement ICT security policies, procedures, protocols and tools that aim to ensure the resilience, conti","description": "Les entités financières conçoivent, acquièrent et mettent en œuvre des politiques, procédures, protocoles et outils de sécurité TIC visant à garantir la résilience, la continuité et la disponibilité des systèmes TIC, en particulier ceux soutenant des fonctions critiques ou importantes, et à maintenir des normes élevées de disponibilité, d'authenticité, d'intégrité et de confidentialité des données, que celles-ci soient au repos, en cours d'utilisation ou en transit.","description_en": "Financial entities shall design, procure and implement ICT security policies, procedures, protocols and tools that aim to ensure the resilience, continuity and availability of ICT systems, in particular for those supporting critical or important functions, and to maintain high standards of availability, authenticity, integrity and confidentiality of data, whether at rest, in use or in transit."},{"ref": "DORA-9.3","theme": "Protection et prévention","theme_en": "Protection and Prevention","mesure": "Afin d'atteindre les objectifs visés au paragraphe 2, les entités financières utilisent des solutions et processus TIC appropriés conformément à l'art","mesure_en": "In order to achieve the objectives referred to in paragraph 2, financial entities shall use ICT solutions and processes that are appropriate in accord","description": "Afin d'atteindre les objectifs visés au paragraphe 2, les entités financières utilisent des solutions et processus TIC appropriés conformément à l'article 4. Ces solutions et processus TIC doivent :\n(a) assurer la sécurité des moyens de transfert de données ;\n(b) minimiser le risque de corruption ou de perte de données, d'accès non autorisé et de défaillances techniques susceptibles d'entraver l'activité ;\n(c) prévenir l'indisponibilité, l'altération de l'authenticité et de l'intégrité, les atteintes à la confidentialité et la perte de données ;\n(d) veiller à ce que les données soient protégées contre les risques liés à la gestion des données, y compris les mauvaises pratiques d'administration, les risques liés au traitement et les erreurs humaines.","description_en": "In order to achieve the objectives referred to in paragraph 2, financial entities shall use ICT solutions and processes that are appropriate in accordance with Article 4. Those ICT solutions and processes shall:\n(a) ensure the security of the means of transfer of data;\n(b) minimise the risk of corruption or loss of data, unauthorised access and technical flaws that may hinder business activity;\n(c) prevent the lack of availability, the impairment of the authenticity and integrity, the breaches of confidentiality and the loss of data;\n(d) ensure that data is protected from risks arising from data management, including poor administration, processing- related risks and human error."},{"ref": "DORA-9.4","theme": "Protection et prévention","theme_en": "Protection and Prevention","mesure": "Dans le cadre du cadre de gestion du risque TIC visé à l'article 6(1), les entités financières doivent notamment :","mesure_en": "As part of the ICT risk management framework referred to in Article 6(1), financial entities shall:","description": "Dans le cadre du cadre de gestion du risque TIC visé à l'article 6, paragraphe 1, les entités financières doivent notamment :\n(a) élaborer et documenter une politique de sécurité de l'information définissant des règles pour protéger la disponibilité, l'authenticité, l'intégrité et la confidentialité des données, des actifs informationnels et des actifs TIC, y compris ceux de leurs clients, le cas échéant ;\n(b) selon une approche fondée sur les risques, mettre en place une structure solide de gestion du réseau et de l'infrastructure utilisant des techniques, méthodes et protocoles appropriés pouvant inclure la mise en œuvre de mécanismes automatisés pour isoler les actifs informationnels touchés en cas de cyberattaques ;\n(c) mettre en œuvre des politiques qui limitent l'accès physique ou logique aux actifs informationnels et aux actifs TIC à ce qui est requis pour les fonctions et activités légitimes et approuvées uniquement, et établir à cette fin un ensemble de politiques, procédures et contrôles régissant les droits d'accès et garantissant une administration saine de ceux-ci ;\n(d) mettre en œuvre des politiques et protocoles d'authentification forte.","description_en": "As part of the ICT risk management framework referred to in Article 6(1), financial entities shall:\n(a) develop and document an information security policy defining rules to protect the availability, authenticity, integrity and confidentiality of data, information assets and ICT assets, including those of their customers, where applicable;\n(b) following a risk-based approach, establish a sound network and infrastructure management structure using appropriate techniques, methods and protocols that may include implementing automated mechanisms to isolate affected information assets in the event of cyber-attacks;\n(c) implement policies that limit the physical or logical access to information assets and ICT assets to what is required for legitimate and approved functions and activities only, and establish to that end a set of policies, procedures and controls that address access rights and ensure a sound administration thereof;\n(d) implement policies and protocols for strong authentication"},{"ref": "DORA-10.1","theme": "Détection","theme_en": "Detection","mesure": "Les entités financières disposent de mécanismes de détection rapide des activités anormales, conformément à l'article 17, y compris les problèmes de p","mesure_en": "Financial entities shall have in place mechanisms to promptly detect anomalous activities, in accordance with Article 17, including ICT network perfor","description": "Les entités financières disposent de mécanismes de détection rapide des activités anormales, conformément à l'article 17, y compris les problèmes de performance des réseaux TIC et les incidents liés aux TIC, et d'identification des points de défaillance uniques matériels potentiels.","description_en": "Financial entities shall have in place mechanisms to promptly detect anomalous activities, in accordance with Article 17, including ICT network performance issues and ICT-related incidents, and to identify potential material single points of failure."},{"ref": "DORA-10.2","theme": "Détection","theme_en": "Detection","mesure": "Les mécanismes de détection visés au paragraphe 1 permettent de multiples niveaux de contrôle, définissent des seuils d'alerte et des critères pour dé","mesure_en": "The detection mechanisms referred to in paragraph 1 shall enable multiple layers of control, define alert thresholds and criteria to trigger and initi","description": "Les mécanismes de détection visés au paragraphe 1 permettent de multiples niveaux de contrôle, définissent des seuils d'alerte et des critères pour déclencher et initier les processus de réponse aux incidents liés aux TIC, y compris des mécanismes d'alerte automatiques pour le personnel compétent chargé de la réponse aux incidents liés aux TIC.","description_en": "The detection mechanisms referred to in paragraph 1 shall enable multiple layers of control, define alert thresholds and criteria to trigger and initiate ICT-related incident response processes, including automatic alert mechanisms for relevant staff in charge of ICT-related incident response."},{"ref": "DORA-10.3","theme": "Détection","theme_en": "Detection","mesure": "Les entités financières consacrent des ressources et des capacités suffisantes à la surveillance de l'activité des utilisateurs, de la survenance d'an","mesure_en": "Financial entities shall devote sufficient resources and capabilities to monitor user activity, the occurrence of ICT anomalies and ICT-related incide","description": "Les entités financières consacrent des ressources et des capacités suffisantes à la surveillance de l'activité des utilisateurs, de la survenance d'anomalies TIC et d'incidents liés aux TIC, en particulier les cyberattaques.","description_en": "Financial entities shall devote sufficient resources and capabilities to monitor user activity, the occurrence of ICT anomalies and ICT-related incidents, in particular cyber-attacks."},{"ref": "DORA-10.4","theme": "Détection","theme_en": "Detection","mesure": "Les prestataires de services de communication de données disposent en outre de systèmes permettant de vérifier efficacement l'exhaustivité des déclarati","mesure_en": "Data reporting service providers shall, in addition, have in place systems that can effectively check trade reports for completeness, identify omissio","description": "Les prestataires de services de communication de données disposent en outre de systèmes permettant de vérifier efficacement l'exhaustivité des déclarations de transactions, d'identifier les omissions et les erreurs manifestes, et de demander la retransmission de ces déclarations.","description_en": "Data reporting service providers shall, in addition, have in place systems that can effectively check trade reports for completeness, identify omissions and obvious errors, and request re-transmission of those reports."},{"ref": "DORA-11.1","theme": "Réponse et rétablissement","theme_en": "Response and Recovery","mesure": "Dans le cadre du cadre de gestion du risque TIC visé à l'article 6(1) et sur la base des exigences d'identification prévues à l'article 8, les entité","mesure_en": "As part of the ICT risk management framework referred to in Article 6(1) and based on the identification requirements set out in Article 8, financial ","description": "Dans le cadre du cadre de gestion du risque TIC visé à l'article 6, paragraphe 1, et sur la base des exigences d'identification prévues à l'article 8, les entités financières mettent en place une politique globale de continuité des activités TIC, qui peut être adoptée en tant que politique spécifique dédiée, faisant partie intégrante de la politique globale de continuité des activités de l'entité financière.","description_en": "As part of the ICT risk management framework referred to in Article 6(1) and based on the identification requirements set out in Article 8, financial entities shall put in place a comprehensive ICT business continuity policy, which may be adopted as a dedicated specific policy, forming an integral part of the overall business continuity policy of the financial entity."},{"ref": "DORA-11.2","theme": "Réponse et rétablissement","theme_en": "Response and Recovery","mesure": "Les entités financières mettent en œuvre la politique de continuité des activités TIC au moyen de dispositifs, plans, procédures et mécanismes dédiés,","mesure_en": "Financial entities shall implement the ICT business continuity policy through dedicated, appropriate and documented arrangements, plans, procedures an","description": "Les entités financières mettent en œuvre la politique de continuité des activités TIC au moyen de dispositifs, plans, procédures et mécanismes dédiés, appropriés et documentés visant à :\n(a) assurer la continuité des fonctions critiques ou importantes de l'entité financière ;\n(b) répondre rapidement, de manière appropriée et efficace à tous les incidents liés aux TIC et les résoudre de manière à limiter les dommages et à donner la priorité à la reprise des activités et aux actions de rétablissement ;\n(c) activer sans délai des plans dédiés permettant des mesures de confinement, des processus et des technologies adaptés à chaque type d'incident lié aux TIC et prévenir tout dommage supplémentaire, ainsi que des procédures de réponse et de rétablissement adaptées établies conformément à l'article 12 ;\n(d) estimer les impacts, dommages et pertes préliminaires ;\n(e) définir des actions de communication et de gestion de crise garantissant la transmission d'informations actualisées à l'ensemble du personnel interne et des parties prenantes externes concernés conformément à l'article 14, et rendre compte à l'autorité compétente.","description_en": "Financial entities shall implement the ICT business continuity policy through dedicated, appropriate and documented arrangements, plans, procedures and mechanisms aiming to:\n(a) ensure the continuity of the financial entity’s critical or important functions;\n(b) quickly, appropriately and effectively respond to, and resolve, all ICT-related incidents in a way that limits damage and prioritises the resumption of activities and recovery actions;\n(c) activate, without delay, dedicated plans that enable containment measures, processes and technologies suited to each type of ICT-related incident and prevent further damage, as well as tailored response and recovery procedures established in accordance with Article 12;\n(d) estimate preliminary impacts, damages and losses;\n(e) set out communication and crisis management actions that ensure that updated information is transmitted to all relevant internal staff and external stakeholders in accordance with Article 14, and report to the competent "},{"ref": "DORA-11.3","theme": "Réponse et rétablissement","theme_en": "Response and Recovery","mesure": "Dans le cadre du cadre de gestion du risque TIC visé à l'article 6(1), les entités financières mettent en œuvre des plans de réponse et de rétablissem","mesure_en": "As part of the ICT risk management framework referred to in Article 6(1), financial entities shall implement associated ICT response and recovery plan","description": "Dans le cadre du cadre de gestion du risque TIC visé à l'article 6, paragraphe 1, les entités financières mettent en œuvre des plans de réponse et de rétablissement TIC associés qui, dans le cas des entités financières autres que les micro-entreprises, font l'objet d'examens d'audit interne indépendants.","description_en": "As part of the ICT risk management framework referred to in Article 6(1), financial entities shall implement associated ICT response and recovery plans which, in the case of financial entities other than microenterprises, shall be subject to independent internal audit reviews."},{"ref": "DORA-11.4","theme": "Réponse et rétablissement","theme_en": "Response and Recovery","mesure": "Les entités financières mettent en place, maintiennent et testent périodiquement des plans de continuité des activités TIC appropriés, notamment en ce","mesure_en": "Financial entities shall put in place, maintain and periodically test appropriate ICT business continuity plans, notably with regard to critical or im","description": "Les entités financières mettent en place, maintiennent et testent périodiquement des plans de continuité des activités TIC appropriés, notamment en ce qui concerne les fonctions critiques ou importantes externalisées ou contractées auprès de prestataires tiers de services TIC.","description_en": "Financial entities shall put in place, maintain and periodically test appropriate ICT business continuity plans, notably with regard to critical or important functions outsourced or contracted through arrangements with ICT third-party service providers."},{"ref": "DORA-11.5","theme": "Réponse et rétablissement","theme_en": "Response and Recovery","mesure": "Dans le cadre de la politique globale de continuité des activités, les entités financières réalisent une analyse d'impact sur les activités (BIA) de le","mesure_en": "As part of the overall business continuity policy, financial entities shall conduct a business impact analysis (BIA) of their exposures to severe busi","description": "Dans le cadre de la politique globale de continuité des activités, les entités financières réalisent une analyse d'impact sur les activités (BIA) de leurs expositions aux perturbations graves des activités. Dans le cadre de la BIA, les entités financières évaluent l'impact potentiel des perturbations graves des activités au moyen de critères quantitatifs et qualitatifs, en utilisant des données internes et externes et une analyse de scénarios, selon le cas. La BIA prend en considération la criticité des fonctions métier identifiées et cartographiées, les processus de support, les dépendances vis-à-vis de tiers et les actifs informationnels, ainsi que leurs interdépendances. Les entités financières veillent à ce que les actifs TIC et les services TIC soient conçus et utilisés en parfaite adéquation avec la BIA, notamment en ce qui concerne la garantie adéquate de la redondance de toutes les composantes critiques.","description_en": "As part of the overall business continuity policy, financial entities shall conduct a business impact analysis (BIA) of their exposures to severe business disruptions. Under the BIA, financial entities shall assess the potential impact of severe business disruptions by means of quantitative and qualitative criteria, using internal and external data and scenario analysis, as appropriate. The BIA shall consider the criticality of identified and mapped business functions, support processes, third-party dependencies and information assets, and their interdependencies. Financial entities shall ensure that ICT assets and ICT services are designed and used in full alignment with the BIA, in particular with regard to adequately ensuring the redundancy of all critical components."},{"ref": "DORA-11.6","theme": "Réponse et rétablissement","theme_en": "Response and Recovery","mesure": "Dans le cadre de leur gestion globale du risque TIC, les entités financières doivent :","mesure_en": "As part of their comprehensive ICT risk management, financial entities shall:","description": "Dans le cadre de leur gestion globale du risque TIC, les entités financières doivent :\n(a) tester les plans de continuité des activités TIC et les plans de réponse et de rétablissement TIC en rapport avec les systèmes TIC soutenant toutes les fonctions au moins une fois par an, ainsi qu'en cas de modifications substantielles des systèmes TIC soutenant des fonctions critiques ou importantes ;\n(b) tester les plans de communication de crise établis conformément à l'article 14.","description_en": "As part of their comprehensive ICT risk management, financial entities shall:\n(a) test the ICT business continuity plans and the ICT response and recovery plans in relation to ICT systems supporting all functions at least yearly, as well as in the event of any substantive changes to ICT systems supporting critical or important functions;\n(b) test the crisis communication plans established in accordance with Article 14."},{"ref": "DORA-11.7","theme": "Réponse et rétablissement","theme_en": "Response and Recovery","mesure": "Les entités financières, autres que les micro-entreprises, disposent d'une fonction de gestion de crise qui, en cas d'activation de leurs plans de cont","mesure_en": "Financial entities, other than microenterprises, shall have a crisis management function, which, in the event of activation of their ICT business cont","description": "Les entités financières, autres que les micro-entreprises, disposent d'une fonction de gestion de crise qui, en cas d'activation de leurs plans de continuité des activités TIC ou de leurs plans de réponse et de rétablissement TIC, définit notamment des procédures claires pour gérer les communications de crise internes et externes conformément à l'article 14.","description_en": "Financial entities, other than microenterprises, shall have a crisis management function, which, in the event of activation of their ICT business continuity plans or ICT response and recovery plans, shall, inter alia, set out clear procedures to manage internal and external crisis communications in accordance with Article 14."},{"ref": "DORA-11.8","theme": "Réponse et rétablissement","theme_en": "Response and Recovery","mesure": "Les entités financières tiennent des registres facilement accessibles des activités avant et pendant les événements perturbateurs lorsque leurs plans d","mesure_en": "Financial entities shall keep readily accessible records of activities before and during disruption events when their ICT business continuity plans an","description": "Les entités financières tiennent des registres facilement accessibles des activités avant et pendant les événements perturbateurs lorsque leurs plans de continuité des activités TIC et leurs plans de réponse et de rétablissement TIC sont activés.","description_en": "Financial entities shall keep readily accessible records of activities before and during disruption events when their ICT business continuity plans and ICT response and recovery plans are activated."},{"ref": "DORA-11.9","theme": "Réponse et rétablissement","theme_en": "Response and Recovery","mesure": "Les dépositaires centraux de titres fournissent aux autorités compétentes des copies des résultats des tests de continuité des activités TIC, ou d'exe","mesure_en": "Central securities depositories shall provide the competent authorities with copies of the results of the ICT business continuity tests, or of similar","description": "Les dépositaires centraux de titres fournissent aux autorités compétentes des copies des résultats des tests de continuité des activités TIC, ou d'exercices similaires.","description_en": "Central securities depositories shall provide the competent authorities with copies of the results of the ICT business continuity tests, or of similar exercises."},{"ref": "DORA-11.10","theme": "Réponse et rétablissement","theme_en": "Response and Recovery","mesure": "Les entités financières, autres que les micro-entreprises, communiquent aux autorités compétentes, sur demande, une estimation des coûts et pertes annu","mesure_en": "Financial entities, other than microenterprises, shall report to the competent authorities, upon their request, an estimation of aggregated annual cos","description": "Les entités financières, autres que les micro-entreprises, communiquent aux autorités compétentes, sur demande, une estimation des coûts et pertes annuels agrégés causés par des incidents majeurs liés aux TIC.","description_en": "Financial entities, other than microenterprises, shall report to the competent authorities, upon their request, an estimation of aggregated annual costs and losses caused by major ICT-related incidents."},{"ref": "DORA-11.11","theme": "Réponse et rétablissement","theme_en": "Response and Recovery","mesure": "Conformément à l'article 16 des règlements (UE) nº 1093/2010, (UE) nº 1094/2010 et (UE) nº 1095/2010, les AES, par l'intermédiaire du comité conjoin","mesure_en": "In accordance with Article 16 of Regulations (EU) No 1093/2010, (EU) No 1094/2010 and (EU) No 1095/2010, the ESAs, through the Joint Committee, shall ","description": "Conformément à l'article 16 des règlements (UE) nº 1093/2010, (UE) nº 1094/2010 et (UE) nº 1095/2010, les AES, par l'intermédiaire du comité conjoint, élaborent d'ici le 17 juillet 2024 des orientations communes sur l'estimation des coûts et pertes annuels agrégés visés au paragraphe 10.","description_en": "In accordance with Article 16 of Regulations (EU) No 1093/2010, (EU) No 1094/2010 and (EU) No 1095/2010, the ESAs, through the Joint Committee, shall by 17 July 2024 develop common guidelines on the estimation of aggregated annual costs and losses referred to in paragraph 10."},{"ref": "DORA-12.1","theme": "Sauvegarde et restauration","theme_en": "Backup and Restoration","mesure": "Afin de garantir la restauration des systèmes TIC et des données avec un temps d'arrêt minimal, une perturbation et des pertes limitées, dans le cadr","mesure_en": "For the purpose of ensuring the restoration of ICT systems and data with minimum downtime, limited disruption and loss, as part of their ICT risk mana","description": "Afin de garantir la restauration des systèmes TIC et des données avec un temps d'arrêt minimal, une perturbation et des pertes limitées, dans le cadre de leur cadre de gestion du risque TIC, les entités financières élaborent et documentent :\n(a) des politiques et procédures de sauvegarde précisant le périmètre des données soumises à sauvegarde et la fréquence minimale de sauvegarde, en fonction de la criticité des informations ou du niveau de confidentialité des données ;\n(b) des procédures et méthodes de restauration et de rétablissement.","description_en": "For the purpose of ensuring the restoration of ICT systems and data with minimum downtime, limited disruption and loss, as part of their ICT risk management framework, financial entities shall develop and document:\n(a) backup policies and procedures specifying the scope of the data that is subject to the backup and the minimum frequency of the backup, based on the criticality of information or the confidentiality level of the data;\n(b) restoration and recovery procedures and methods."},{"ref": "DORA-12.2","theme": "Sauvegarde et restauration","theme_en": "Backup and Restoration","mesure": "Les entités financières mettent en place des systèmes de sauvegarde pouvant être activés conformément aux politiques et procédures de sauvegarde, ains","mesure_en": "Financial entities shall set up backup systems that can be activated in accordance with the backup policies and procedures, as well as restoration and","description": "Les entités financières mettent en place des systèmes de sauvegarde pouvant être activés conformément aux politiques et procédures de sauvegarde, ainsi qu'aux procédures et méthodes de restauration et de rétablissement. L'activation des systèmes de sauvegarde ne doit pas compromettre la sécurité des systèmes de réseau et d'information ni la disponibilité, l'authenticité, l'intégrité ou la confidentialité des données. Les tests des procédures de sauvegarde et des procédures et méthodes de restauration et de rétablissement sont réalisés périodiquement.","description_en": "Financial entities shall set up backup systems that can be activated in accordance with the backup policies and procedures, as well as restoration and recovery procedures and methods. The activation of backup systems shall not jeopardise the security of the network and information systems or the availability, authenticity, integrity or confidentiality of data. Testing of the backup procedures and restoration and recovery procedures and methods shall be undertaken periodically."},{"ref": "DORA-12.3","theme": "Sauvegarde et restauration","theme_en": "Backup and Restoration","mesure": "Lors de la restauration de données de sauvegarde à l'aide de leurs propres systèmes, les entités financières utilisent des systèmes TIC physiquement e","mesure_en": "When restoring backup data using own systems, financial entities shall use ICT systems that are physically and logically segregated from the source IC","description": "Lors de la restauration de données de sauvegarde à l'aide de leurs propres systèmes, les entités financières utilisent des systèmes TIC physiquement et logiquement séparés du système TIC source. Les systèmes TIC doivent être protégés de manière sécurisée contre tout accès non autorisé ou toute corruption TIC et permettre le rétablissement rapide des services en utilisant les sauvegardes de données et de systèmes si nécessaire.","description_en": "When restoring backup data using own systems, financial entities shall use ICT systems that are physically and logically segregated from the source ICT system. The ICT systems shall be securely protected from any unauthorised access or ICT corruption and allow for the timely restoration of services making use of data and system backups as necessary."},{"ref": "DORA-12.4","theme": "Sauvegarde et restauration","theme_en": "Backup and Restoration","mesure": "Les entités financières, autres que les micro-entreprises, maintiennent des capacités TIC redondantes dotées de ressources, capacités et fonctions suff","mesure_en": "Financial entities, other than microenterprises, shall maintain redundant ICT capacities equipped with resources, capabilities and functions that are ","description": "Les entités financières, autres que les micro-entreprises, maintiennent des capacités TIC redondantes dotées de ressources, capacités et fonctions suffisantes pour répondre aux besoins opérationnels. Les micro-entreprises évaluent la nécessité de maintenir de telles capacités TIC redondantes en fonction de leur profil de risque.","description_en": "Financial entities, other than microenterprises, shall maintain redundant ICT capacities equipped with resources, capabilities and functions that are adequate to ensure business needs. Microenterprises shall assess the need to maintain such redundant ICT capacities based on their risk profile."},{"ref": "DORA-12.5","theme": "Sauvegarde et restauration","theme_en": "Backup and Restoration","mesure": "Les dépositaires centraux de titres maintiennent au moins un site de traitement secondaire doté de ressources, capacités, fonctions et effectifs suffis","mesure_en": "Central securities depositories shall maintain at least one secondary processing site endowed with adequate resources, capabilities, functions and sta","description": "Les dépositaires centraux de titres maintiennent au moins un site de traitement secondaire doté de ressources, capacités, fonctions et effectifs suffisants pour répondre aux besoins opérationnels.\n(a) situé à une distance géographique suffisante du site de traitement principal afin de présenter un profil de risque distinct et d'éviter d'être affecté par l'événement ayant touché le site principal ;\n(b) capable d'assurer la continuité des fonctions critiques ou importantes de manière identique au site principal, ou de fournir le niveau de services nécessaire pour garantir que l'entité financière exécute ses opérations critiques dans le respect des objectifs de rétablissement ;\n(c) immédiatement accessible au personnel de l'entité financière afin d'assurer la continuité des fonctions critiques ou importantes en cas d'indisponibilité du site de traitement principal.","description_en": "Central securities depositories shall maintain at least one secondary processing site endowed with adequate resources, capabilities, functions and staffing arrangements to ensure business needs.\n(a) located at a geographical distance from the primary processing site to ensure that it bears a distinct risk profile and to prevent it from being affected by the event which has affected the primary site;\n(b) capable of ensuring the continuity of critical or important functions identically to the primary site, or providing the level of services necessary to ensure that the financial entity performs its critical operations within the recovery objectives;\n(c) immediately accessible to the financial entity’s staff to ensure continuity of critical or important functions in the event that the primary processing site has become unavailable."},{"ref": "DORA-12.6","theme": "Sauvegarde et restauration","theme_en": "Backup and Restoration","mesure": "Lors de la détermination des objectifs de temps de rétablissement et de point de rétablissement pour chaque fonction, les entités financières tiennent","mesure_en": "In determining the recovery time and recovery point objectives for each function, financial entities shall take into account whether it is a critical ","description": "Lors de la détermination des objectifs de temps de rétablissement et de point de rétablissement pour chaque fonction, les entités financières tiennent compte du caractère critique ou important de la fonction et de l'impact potentiel global sur l'efficience du marché. Ces objectifs de temps garantissent que, dans des scénarios extrêmes, les niveaux de service convenus sont respectés.","description_en": "In determining the recovery time and recovery point objectives for each function, financial entities shall take into account whether it is a critical or important function and the potential overall impact on market efficiency. Such time objectives shall ensure that, in extreme scenarios, the agreed service levels are met."},{"ref": "DORA-12.7","theme": "Sauvegarde et restauration","theme_en": "Backup and Restoration","mesure": "Lors du rétablissement après un incident lié aux TIC, les entités financières effectuent les vérifications nécessaires, y compris des vérifications mul","mesure_en": "When recovering from an ICT-related incident, financial entities shall perform necessary checks, including any multiple checks and reconciliations, in","description": "Lors du rétablissement après un incident lié aux TIC, les entités financières effectuent les vérifications nécessaires, y compris des vérifications multiples et des rapprochements, afin de garantir le maintien du plus haut niveau d'intégrité des données. Ces vérifications sont également effectuées lors de la reconstitution de données à partir de parties prenantes externes, afin de s'assurer que toutes les données sont cohérentes entre les systèmes.","description_en": "When recovering from an ICT-related incident, financial entities shall perform necessary checks, including any multiple checks and reconciliations, in order to ensure that the highest level of data integrity is maintained. These checks shall also be performed when reconstructing data from external stakeholders, in order to ensure that all data is consistent between systems."},{"ref": "DORA-13.1","theme": "Apprentissage et évolution","theme_en": "Learning and Evolving","mesure": "Les entités financières disposent de capacités et de personnel pour recueillir des informations sur les vulnérabilités et les cybermenaces, les inciden","mesure_en": "Financial entities shall have in place capabilities and staff to gather information on vulnerabilities and cyber threats, ICT-related incidents, in pa","description": "Les entités financières disposent de capacités et de personnel pour recueillir des informations sur les vulnérabilités et les cybermenaces, les incidents liés aux TIC, en particulier les cyberattaques, et analyser l'impact qu'ils sont susceptibles d'avoir sur leur résilience opérationnelle numérique.","description_en": "Financial entities shall have in place capabilities and staff to gather information on vulnerabilities and cyber threats, ICT-related incidents, in particular cyber-attacks, and analyse the impact they are likely to have on their digital operational resilience."},{"ref": "DORA-13.2","theme": "Apprentissage et évolution","theme_en": "Learning and Evolving","mesure": "Les entités financières mettent en place des revues post-incident TIC après qu'un incident majeur lié aux TIC a perturbé leurs activités essentielles,","mesure_en": "Financial entities shall put in place post ICT-related incident reviews after a major ICT-related incident disrupts their core activities, analysing t","description": "Les entités financières mettent en place des revues post-incident TIC après qu'un incident majeur lié aux TIC a perturbé leurs activités essentielles, en analysant les causes de la perturbation et en identifiant les améliorations requises des opérations TIC ou de la politique de continuité des activités TIC visée à l'article 11.\n(a) la rapidité de réponse aux alertes de sécurité et de détermination de l'impact des incidents liés aux TIC et de leur gravité ;\n(b) la qualité et la rapidité de l'analyse criminalistique (forensique), le cas échéant ;\n(c) l'efficacité de l'escalade des incidents au sein de l'entité financière ;\n(d) l'efficacité de la communication interne et externe.","description_en": "Financial entities shall put in place post ICT-related incident reviews after a major ICT-related incident disrupts their core activities, analysing the causes of disruption and identifying required improvements to the ICT operations or within the ICT business continuity policy referred to in Article 11.\n(a) the promptness in responding to security alerts and determining the impact of ICT-related incidents and their severity;\n(b) the quality and speed of performing a forensic analysis, where deemed appropriate;\n(c) the effectiveness of incident escalation within the financial entity;\n(d) the effectiveness of internal and external communication."},{"ref": "DORA-13.3","theme": "Apprentissage et évolution","theme_en": "Learning and Evolving","mesure": "Les enseignements tirés des tests de résilience opérationnelle numérique réalisés conformément aux articles 26 et 27 et des incidents réels liés aux T","mesure_en": "Lessons derived from the digital operational resilience testing carried out in accordance with Articles 26 and 27 and from real life ICT-related incid","description": "Les enseignements tirés des tests de résilience opérationnelle numérique réalisés conformément aux articles 26 et 27 et des incidents réels liés aux TIC, en particulier les cyberattaques, ainsi que les difficultés rencontrées lors de l'activation des plans de continuité des activités TIC et des plans de réponse et de rétablissement TIC, accompagnés des informations pertinentes échangées avec les contreparties et évaluées lors des examens prudentiels, sont dûment intégrés en permanence dans le processus d'évaluation du risque TIC. Ces constatations constituent la base des réexamens appropriés des composantes pertinentes du cadre de gestion du risque TIC visé à l'article 6, paragraphe 1.","description_en": "Lessons derived from the digital operational resilience testing carried out in accordance with Articles 26 and 27 and from real life ICT-related incidents, in particular cyber-attacks, along with challenges faced upon the activation of ICT business continuity plans and ICT response and recovery plans, together with relevant information exchanged with counterparts and assessed during supervisory reviews, shall be duly incorporated on a continuous basis into the ICT risk assessment process. Those findings shall form the basis for appropriate reviews of relevant components of the ICT risk management framework referred to in Article 6(1)."},{"ref": "DORA-13.4","theme": "Apprentissage et évolution","theme_en": "Learning and Evolving","mesure": "Les entités financières surveillent l'efficacité de la mise en œuvre de leur stratégie de résilience opérationnelle numérique définie à l'article 6(8)","mesure_en": "Financial entities shall monitor the effectiveness of the implementation of their digital operational resilience strategy set out in Article 6(8). The","description": "Les entités financières surveillent l'efficacité de la mise en œuvre de leur stratégie de résilience opérationnelle numérique définie à l'article 6, paragraphe 8. Elles cartographient l'évolution du risque TIC dans le temps, analysent la fréquence, les types, l'ampleur et l'évolution des incidents liés aux TIC, en particulier les cyberattaques et leurs schémas, afin de comprendre le niveau d'exposition au risque TIC, notamment en ce qui concerne les fonctions critiques ou importantes, et d'améliorer la cybermaturité et la préparation de l'entité financière.","description_en": "Financial entities shall monitor the effectiveness of the implementation of their digital operational resilience strategy set out in Article 6(8). They shall map the evolution of ICT risk over time, analyse the frequency, types, magnitude and evolution of ICT-related incidents, in particular cyber-attacks and their patterns, with a view to understanding the level of ICT risk exposure, in particular in relation to critical or important functions, and enhance the cyber maturity and preparedness of the financial entity."},{"ref": "DORA-13.5","theme": "Apprentissage et évolution","theme_en": "Learning and Evolving","mesure": "Le personnel TIC dirigeant rend compte au moins une fois par an à l'organe de direction des constatations visées au paragraphe 3 et formule des recomm","mesure_en": "Senior ICT staff shall report at least yearly to the management body on the findings referred to in paragraph 3 and put forward recommendations.","description": "Le personnel TIC dirigeant rend compte au moins une fois par an à l'organe de direction des constatations visées au paragraphe 3 et formule des recommandations.","description_en": "Senior ICT staff shall report at least yearly to the management body on the findings referred to in paragraph 3 and put forward recommendations."},{"ref": "DORA-13.6","theme": "Apprentissage et évolution","theme_en": "Learning and Evolving","mesure": "Les entités financières élaborent des programmes de sensibilisation à la sécurité TIC et des formations à la résilience opérationnelle numérique en ta","mesure_en": "Financial entities shall develop ICT security awareness programmes and digital operational resilience training as compulsory modules in their staff tr","description": "Les entités financières élaborent des programmes de sensibilisation à la sécurité TIC et des formations à la résilience opérationnelle numérique en tant que modules obligatoires de leurs programmes de formation du personnel. Ces programmes et formations s'appliquent à l'ensemble des employés et au personnel de direction, et présentent un niveau de complexité proportionné aux responsabilités de leurs fonctions. Le cas échéant, les entités financières incluent également les prestataires tiers de services TIC dans leurs programmes de formation pertinents, conformément à l'article 30, paragraphe 2, point i).","description_en": "Financial entities shall develop ICT security awareness programmes and digital operational resilience training as compulsory modules in their staff training schemes. Those programmes and training shall be applicable to all employees and to senior management staff, and shall have a level of complexity commensurate to the remit of their functions. Where appropriate, financial entities shall also include ICT third-party service providers in their relevant training schemes in accordance with Article 30(2), point (i)."},{"ref": "DORA-13.7","theme": "Apprentissage et évolution","theme_en": "Learning and Evolving","mesure": "Les entités financières, autres que les micro-entreprises, surveillent en permanence les évolutions technologiques pertinentes, y compris en vue de comp","mesure_en": "Financial entities, other than microenterprises, shall monitor relevant technological developments on a continuous basis, also with a view to understa","description": "Les entités financières, autres que les micro-entreprises, surveillent en permanence les évolutions technologiques pertinentes, y compris en vue de comprendre l'impact potentiel du déploiement de ces nouvelles technologies sur les exigences de sécurité TIC et la résilience opérationnelle numérique. Elles se tiennent à jour des derniers processus de gestion du risque TIC, afin de lutter efficacement contre les formes actuelles ou nouvelles de cyberattaques.","description_en": "Financial entities, other than microenterprises, shall monitor relevant technological developments on a continuous basis, also with a view to understanding the possible impact of the deployment of such new technologies on ICT security requirements and digital operational resilience. They shall keep up-to-date with the latest ICT risk management processes, in order to effectively combat current or new forms of cyber-attacks."},{"ref": "DORA-14.1","theme": "Communication de crise","theme_en": "Crisis Communication","mesure": "Dans le cadre du cadre de gestion du risque TIC visé à l'article 6(1), les entités financières disposent de plans de communication de crise permettant","mesure_en": "As part of the ICT risk management framework referred to in Article 6(1), financial entities shall have in place crisis communication plans enabling a","description": "Dans le cadre du cadre de gestion du risque TIC visé à l'article 6, paragraphe 1, les entités financières disposent de plans de communication de crise permettant une divulgation responsable, au minimum, des incidents majeurs liés aux TIC ou des vulnérabilités aux clients et aux contreparties ainsi qu'au public, le cas échéant.","description_en": "As part of the ICT risk management framework referred to in Article 6(1), financial entities shall have in place crisis communication plans enabling a responsible disclosure of, at least, major ICT-related incidents or vulnerabilities to clients and counterparts as well as to the public, as appropriate."},{"ref": "DORA-14.2","theme": "Communication de crise","theme_en": "Crisis Communication","mesure": "Dans le cadre du cadre de gestion du risque TIC, les entités financières mettent en œuvre des politiques de communication pour le personnel interne et","mesure_en": "As part of the ICT risk management framework, financial entities shall implement communication policies for internal staff and for external stakeholde","description": "Dans le cadre du cadre de gestion du risque TIC, les entités financières mettent en œuvre des politiques de communication pour le personnel interne et pour les parties prenantes externes. Les politiques de communication pour le personnel tiennent compte de la nécessité de différencier le personnel impliqué dans la gestion du risque TIC, en particulier le personnel chargé de la réponse et du rétablissement, et le personnel devant être informé.","description_en": "As part of the ICT risk management framework, financial entities shall implement communication policies for internal staff and for external stakeholders. Communication policies for staff shall take into account the need to differentiate between staff involved in ICT risk management, in particular the staff responsible for response and recovery, and staff that needs to be informed."},{"ref": "DORA-14.3","theme": "Communication de crise","theme_en": "Crisis Communication","mesure": "Au moins une personne au sein de l'entité financière est chargée de la mise en œuvre de la stratégie de communication relative aux incidents liés aux","mesure_en": "At least one person in the financial entity shall be tasked with implementing the communication strategy for ICT- related incidents and fulfil the pub","description": "Au moins une personne au sein de l'entité financière est chargée de la mise en œuvre de la stratégie de communication relative aux incidents liés aux TIC et remplit la fonction de porte-parole auprès du public et des médias à cette fin.","description_en": "At least one person in the financial entity shall be tasked with implementing the communication strategy for ICT- related incidents and fulfil the public and media function for that purpose."},{"ref": "DORA-16.1","theme": "Cadre simplifié de gestion des risques","theme_en": "Simplified ICT Risk Management","mesure": "Les articles 5 à 15 du présent règlement ne s'appliquent pas aux petites entreprises d'investissement non interconnectées, aux établissements de paiem","mesure_en": "Articles 5 to 15 of this Regulation shall not apply to small and non-interconnected investment firms, payment institutions exempted pursuant to Direct","description": "Les articles 5 à 15 du présent règlement ne s'appliquent pas aux petites entreprises d'investissement non interconnectées, aux établissements de paiement exemptés en vertu de la directive (UE) 2015/2366 ; aux établissements exemptés en vertu de la directive 2013/36/UE pour lesquels les États membres ont décidé de ne pas appliquer l'option visée à l'article 2, paragraphe 4, du présent règlement ; aux établissements de monnaie électronique exemptés en vertu de la directive 2009/110/CE ; et aux petites institutions de retraite professionnelle.\n(a) mettre en place et maintenir un cadre de gestion du risque TIC solide et documenté détaillant les mécanismes et mesures visant à une gestion rapide, efficace et complète du risque TIC, y compris pour la protection des composantes physiques et infrastructures pertinentes ;\n(b) surveiller en permanence la sécurité et le fonctionnement de tous les systèmes TIC ;\n(c) minimiser l'impact du risque TIC par l'utilisation de systèmes, protocoles et outils TIC solides, résilients et actualisés, appropriés pour soutenir l'exécution de leurs activités.","description_en": "Articles 5 to 15 of this Regulation shall not apply to small and non-interconnected investment firms, payment institutions exempted pursuant to Directive (EU) 2015/2366; institutions exempted pursuant to Directive 2013/36/EU in respect of which Member States have decided not to apply the option referred to in Article 2(4) of this Regulation; electronic money institutions exempted pursuant to Directive 2009/110/EC; and small institutions for occupational retirement provision.\n(a) put in place and maintain a sound and documented ICT risk management framework that details the mechanisms and measures aimed at a quick, efficient and comprehensive management of ICT risk, including for the protection of relevant physical components and infrastructures;\n(b) continuously monitor the security and functioning of all ICT systems;\n(c) minimise the impact of ICT risk through the use of sound, resilient and updated ICT systems, protocols and tools which are appropriate to support the performance of t"},{"ref": "DORA-16.2","theme": "Cadre simplifié de gestion des risques","theme_en": "Simplified ICT Risk Management","mesure": "Le cadre de gestion du risque TIC visé au paragraphe 1, deuxième alinéa, point a), est documenté et réexaminé périodiquement et à la suite d'incident","mesure_en": "The ICT risk management framework referred to in paragraph 1, second subparagraph, point (a), shall be documented and reviewed periodically and upon t","description": "Le cadre de gestion du risque TIC visé au paragraphe 1, deuxième alinéa, point a), est documenté et réexaminé périodiquement et à la suite d'incidents majeurs liés aux TIC, conformément aux instructions prudentielles. Il est amélioré en permanence sur la base des enseignements tirés de la mise en œuvre et du suivi. Un rapport sur le réexamen du cadre de gestion du risque TIC est soumis à l'autorité compétente sur demande.","description_en": "The ICT risk management framework referred to in paragraph 1, second subparagraph, point (a), shall be documented and reviewed periodically and upon the occurrence of major ICT-related incidents in compliance with supervisory instructions. It shall be continuously improved on the basis of lessons derived from implementation and monitoring. A report on the review of the ICT risk management framework shall be submitted to the competent authority upon its request."},{"ref": "DORA-16.3","theme": "Cadre simplifié de gestion des risques","theme_en": "Simplified ICT Risk Management","mesure": "Les AES, par l'intermédiaire du comité conjoint, en consultation avec l'ENISA, élaborent des projets communs de normes techniques de réglementation af","mesure_en": "The ESAs shall, through the Joint Committee, in consultation with the ENISA, develop common draft regulatory technical standards in order to:","description": "Les AES, par l'intermédiaire du comité conjoint, en consultation avec l'ENISA, élaborent des projets communs de normes techniques de réglementation afin de :\n(a) préciser les éléments à inclure dans le cadre de gestion du risque TIC visé au paragraphe 1, deuxième alinéa, point a) ;\n(b) préciser les éléments relatifs aux systèmes, protocoles et outils visant à minimiser l'impact du risque TIC visés au paragraphe 1, deuxième alinéa, point c), en vue de garantir la sécurité des réseaux, de permettre des protections adéquates contre les intrusions et l'utilisation abusive des données, et de préserver la disponibilité, l'authenticité, l'intégrité et la confidentialité des données ;\n(c) préciser les composantes des plans de continuité des activités TIC visés au paragraphe 1, deuxième alinéa, point f) ;\n(d) préciser les règles relatives aux tests des plans de continuité des activités et garantir l'efficacité des contrôles visés au paragraphe 1, deuxième alinéa, point g).","description_en": "The ESAs shall, through the Joint Committee, in consultation with the ENISA, develop common draft regulatory technical standards in order to:\n(a)\tspecify further the elements to be included in the ICT risk management framework referred to in paragraph 1, second subparagraph, point (a);\n(b)\tspecify further the elements in relation to systems, protocols and tools to minimise the impact of ICT risk referred to in paragraph 1, second subparagraph, point (c), with a view to ensuring the security of networks, enabling adequate safeguards against intrusions and data misuse and preserving the availability, authenticity, integrity and confidentiality of data;\n(c)\tspecify further the components of the ICT business continuity plans referred to in paragraph 1, second subparagraph, point (f);\n(d)\tspecify further the rules on the testing of business continuity plans and ensure the effectiveness of the controls referred to in paragraph 1, second subparagraph, point (g) and ensure that such testing du"},{"ref": "DORA-17.1","theme": "Gestion des incidents TIC","theme_en": "ICT Incident Management","mesure": "Les entités financières définissent, établissent et mettent en œuvre un processus de gestion des incidents liés aux TIC pour détecter, gérer et notifi","mesure_en": "Financial entities shall define, establish and implement an ICT-related incident management process to detect, manage and notify ICT-related incidents","description": "Les entités financières définissent, établissent et mettent en œuvre un processus de gestion des incidents liés aux TIC pour détecter, gérer et notifier les incidents liés aux TIC.","description_en": "Financial entities shall define, establish and implement an ICT-related incident management process to detect, manage and notify ICT-related incidents."},{"ref": "DORA-17.2","theme": "Gestion des incidents TIC","theme_en": "ICT Incident Management","mesure": "Les entités financières enregistrent tous les incidents liés aux TIC et les cybermenaces significatives. Elles établissent des procédures et processus","mesure_en": "Financial entities shall record all ICT-related incidents and significant cyber threats. Financial entities shall establish appropriate procedures and","description": "Les entités financières enregistrent tous les incidents liés aux TIC et les cybermenaces significatives. Elles établissent des procédures et processus appropriés pour assurer un suivi, un traitement et un contrôle cohérents et intégrés des incidents liés aux TIC, afin de garantir que les causes profondes sont identifiées, documentées et traitées pour prévenir la survenance de tels incidents.","description_en": "Financial entities shall record all ICT-related incidents and significant cyber threats. Financial entities shall establish appropriate procedures and processes to ensure a consistent and integrated monitoring, handling and follow-up of ICT- related incidents, to ensure that root causes are identified, documented and addressed in order to prevent the occurrence of such incidents."},{"ref": "DORA-17.3","theme": "Gestion des incidents TIC","theme_en": "ICT Incident Management","mesure": "Le processus de gestion des incidents liés aux TIC visé au paragraphe 1 doit :","mesure_en": "The ICT-related incident management process referred to in paragraph 1 shall:","description": "Le processus de gestion des incidents liés aux TIC visé au paragraphe 1 doit :\n(a) mettre en place des indicateurs d'alerte précoce ;\n(b) établir des procédures pour identifier, suivre, enregistrer, catégoriser et classer les incidents liés aux TIC en fonction de leur priorité et de leur gravité et de la criticité des services concernés, conformément aux critères définis à l'article 18, paragraphe 1 ;\n(c) attribuer les rôles et responsabilités à activer pour les différents types et scénarios d'incidents liés aux TIC ;\n(d) définir des plans de communication au personnel, aux parties prenantes externes et aux médias conformément à l'article 14 et de notification aux clients, pour les procédures d'escalade interne, y compris les réclamations des clients liées aux TIC, ainsi que pour la fourniture d'informations aux entités financières agissant en tant que contreparties, le cas échéant ;\n(e) veiller à ce qu'au minimum les incidents majeurs liés aux TIC soient signalés à la direction compétente et informer l'organe de direction d'au minimum les incidents majeurs liés aux TIC.","description_en": "The ICT-related incident management process referred to in paragraph 1 shall:\n(a) put in place early warning indicators;\n(b) establish procedures to identify, track, log, categorise and classify ICT-related incidents according to their priority and severity and according to the criticality of the services impacted, in accordance with the criteria set out in Article 18(1);\n(c) assign roles and responsibilities that need to be activated for different ICT-related incident types and scenarios;\n(d) set out plans for communication to staff, external stakeholders and media in accordance with Article 14 and for notification to clients, for internal escalation procedures, including ICT-related customer complaints, as well as for the provision of information to financial entities that act as counterparts, as appropriate;\n(e) ensure that at least major ICT-related incidents are reported to relevant senior management and inform the management body of at least major ICT-related incidents, explainin"},{"ref": "DORA-18.1","theme": "Classification des incidents","theme_en": "Incident Classification","mesure": "Les entités financières classifient les incidents liés aux TIC et déterminent leur impact sur la base des critères suivants :","mesure_en": "Financial entities shall classify ICT-related incidents and shall determine their impact based on the following criteria:","description": "Les entités financières classifient les incidents liés aux TIC et déterminent leur impact sur la base des critères suivants :\n(a) le nombre et/ou la pertinence des clients ou des contreparties financières concernés et, le cas échéant, le montant ou le nombre de transactions affectées par l'incident lié aux TIC, et si l'incident a causé un préjudice de réputation ;\n(b) la durée de l'incident lié aux TIC, y compris l'interruption de service ;\n(c) la répartition géographique des zones affectées par l'incident lié aux TIC, en particulier s'il touche plus de deux États membres ;\n(d) les pertes de données que l'incident lié aux TIC entraîne, en termes de disponibilité, d'authenticité, d'intégrité ou de confidentialité des données ;\n(e) la criticité des services affectés, y compris les transactions et opérations de l'entité financière ;\n(f) l'impact économique, en particulier les coûts et pertes directs et indirects, de l'incident lié aux TIC en termes absolus et relatifs.","description_en": "Financial entities shall classify ICT-related incidents and shall determine their impact based on the following criteria:\n(a) the number and/or relevance of clients or financial counterparts affected and, where applicable, the amount or number of transactions affected by the ICT-related incident, and whether the ICT-related incident has caused reputational impact;\n(b) the duration of the ICT-related incident, including the service downtime;\n(c) the geographical spread with regard to the areas affected by the ICT-related incident, particularly if it affects more than two Member States;\n(d) the data losses that the ICT-related incident entails, in relation to availability, authenticity, integrity or confidentiality of data;\n(e) the criticality of the services affected, including the financial entity’s transactions and operations;\n(f) the economic impact, in particular direct and indirect costs and losses, of the ICT-related incident in both absolute and relative terms."},{"ref": "DORA-18.2","theme": "Classification des incidents","theme_en": "Incident Classification","mesure": "Les entités financières classifient les cybermenaces comme significatives sur la base de la criticité des services à risque, y compris les transactions","mesure_en": "Financial entities shall classify cyber threats as significant based on the criticality of the services at risk, including the financial entity’s tran","description": "Les entités financières classifient les cybermenaces comme significatives sur la base de la criticité des services à risque, y compris les transactions et opérations de l'entité financière, du nombre et/ou de la pertinence des clients ou des contreparties financières ciblés et de la répartition géographique des zones à risque.","description_en": "Financial entities shall classify cyber threats as significant based on the criticality of the services at risk, including the financial entity’s transactions and operations, number and/or relevance of clients or financial counterparts targeted and the geographical spread of the areas at risk."},{"ref": "DORA-18.3","theme": "Classification des incidents","theme_en": "Incident Classification","mesure": "Les AES, par l'intermédiaire du comité conjoint et en consultation avec la BCE et l'ENISA, élaborent des projets communs de normes techniques de régle","mesure_en": "The ESAs shall, through the Joint Committee and in consultation with the ECB and ENISA, develop common draft regulatory technical standards further sp","description": "Les AES, par l'intermédiaire du comité conjoint et en consultation avec la BCE et l'ENISA, élaborent des projets communs de normes techniques de réglementation précisant davantage les éléments suivants :\n(a) les critères définis au paragraphe 1, y compris les seuils de matérialité pour la détermination des incidents majeurs liés aux TIC ou, le cas échéant, des incidents opérationnels ou de sécurité majeurs liés aux paiements, soumis à l'obligation de notification prévue à l'article 19, paragraphe 1 ;\n(b) les critères à appliquer par les autorités compétentes pour évaluer la pertinence des incidents majeurs liés aux TIC pour les autorités compétentes d'autres États membres, et les détails des rapports d'incidents majeurs liés aux TIC à partager avec d'autres autorités compétentes en vertu de l'article 19, paragraphes 6 et 7 ;\n(c) les critères définis au paragraphe 2 du présent article, y compris les seuils de matérialité élevés.","description_en": "The ESAs shall, through the Joint Committee and in consultation with the ECB and ENISA, develop common draft regulatory technical standards further specifying the following:\n(a)\tthe criteria set out in paragraph 1, including materiality thresholds for determining major ICT-related incidents or, as applicable, major operational or security payment-related incidents, that are subject to the reporting obligation laid down in Article 19(1);\n(b)\tthe criteria to be applied by competent authorities for the purpose of assessing the relevance of major ICT-related incidents or, as applicable, major operational or security payment-related incidents, to relevant competent authorities in other Member States’, and the details of reports of major ICT-related incidents or, as applicable, major operational or security payment-related incidents, to be shared with other competent authorities pursuant to Article 19(6) and (7);\n(c)\tthe criteria set out in paragraph 2 of this Article, including high materia"},{"ref": "DORA-18.4","theme": "Classification des incidents","theme_en": "Incident Classification","mesure": "Lors de l'élaboration des projets communs de normes techniques de réglementation visés au paragraphe 3, les AES tiennent compte des critères définis à","mesure_en": "When developing the common draft regulatory technical standards referred to in paragraph 3 of this Article, the ESAs shall take into account the crite","description": "Lors de l'élaboration des projets communs de normes techniques de réglementation visés au paragraphe 3 du présent article, les AES tiennent compte des critères définis à l'article 4, paragraphe 2, ainsi que des normes internationales, des orientations et des spécifications élaborées et publiées par l'ENISA, y compris, le cas échéant, des spécifications relatives à d'autres secteurs économiques. Aux fins de l'application des critères définis à l'article 4, paragraphe 2, les AES tiennent dûment compte de la nécessité pour les micro-entreprises et les petites et moyennes entreprises de mobiliser des ressources et des capacités suffisantes pour garantir une gestion rapide des incidents liés aux TIC.\nLes AES soumettent ces projets communs de normes techniques de réglementation à la Commission au plus tard le 17 janvier 2024.\nLa Commission est habilitée à compléter le présent règlement en adoptant les normes techniques de réglementation visées au paragraphe 3 conformément aux articles 10 à 14 des règlements (UE) nº 1093/2010, (UE) nº 1094/2010 et (UE) nº 1095/2010.","description_en": "When developing the common draft regulatory technical standards referred to in paragraph 3 of this Article, the ESAs shall take into account the criteria set out in Article 4(2), as well as international standards, guidance and specifications developed and published by ENISA, including, where appropriate, specifications for other economic sectors. For the purposes of applying the criteria set out in Article 4(2), the ESAs shall duly consider the need for microenterprises and small and medium-sized enterprises to mobilise sufficient resources and capabilities to ensure that ICT-related incidents are managed swiftly.\nThe ESAs shall submit those common draft regulatory technical standards to the Commission by 17 January 2024.\nPower is delegated to the Commission to supplement this Regulation by adopting the regulatory technical standards referred to in paragraph 3 in accordance with Articles 10 to 14 of Regulations (EU) No 1093/2010, (EU) No 1094/2010 and (EU) No 1095/2010."},{"ref": "DORA-19.1","theme": "Déclaration des incidents majeurs","theme_en": "Major Incident Reporting","mesure": "Les entités financières signalent les incidents majeurs liés aux TIC à l'autorité compétente concernée visée à l'article 46, conformément au paragraph","mesure_en": "Financial entities shall report major ICT-related incidents to the relevant competent authority as referred to in Article 46 in accordance with paragr","description": "Les entités financières signalent les incidents majeurs liés aux TIC à l'autorité compétente concernée visée à l'article 46, conformément au paragraphe 4 du présent article.","description_en": "Financial entities shall report major ICT-related incidents to the relevant competent authority as referred to in Article 46 in accordance with paragraph 4 of this Article."},{"ref": "DORA-19.2","theme": "Déclaration des incidents majeurs","theme_en": "Major Incident Reporting","mesure": "Les entités financières peuvent, sur une base volontaire, notifier les cybermenaces significatives à l'autorité compétente concernée lorsqu'elles estim","mesure_en": "Financial entities may, on a voluntary basis, notify significant cyber threats to the relevant competent authority when they deem the threat to be of ","description": "Les entités financières peuvent, sur une base volontaire, notifier les cybermenaces significatives à l'autorité compétente concernée lorsqu'elles estiment que la menace est pertinente pour le système financier, les utilisateurs de services ou les clients. L'autorité compétente concernée peut communiquer ces informations à d'autres autorités compétentes visées au paragraphe 6.","description_en": "Financial entities may, on a voluntary basis, notify significant cyber threats to the relevant competent authority when they deem the threat to be of relevance to the financial system, service users or clients. The relevant competent authority may provide such information to other relevant authorities referred to in paragraph 6."},{"ref": "DORA-19.3","theme": "Déclaration des incidents majeurs","theme_en": "Major Incident Reporting","mesure": "Lorsqu'un incident majeur lié aux TIC se produit et a un impact sur les intérêts financiers des clients, les entités financières informent, sans retar","mesure_en": "Where a major ICT-related incident occurs and has an impact on the financial interests of clients, financial entities shall, without undue delay as so","description": "Lorsqu'un incident majeur lié aux TIC se produit et a un impact sur les intérêts financiers des clients, les entités financières informent, sans retard injustifié dès qu'elles en ont connaissance, leurs clients de l'incident majeur lié aux TIC et des mesures prises pour atténuer les effets négatifs de cet incident.","description_en": "Where a major ICT-related incident occurs and has an impact on the financial interests of clients, financial entities shall, without undue delay as soon as they become aware of it, inform their clients about the major ICT-related incident and about the measures that have been taken to mitigate the adverse effects of such incident."},{"ref": "DORA-19.4","theme": "Déclaration des incidents majeurs","theme_en": "Major Incident Reporting","mesure": "Les entités financières soumettent, dans les délais à fixer conformément à l'article 20, premier alinéa, point a), sous-point ii), les éléments suivan","mesure_en": "Financial entities shall, within the time limits to be laid down in accordance with Article 20, first paragraph, point (a), point (ii), submit the fol","description": "Les entités financières soumettent, dans les délais à fixer conformément à l'article 20, premier alinéa, point a), sous-point ii), les éléments suivants à l'autorité compétente concernée :\n(a) une notification initiale ;\n(b) un rapport intermédiaire après la notification initiale visée au point a), dès que le statut de l'incident initial a changé de manière significative ou que le traitement de l'incident majeur lié aux TIC a évolué sur la base de nouvelles informations disponibles, suivi, le cas échéant, de notifications actualisées chaque fois qu'une mise à jour pertinente du statut est disponible, ainsi que sur demande spécifique de l'autorité compétente ;\n(c) un rapport final, lorsque l'analyse des causes profondes a été achevée, que des mesures d'atténuation aient ou non déjà été mises en œuvre, et lorsque les chiffres d'impact réels sont disponibles pour remplacer les estimations.","description_en": "Financial entities shall, within the time limits to be laid down in accordance with Article 20, first paragraph, point (a), point (ii), submit the following to the relevant competent authority:\n(a) an initial notification;\n(b) an intermediate report after the initial notification referred to in point (a), as soon as the status of the original incident has changed significantly or the handling of the major ICT-related incident has changed based on new information available, followed, as appropriate, by updated notifications every time a relevant status update is available, as well as upon a specific request of the competent authority;\n(c) a final report, when the root cause analysis has been completed, regardless of whether mitigation measures have already been implemented, and when the actual impact figures are available to replace estimates."},{"ref": "DORA-19.5","theme": "Déclaration des incidents majeurs","theme_en": "Major Incident Reporting","mesure": "Les entités financières peuvent externaliser, conformément au droit sectoriel de l'Union et national, les obligations de notification prévues au présen","mesure_en": "Financial entities may outsource, in accordance with Union and national sectoral law, the reporting obligations under this Article to a third-party se","description": "Les entités financières peuvent externaliser, conformément au droit sectoriel de l'Union et national, les obligations de notification prévues au présent article à un prestataire de services tiers. En cas d'une telle externalisation, l'entité financière reste pleinement responsable du respect des obligations de notification des incidents.","description_en": "Financial entities may outsource, in accordance with Union and national sectoral law, the reporting obligations under this Article to a third-party service provider. In case of such outsourcing, the financial entity remains fully responsible for the fulfilment of the incident reporting requirements."},{"ref": "DORA-19.6","theme": "Déclaration des incidents majeurs","theme_en": "Major Incident Reporting","mesure": "Dès réception de la notification initiale et de chaque rapport visé au paragraphe 4, l'autorité compétente fournit en temps utile les détails de l'inc","mesure_en": "Upon receipt of the initial notification and of each report referred to in paragraph 4, the competent authority shall, in a timely manner, provide det","description": "Dès réception de la notification initiale et de chaque rapport visé au paragraphe 4, l'autorité compétente fournit en temps utile les détails de l'incident majeur lié aux TIC aux destinataires suivants, selon leurs compétences respectives :\n(a) l'ABE, l'AEMF ou l'AEAPP ;\n(b) la BCE, dans le cas des entités financières visées à l'article 2, paragraphe 1, points a), b) et d) ;\n(c) les autorités compétentes, points de contact uniques ou CSIRT désignés ou établis conformément à la directive (UE) 2022/2555 ;\n(d) les autorités de résolution, visées à l'article 3 de la directive 2014/59/UE, et le Conseil de résolution unique (CRU) pour les entités visées à l'article 7, paragraphe 2, du règlement (UE) nº 806/2014.","description_en": "Upon receipt of the initial notification and of each report referred to in paragraph 4, the competent authority shall, in a timely manner, provide details of the major ICT-related incident to the following recipients based, as applicable, on their respective competences:\n(a)\tEBA, ESMA or EIOPA;\n(b)\tthe ECB, in the case of financial entities referred to in Article 2(1), points (a), (b) and (d);\n(c)\tthe competent authorities, single points of contact or CSIRTs designated or established in accordance with Directive (EU) 2022/2555;\n(d)\tthe resolution authorities, as referred to in Article 3 of Directive 2014/59/EU, and the Single Resolution Board (SRB) with respect to entities referred to in Article 7(2) of Regulation (EU) No 806/2014 of the European Parliament and of the Council (37), and with respect to entities and groups referred to in Article 7(4)(b) and (5) of Regulation (EU) No 806/2014 if such details concern incidents that pose a risk to ensuring critical functions within the mean"},{"ref": "DORA-19.7","theme": "Déclaration des incidents majeurs","theme_en": "Major Incident Reporting","mesure": "À la suite de la réception des informations conformément au paragraphe 6, l'ABE, l'AEMF ou l'AEAPP et la BCE, en consultation avec l'ENISA et en coopé","mesure_en": "Following receipt of information in accordance with paragraph 6, EBA, ESMA or EIOPA and the ECB, in consultation with ENISA and in cooperation with th","description": "À la suite de la réception des informations conformément au paragraphe 6, l'ABE, l'AEMF ou l'AEAPP et la BCE, en consultation avec l'ENISA et en coopération avec l'autorité compétente concernée, évaluent si l'incident majeur lié aux TIC est pertinent pour les autorités compétentes d'autres États membres. À la suite de cette évaluation, l'ABE, l'AEMF ou l'AEAPP notifient dès que possible les autorités compétentes concernées des autres États membres. La BCE notifie les membres du Système européen de banques centrales sur les questions pertinentes pour le système de paiement. Sur la base de cette notification, les autorités compétentes prennent, le cas échéant, toutes les mesures nécessaires pour protéger la stabilité immédiate du système financier.","description_en": "Following receipt of information in accordance with paragraph 6, EBA, ESMA or EIOPA and the ECB, in consultation with ENISA and in cooperation with the relevant competent authority, shall assess whether the major ICT-related incident is relevant for competent authorities in other Member States. Following that assessment, EBA, ESMA or EIOPA shall, as soon as possible, notify relevant competent authorities in other Member States accordingly. The ECB shall notify the members of the European System of Central Banks on issues relevant to the payment system. Based on that notification, the competent authorities shall, where appropriate, take all of the necessary measures to protect the immediate stability of the financial system."},{"ref": "DORA-19.8","theme": "Déclaration des incidents majeurs","theme_en": "Major Incident Reporting","mesure": "La notification effectuée par l'AEMF en vertu du paragraphe 7 du présent article est sans préjudice de la responsabilité de l'autorité compétente de","mesure_en": "The notification to be done by ESMA pursuant to paragraph 7 of this Article shall be without prejudice to the responsibility of the competent authorit","description": "La notification effectuée par l'AEMF en vertu du paragraphe 7 du présent article est sans préjudice de la responsabilité de l'autorité compétente de transmettre d'urgence les détails de l'incident majeur lié aux TIC à l'autorité compétente de l'État membre d'accueil, lorsqu'un dépositaire central de titres exerce une activité transfrontalière significative dans l'État membre d'accueil, que l'incident majeur lié aux TIC est susceptible d'avoir des conséquences graves pour les marchés financiers de l'État membre d'accueil et qu'il existe des accords de coopération entre autorités compétentes relatifs à la surveillance des entités financières.","description_en": "The notification to be done by ESMA pursuant to paragraph 7 of this Article shall be without prejudice to the responsibility of the competent authority to urgently transmit the details of the major ICT-related incident to the relevant authority in the host Member State, where a central securities depository has significant cross-border activity in the host Member State, the major ICT-related incident is likely to have severe consequences for the financial markets of the host Member State and where there are cooperation arrangements among competent authorities related to the supervision of financial entities."},{"ref": "DORA-20.1","theme": "Harmonisation des déclarations","theme_en": "Reporting Harmonisation","mesure": "Les AES, par l'intermédiaire du comité conjoint, et en consultation avec l'ENISA et la BCE, élaborent :","mesure_en": "The ESAs, through the Joint Committee, and in consultation with ENISA and the ECB, shall develop:","description": "Les AES, par l'intermédiaire du comité conjoint, et en consultation avec l'ENISA et la BCE, élaborent :\n(a) des projets communs de normes techniques de réglementation afin de :\n(i) établir le contenu des rapports relatifs aux incidents majeurs liés aux TIC afin de refléter les critères définis à l'article 18, paragraphe 1, et d'incorporer des éléments supplémentaires, tels que les détails permettant d'établir la pertinence de la notification pour d'autres États membres et si l'incident constitue ou non un incident opérationnel ou de sécurité majeur lié aux paiements ; (ii) déterminer les délais pour la notification initiale et pour chaque rapport visé à l'article 19, paragraphe 4 ;\n(iii) établir le contenu de la notification relative aux cybermenaces significatives.\nLors de l'élaboration de ces projets de normes techniques de réglementation, les AES tiennent compte de la taille et du profil de risque global de l'entité financière, ainsi que de la nature, de l'ampleur et de la complexité de ses services, activités et opérations.","description_en": "The ESAs, through the Joint Committee, and in consultation with ENISA and the ECB, shall develop:\n(a)\tcommon draft regulatory technical standards in order to:\n(i) establish the content of the reports for major ICT-related incidents in order to reflect the criteria laid down in Article 18(1) and incorporate further elements, such as details for establishing the relevance of the reporting for other Member States and whether it constitutes a major operational or security payment-related incident or not; (ii) determine the time limits for the initial notification and for each report referred to in Article 19(4);\n(iii) establish the content of the notification for significant cyber threats.\nWhen developing those draft regulatory technical standards, the ESAs shall take into account the size and the overall risk profile of the financial entity, and the nature, scale and complexity of its services, activities and operations, and in particular, with a view to ensuring that, for the purposes of"},{"ref": "DORA-21.1","theme": "Centralisation des déclarations","theme_en": "Reporting Centralisation","mesure": "Les AES, par l'intermédiaire du comité conjoint, et en consultation avec la BCE et l'ENISA, préparent un rapport conjoint évaluant la faisabilité d'un","mesure_en": "The ESAs, through the Joint Committee, and in consultation with the ECB and ENISA, shall prepare a joint report assessing the feasibility of further c","description": "Les AES, par l'intermédiaire du comité conjoint, et en consultation avec la BCE et l'ENISA, préparent un rapport conjoint évaluant la faisabilité d'une centralisation accrue des notifications d'incidents par la création d'un hub UE unique pour la notification des incidents majeurs liés aux TIC par les entités financières. Le rapport conjoint explore les moyens de faciliter le flux de notification d'incidents liés aux TIC, de réduire les coûts associés et de soutenir les analyses thématiques en vue de renforcer la convergence prudentielle.","description_en": "The ESAs, through the Joint Committee, and in consultation with the ECB and ENISA, shall prepare a joint report assessing the feasibility of further centralisation of incident reporting through the establishment of a single EU Hub for major ICT-related incident reporting by financial entities. The joint report shall explore ways to facilitate the flow of ICT- related incident reporting, reduce associated costs and underpin thematic analyses with a view to enhancing supervisory convergence."},{"ref": "DORA-21.2","theme": "Centralisation des déclarations","theme_en": "Reporting Centralisation","mesure": "Le rapport conjoint visé au paragraphe 1 comprend au moins les éléments suivants :","mesure_en": "The joint report referred to in paragraph 1 shall comprise at least the following elements:","description": "Le rapport conjoint visé au paragraphe 1 comprend au moins les éléments suivants :\n(a) les conditions préalables à la création d'un hub UE unique ;\n(b) les avantages, les limites et les risques, y compris les risques liés à la forte concentration d'informations sensibles ;\n(c) la capacité nécessaire pour garantir l'interopérabilité avec d'autres dispositifs de notification pertinents ;\n(d) les éléments de gestion opérationnelle ;\n(e) les conditions d'adhésion ;\n(f) les modalités techniques permettant aux entités financières et aux autorités compétentes nationales d'accéder au hub UE unique ;\n(g) une évaluation préliminaire des coûts financiers liés à la mise en place de la plateforme opérationnelle soutenant le hub UE unique, y compris l'expertise requise.","description_en": "The joint report referred to in paragraph 1 shall comprise at least the following elements:\n(a)\tprerequisites for the establishment of a single EU Hub;\n(b)\tbenefits, limitations and risks, including risks associated with the high concentration of sensitive information;\n(c)\tthe necessary capability to ensure interoperability with regard to other relevant reporting schemes;\n(d)\telements of operational management;\n(e)\tconditions of membership;\n(f)\ttechnical arrangements for financial entities and national competent authorities to access the single EU Hub;\n(g)\ta preliminary assessment of financial costs incurred by setting-up the operational platform supporting the single EU Hub, including the requisite expertise."},{"ref": "DORA-21.3","theme": "Centralisation des déclarations","theme_en": "Reporting Centralisation","mesure": "Les AES soumettent le rapport visé au paragraphe 1 au Parlement européen, au Conseil et à la Commission au plus tard le 17 janvier 2025.","mesure_en": "The ESAs shall submit the report referred to in paragraph 1 to the European Parliament, to the Council and to the Commission by 17 January 2025.","description": "Les AES soumettent le rapport visé au paragraphe 1 au Parlement européen, au Conseil et à la Commission au plus tard le 17 janvier 2025.","description_en": "The ESAs shall submit the report referred to in paragraph 1 to the European Parliament, to the Council and to the Commission by 17 January 2025."},{"ref": "DORA-22.1","theme": "Retour d'information","theme_en": "Supervisory Feedback","mesure": "Sans préjudice de l'apport technique, des conseils ou des mesures correctives et du suivi ultérieur qui peuvent être fournis, le cas échéant, conformém","mesure_en": "Without prejudice to the technical input, advice or remedies and subsequent follow-up which may be provided, where applicable, in accordance with nati","description": "Sans préjudice de l'apport technique, des conseils ou des mesures correctives et du suivi ultérieur qui peuvent être fournis, le cas échéant, conformément au droit national, par les CSIRT en vertu de la directive (UE) 2022/2555, l'autorité compétente, dès réception de la notification initiale et de chaque rapport visé à l'article 19, paragraphe 4, en accuse réception et peut, dans la mesure du possible, fournir en temps utile un retour d'information pertinent et proportionné ou des orientations de haut niveau à l'entité financière, notamment en mettant à disposition toute information anonymisée et tout renseignement pertinents sur des menaces similaires, et peut examiner les mesures correctives appliquées au niveau de l'entité financière et les moyens de minimiser et d'atténuer l'impact négatif dans l'ensemble du secteur financier. Sans préjudice du retour d'information prudentiel reçu, les entités financières restent pleinement responsables du traitement et des conséquences des incidents liés aux TIC signalés en vertu de l'article 19, paragraphe 1.","description_en": "Without prejudice to the technical input, advice or remedies and subsequent follow-up which may be provided, where applicable, in accordance with national law, by the CSIRTs under Directive (EU) 2022/2555, the competent authority shall, upon receipt of the initial notification and of each report as referred to in Article 19(4), acknowledge receipt and may, where feasible, provide in a timely manner relevant and proportionate feedback or high-level guidance to the financial entity, in particular by making available any relevant anonymised information and intelligence on similar threats, and may discuss remedies applied at the level of the financial entity and ways to minimise and mitigate adverse impact across the financial sector. Without prejudice to the supervisory feedback received, financial entities shall remain fully responsible for the handling and for consequences of the ICT-related incidents reported pursuant to Article 19(1)."},{"ref": "DORA-22.2","theme": "Retour d'information","theme_en": "Supervisory Feedback","mesure": "Les AES, par l'intermédiaire du comité conjoint, rendent compte chaque année, de manière anonymisée et agrégée, des incidents majeurs liés aux TIC, do","mesure_en": "The ESAs shall, through the Joint Committee, on an anonymised and aggregated basis, report yearly on major ICT- related incidents, the details of whic","description": "Les AES, par l'intermédiaire du comité conjoint, rendent compte chaque année, de manière anonymisée et agrégée, des incidents majeurs liés aux TIC, dont les détails sont fournis par les autorités compétentes conformément à l'article 19, paragraphe 6, en indiquant au minimum le nombre d'incidents majeurs liés aux TIC, leur nature et leur impact sur les opérations des entités financières ou des clients, les mesures correctives prises et les coûts encourus.","description_en": "The ESAs shall, through the Joint Committee, on an anonymised and aggregated basis, report yearly on major ICT- related incidents, the details of which shall be provided by competent authorities in accordance with Article 19(6), setting out at least the number of major ICT-related incidents, their nature and their impact on the operations of financial entities or clients, remedial actions taken and costs incurred."},{"ref": "DORA-22.3","theme": "Retour d'information","theme_en": "Supervisory Feedback","mesure": "Les AES émettent des alertes et produisent des statistiques de haut niveau pour soutenir les évaluations des menaces et vulnérabilités TIC.","mesure_en": "The ESAs shall issue warnings and produce high-level statistics to support ICT threat and vulnerability assessments.","description": "Les AES émettent des alertes et produisent des statistiques de haut niveau pour soutenir les évaluations des menaces et vulnérabilités TIC.","description_en": "The ESAs shall issue warnings and produce high-level statistics to support ICT threat and vulnerability assessments."},{"ref": "DORA-24.1","theme": "Tests de résilience","theme_en": "Resilience Testing","mesure": "Aux fins d'évaluer l'état de préparation au traitement des incidents liés aux TIC, d'identifier les faiblesses, lacunes et insuffisances en matière de","mesure_en": "For the purpose of assessing preparedness for handling ICT-related incidents, of identifying weaknesses, deficiencies and gaps in digital operational ","description": "Aux fins d'évaluer l'état de préparation au traitement des incidents liés aux TIC, d'identifier les faiblesses, lacunes et insuffisances en matière de résilience opérationnelle numérique, et de mettre rapidement en œuvre des mesures correctives, les entités financières, autres que les micro-entreprises, en tenant compte des critères définis à l'article 4, paragraphe 2, établissent, maintiennent et réexaminent un programme de tests de résilience opérationnelle numérique solide et complet, faisant partie intégrante du cadre de gestion du risque TIC visé à l'article 6.","description_en": "For the purpose of assessing preparedness for handling ICT-related incidents, of identifying weaknesses, deficiencies and gaps in digital operational resilience, and of promptly implementing corrective measures, financial entities, other than microenterprises, shall, taking into account the criteria set out in Article 4(2), establish, maintain and review a sound and comprehensive digital operational resilience testing programme as an integral part of the ICT risk-management framework referred to in Article 6."},{"ref": "DORA-24.2","theme": "Tests de résilience","theme_en": "Resilience Testing","mesure": "Le programme de tests de résilience opérationnelle numérique comprend une série d'évaluations, de tests, de méthodologies, de pratiques et d'outils à","mesure_en": "The digital operational resilience testing programme shall include a range of assessments, tests, methodologies, practices and tools to be applied in ","description": "Le programme de tests de résilience opérationnelle numérique comprend une série d'évaluations, de tests, de méthodologies, de pratiques et d'outils à appliquer conformément aux articles 25 et 26.","description_en": "The digital operational resilience testing programme shall include a range of assessments, tests, methodologies, practices and tools to be applied in accordance with Articles 25 and 26."},{"ref": "DORA-24.3","theme": "Tests de résilience","theme_en": "Resilience Testing","mesure": "Lors de la réalisation du programme de tests de résilience opérationnelle numérique visé au paragraphe 1, les entités financières, autres que les micro","mesure_en": "When conducting the digital operational resilience testing programme referred to in paragraph 1 of this Article, financial entities, other than microe","description": "Lors de la réalisation du programme de tests de résilience opérationnelle numérique visé au paragraphe 1 du présent article, les entités financières, autres que les micro-entreprises, adoptent une approche fondée sur les risques tenant compte des critères définis à l'article 4, paragraphe 2, en considérant dûment l'évolution du paysage du risque TIC, tout risque spécifique auquel l'entité financière concernée est ou pourrait être exposée, la criticité des actifs informationnels et des services fournis, ainsi que tout autre facteur que l'entité financière juge approprié.","description_en": "When conducting the digital operational resilience testing programme referred to in paragraph 1 of this Article, financial entities, other than microenterprises, shall follow a risk-based approach taking into account the criteria set out in Article 4(2) duly considering the evolving landscape of ICT risk, any specific risks to which the financial entity concerned is or might be exposed, the criticality of information assets and of services provided, as well as any other factor the financial entity deems appropriate."},{"ref": "DORA-24.4","theme": "Tests de résilience","theme_en": "Resilience Testing","mesure": "Les entités financières, autres que les micro-entreprises, veillent à ce que les tests soient réalisés par des parties indépendantes, qu'elles soient","mesure_en": "Financial entities, other than microenterprises, shall ensure that tests are undertaken by independent parties, whether internal or external. Where te","description": "Les entités financières, autres que les micro-entreprises, veillent à ce que les tests soient réalisés par des parties indépendantes, qu'elles soient internes ou externes. Lorsque les tests sont réalisés par un testeur interne, les entités financières allouent des ressources suffisantes et veillent à ce que les conflits d'intérêts soient évités tout au long des phases de conception et d'exécution du test.","description_en": "Financial entities, other than microenterprises, shall ensure that tests are undertaken by independent parties, whether internal or external. Where tests are undertaken by an internal tester, financial entities shall dedicate sufficient resources and ensure that conflicts of interest are avoided throughout the design and execution phases of the test."},{"ref": "DORA-24.5","theme": "Tests de résilience","theme_en": "Resilience Testing","mesure": "Les entités financières, autres que les micro-entreprises, établissent des procédures et politiques pour hiérarchiser, classer et corriger toutes les d","mesure_en": "Financial entities, other than microenterprises, shall establish procedures and policies to prioritise, classify and remedy all issues revealed throug","description": "Les entités financières, autres que les micro-entreprises, établissent des procédures et politiques pour hiérarchiser, classer et corriger toutes les déficiences révélées lors de l'exécution des tests et mettent en place des méthodologies de validation internes pour s'assurer que toutes les faiblesses, insuffisances ou lacunes identifiées sont entièrement corrigées.","description_en": "Financial entities, other than microenterprises, shall establish procedures and policies to prioritise, classify and remedy all issues revealed throughout the performance of the tests and shall establish internal validation methodologies to ascertain that all identified weaknesses, deficiencies or gaps are fully addressed."},{"ref": "DORA-24.6","theme": "Tests de résilience","theme_en": "Resilience Testing","mesure": "Les entités financières, autres que les micro-entreprises, veillent à ce que, au moins une fois par an, des tests appropriés soient réalisés sur tous l","mesure_en": "Financial entities, other than microenterprises, shall ensure, at least yearly, that appropriate tests are conducted on all ICT systems and applicatio","description": "Les entités financières, autres que les micro-entreprises, veillent à ce que, au moins une fois par an, des tests appropriés soient réalisés sur tous les systèmes et applications TIC soutenant des fonctions critiques ou importantes.","description_en": "Financial entities, other than microenterprises, shall ensure, at least yearly, that appropriate tests are conducted on all ICT systems and applications supporting critical or important functions."},{"ref": "DORA-25.1","theme": "Programme de tests","theme_en": "Testing Programme","mesure": "Le programme de tests de résilience opérationnelle numérique visé à l'article 24 prévoit, conformément aux critères définis à l'article 4(2), l'exécu","mesure_en": "The digital operational resilience testing programme referred to in Article 24 shall provide, in accordance with the criteria set out in Article 4(2),","description": "Le programme de tests de résilience opérationnelle numérique visé à l'article 24 prévoit, conformément aux critères définis à l'article 4, paragraphe 2, l'exécution de tests appropriés, tels que des évaluations et des scans de vulnérabilité, des analyses de code source ouvert, des évaluations de la sécurité des réseaux, des analyses d'écarts, des revues de sécurité physique, des questionnaires et des solutions logicielles de scan, des revues de code source lorsque cela est possible, des tests par scénarios, des tests de compatibilité, des tests de performance, des tests de bout en bout et des tests d'intrusion.","description_en": "The digital operational resilience testing programme referred to in Article 24 shall provide, in accordance with the criteria set out in Article 4(2), for the execution of appropriate tests, such as vulnerability assessments and scans, open source analyses, network security assessments, gap analyses, physical security reviews, questionnaires and scanning software solutions, source code reviews where feasible, scenario-based tests, compatibility testing, performance testing, end-to-end testing and penetration testing."},{"ref": "DORA-25.2","theme": "Programme de tests","theme_en": "Testing Programme","mesure": "Les dépositaires centraux de titres et les contreparties centrales procèdent à des évaluations de vulnérabilité avant tout déploiement ou redéploiemen","mesure_en": "Central securities depositories and central counterparties shall perform vulnerability assessments before any deployment or redeployment of new or exi","description": "Les dépositaires centraux de titres et les contreparties centrales procèdent à des évaluations de vulnérabilité avant tout déploiement ou redéploiement d'applications et de composantes d'infrastructure nouvelles ou existantes, et de services TIC soutenant des fonctions critiques ou importantes de l'entité financière.","description_en": "Central securities depositories and central counterparties shall perform vulnerability assessments before any deployment or redeployment of new or existing applications and infrastructure components, and ICT services supporting critical or important functions of the financial entity."},{"ref": "DORA-25.3","theme": "Programme de tests","theme_en": "Testing Programme","mesure": "Les micro-entreprises réalisent les tests visés au paragraphe 1 en combinant une approche fondée sur les risques et une planification stratégique des t","mesure_en": "Microenterprises shall perform the tests referred to in paragraph 1 by combining a risk-based approach with a strategic planning of ICT testing, by du","description": "Les micro-entreprises réalisent les tests visés au paragraphe 1 en combinant une approche fondée sur les risques et une planification stratégique des tests TIC, en tenant dûment compte de la nécessité de maintenir un équilibre entre l'ampleur des ressources et le temps à consacrer aux tests TIC prévus au présent article, d'une part, et l'urgence, le type de risque, la criticité des actifs informationnels et des services fournis, ainsi que tout autre facteur pertinent, y compris la capacité de l'entité financière à prendre des risques calculés, d'autre part.","description_en": "Microenterprises shall perform the tests referred to in paragraph 1 by combining a risk-based approach with a strategic planning of ICT testing, by duly considering the need to maintain a balanced approach between the scale of resources and the time to be allocated to the ICT testing provided for in this Article, on the one hand, and the urgency, type of risk, criticality of information assets and of services provided, as well as any other relevant factor, including the financial entity’s ability to take calculated risks, on the other hand."},{"ref": "DORA-26.1","theme": "Tests TLPT","theme_en": "TLPT Testing","mesure": "Les entités financières, autres que celles visées à l'article 16(1), premier alinéa, et autres que les micro-entreprises, identifiées conformément au","mesure_en": "Financial entities, other than entities referred to in Article 16(1), first subparagraph, and other than microenterprises, which are identified in acc","description": "Les entités financières, autres que celles visées à l'article 16, paragraphe 1, premier alinéa, et autres que les micro-entreprises, identifiées conformément au paragraphe 8, troisième alinéa, du présent article, réalisent au moins tous les 3 ans des tests avancés au moyen de TLPT. Sur la base du profil de risque de l'entité financière et compte tenu des circonstances opérationnelles, l'autorité compétente peut, si nécessaire, demander à l'entité financière de réduire ou d'augmenter cette fréquence.","description_en": "Financial entities, other than entities referred to in Article 16(1), first subparagraph, and other than microenterprises, which are identified in accordance with paragraph 8, third subparagraph, of this Article, shall carry out at least every 3 years advanced testing by means of TLPT. Based on the risk profile of the financial entity and taking into account operational circumstances, the competent authority may, where necessary, request the financial entity to reduce or increase this frequency."},{"ref": "DORA-26.2","theme": "Tests TLPT","theme_en": "TLPT Testing","mesure": "Chaque test d'intrusion fondé sur la menace couvre plusieurs ou toutes les fonctions critiques ou importantes d'une entité financière, et est réalisé","mesure_en": "Each threat-led penetration test shall cover several or all critical or important functions of a financial entity, and shall be performed on live prod","description": "Chaque test d'intrusion fondé sur la menace couvre plusieurs ou toutes les fonctions critiques ou importantes d'une entité financière, et est réalisé sur les systèmes de production en activité soutenant ces fonctions.","description_en": "Each threat-led penetration test shall cover several or all critical or important functions of a financial entity, and shall be performed on live production systems supporting such functions."},{"ref": "DORA-26.3","theme": "Tests TLPT","theme_en": "TLPT Testing","mesure": "Lorsque des prestataires tiers de services TIC sont inclus dans le périmètre du TLPT, l'entité financière prend les mesures et garanties nécessaires","mesure_en": "Where ICT third-party service providers are included in the scope of TLPT, the financial entity shall take the necessary measures and safeguards to en","description": "Lorsque des prestataires tiers de services TIC sont inclus dans le périmètre du TLPT, l'entité financière prend les mesures et garanties nécessaires pour assurer la participation de ces prestataires tiers de services TIC au TLPT et conserve à tout moment l'entière responsabilité du respect du présent règlement.","description_en": "Where ICT third-party service providers are included in the scope of TLPT, the financial entity shall take the necessary measures and safeguards to ensure the participation of such ICT third-party service providers in the TLPT and shall retain at all times full responsibility for ensuring compliance with this Regulation."},{"ref": "DORA-26.4","theme": "Tests TLPT","theme_en": "TLPT Testing","mesure": "Sans préjudice du paragraphe 2, premier et deuxième alinéas, lorsque la participation d'un prestataire tiers de services TIC au TLPT visé au paragraph","mesure_en": "Without prejudice to paragraph 2, first and second subparagraphs, where the participation of an ICT third-party service provider in the TLPT, referred","description": "Sans préjudice du paragraphe 2, premier et deuxième alinéas, lorsque la participation d'un prestataire tiers de services TIC au TLPT visé au paragraphe 3 est raisonnablement susceptible d'avoir un impact négatif sur la qualité ou la sécurité des services fournis par le prestataire tiers de services TIC à des clients qui sont des entités ne relevant pas du champ d'application du présent règlement, ou sur la confidentialité des données relatives à ces services, l'entité financière et le prestataire tiers de services TIC peuvent convenir par écrit que le prestataire tiers de services TIC conclut directement des arrangements contractuels avec un testeur externe, aux fins de la réalisation, sous la direction d'une entité financière désignée, d'un TLPT groupé impliquant plusieurs entités financières (test groupé) auxquelles le prestataire tiers de services TIC fournit des services TIC.","description_en": "Without prejudice to paragraph 2, first and second subparagraphs, where the participation of an ICT third-party service provider in the TLPT, referred to in paragraph 3, is reasonably expected to have an adverse impact on the quality or security of services delivered by the ICT third-party service provider to customers that are entities falling outside the scope of this Regulation, or on the confidentiality of the data related to such services, the financial entity and the ICT third-party service provider may agree in writing that the ICT third-party service provider directly enters into contractual arrangements with an external tester, for the purpose of conducting, under the direction of one designated financial entity, a pooled TLPT involving several financial entities (pooled testing) to which the ICT third-party service provider provides ICT services."},{"ref": "DORA-26.5","theme": "Tests TLPT","theme_en": "TLPT Testing","mesure": "Les entités financières, avec la coopération des prestataires tiers de services TIC et des autres parties impliquées, y compris les testeurs mais à l'e","mesure_en": "Financial entities shall, with the cooperation of ICT third-party service providers and other parties involved, including the testers but excluding th","description": "Les entités financières, avec la coopération des prestataires tiers de services TIC et des autres parties impliquées, y compris les testeurs mais à l'exclusion des autorités compétentes, appliquent des contrôles efficaces de gestion des risques pour atténuer les risques d'impact potentiel sur les données, de dommages aux actifs et de perturbation des fonctions, services ou opérations critiques ou importants au sein de l'entité financière elle-même, de ses contreparties ou du secteur financier.","description_en": "Financial entities shall, with the cooperation of ICT third-party service providers and other parties involved, including the testers but excluding the competent authorities, apply effective risk management controls to mitigate the risks of any potential impact on data, damage to assets, and disruption to critical or important functions, services or operations at the financial entity itself, its counterparts or to the financial sector."},{"ref": "DORA-26.6","theme": "Tests TLPT","theme_en": "TLPT Testing","mesure": "À l'issue des tests, après que les rapports et les plans de remédiation ont été convenus, l'entité financière et, le cas échéant, les testeurs externe","mesure_en": "At the end of the testing, after reports and remediation plans have been agreed, the financial entity and, where applicable, the external testers shal","description": "À l'issue des tests, après que les rapports et les plans de remédiation ont été convenus, l'entité financière et, le cas échéant, les testeurs externes fournissent à l'autorité désignée conformément au paragraphe 9 ou 10, un résumé des constatations pertinentes, les plans de remédiation et la documentation démontrant que le TLPT a été réalisé conformément aux exigences.","description_en": "At the end of the testing, after reports and remediation plans have been agreed, the financial entity and, where applicable, the external testers shall provide to the authority, designated in accordance with paragraph 9 or 10, a summary of the relevant findings, the remediation plans and the documentation demonstrating that the TLPT has been conducted in accordance with the requirements."},{"ref": "DORA-26.7","theme": "Tests TLPT","theme_en": "TLPT Testing","mesure": "Les autorités fournissent aux entités financières une attestation confirmant que le test a été réalisé conformément aux exigences, attesté par la docum","mesure_en": "Authorities shall provide financial entities with an attestation confirming that the test was performed in accordance with the requirements as evidenc","description": "Les autorités fournissent aux entités financières une attestation confirmant que le test a été réalisé conformément aux exigences, attesté par la documentation, afin de permettre la reconnaissance mutuelle des tests d'intrusion fondés sur la menace entre autorités compétentes. L'entité financière notifie à l'autorité compétente concernée l'attestation, le résumé des constatations pertinentes et les plans de remédiation.","description_en": "Authorities shall provide financial entities with an attestation confirming that the test was performed in accordance with the requirements as evidenced in the documentation in order to allow for mutual recognition of threat led penetration tests between competent authorities. The financial entity shall notify the relevant competent authority of the attestation, the summary of the relevant findings and the remediation plans."},{"ref": "DORA-26.8","theme": "Tests TLPT","theme_en": "TLPT Testing","mesure": "Les entités financières contractent des testeurs aux fins de la réalisation de TLPT conformément à l'article 27. Lorsque les entités financières utilis","mesure_en": "Financial entities shall contract testers for the purposes of undertaking TLPT in accordance with Article 27. When financial entities use internal tes","description": "Les entités financières contractent des testeurs aux fins de la réalisation de TLPT conformément à l'article 27. Lorsque les entités financières utilisent des testeurs internes aux fins de la réalisation de TLPT, elles contractent des testeurs externes tous les trois tests.","description_en": "Financial entities shall contract testers for the purposes of undertaking TLPT in accordance with Article 27. When financial entities use internal testers for the purposes of undertaking TLPT, they shall contract external testers every three tests."},{"ref": "DORA-26.9","theme": "Tests TLPT","theme_en": "TLPT Testing","mesure": "Les États membres peuvent désigner une autorité publique unique dans le secteur financier responsable des questions liées au TLPT dans le secteur finan","mesure_en": "Member States may designate a single public authority in the financial sector to be responsible for TLPT-related matters in the financial sector at na","description": "Les États membres peuvent désigner une autorité publique unique dans le secteur financier responsable des questions liées au TLPT dans le secteur financier au niveau national et lui confient toutes les compétences et missions à cet effet.","description_en": "Member States may designate a single public authority in the financial sector to be responsible for TLPT-related matters in the financial sector at national level and shall entrust it with all competences and tasks to that effect."},{"ref": "DORA-26.10","theme": "Tests TLPT","theme_en": "TLPT Testing","mesure": "En l'absence de désignation conformément au paragraphe 9 du présent article, et sans préjudice du pouvoir d'identifier les entités financières tenues","mesure_en": "In the absence of a designation in accordance with paragraph 9 of this Article, and without prejudice to the power to identify the financial entities ","description": "En l'absence de désignation conformément au paragraphe 9 du présent article, et sans préjudice du pouvoir d'identifier les entités financières tenues de réaliser des TLPT, une autorité compétente peut déléguer l'exercice de certaines ou de toutes les missions visées au présent article et à l'article 27 à une autre autorité nationale du secteur financier.","description_en": "In the absence of a designation in accordance with paragraph 9 of this Article, and without prejudice to the power to identify the financial entities that are required to perform TLPT, a competent authority may delegate the exercise of some or all of the tasks referred to in this Article and Article 27 to another national authority in the financial sector."},{"ref": "DORA-26.11","theme": "Tests TLPT","theme_en": "TLPT Testing","mesure": "Les AES, en accord avec la BCE, élaborent des projets conjoints de normes techniques de réglementation conformément au cadre TIBER-EU afin de préciser","mesure_en": "The ESAs shall, in agreement with the ECB, develop joint draft regulatory technical standards in accordance with the TIBER-EU framework in order to sp","description": "Les AES, en accord avec la BCE, élaborent des projets conjoints de normes techniques de réglementation conformément au cadre TIBER-EU afin de préciser davantage :\n(a) les critères utilisés aux fins de l'application du paragraphe 8, deuxième alinéa ;\n(b) les exigences et normes régissant le recours à des testeurs internes ;\n(c) les exigences relatives à :\n(i) le périmètre du TLPT visé au paragraphe 2 ;\n(ii) la méthodologie et l'approche de test à suivre pour chaque phase spécifique du processus de test ;\n(iii) les résultats, la clôture et les étapes de remédiation des tests ;\n(d) le type de coopération prudentielle et autres coopérations pertinentes nécessaires à la mise en œuvre du TLPT et à la facilitation de la reconnaissance mutuelle de ces tests, dans le contexte des entités financières opérant dans plus d'un État membre.","description_en": "The ESAs shall, in agreement with the ECB, develop joint draft regulatory technical standards in accordance with the TIBER-EU framework in order to specify further:\n(a)\tthe criteria used for the purpose of the application of paragraph 8, second subparagraph;\n(b)\tthe requirements and standards governing the use of internal testers;\n(c)\tthe requirements in relation to:\n(i)\tthe scope of TLPT referred to in paragraph 2;\n(ii)\tthe testing methodology and approach to be followed for each specific phase of the testing process;\n(iii)\tthe results, closure and remediation stages of the testing;\n(d)\tthe type of supervisory and other relevant cooperation which are needed for the implementation of TLPT, and for the facilitation of mutual recognition of that testing, in the context of financial entities that operate in more than one Member State, to allow an appropriate level of supervisory involvement and a flexible implementation to cater for specificities of financial sub-sectors or local financia"},{"ref": "DORA-27.1","theme": "Exigences TLPT","theme_en": "TLPT Requirements","mesure": "Les entités financières n'utilisent que des testeurs pour la réalisation de TLPT qui :","mesure_en": "Financial entities shall only use testers for the carrying out of TLPT, that:","description": "Les entités financières n'utilisent que des testeurs pour la réalisation de TLPT qui :\n(a) présentent le plus haut niveau d'aptitude et de réputation ;\n(b) possèdent des capacités techniques et organisationnelles et démontrent une expertise spécifique en matière de renseignement sur les menaces, de tests d'intrusion et de tests « red team » ;\n(c) sont certifiés par un organisme d'accréditation d'un État membre ou adhèrent à des codes de conduite formels ou à des cadres éthiques ;\n(d) fournissent une assurance indépendante ou un rapport d'audit relatif à la bonne gestion des risques liés à la réalisation de TLPT, y compris la protection adéquate des informations confidentielles de l'entité financière et les recours pour les risques commerciaux de l'entité financière ;\n(e) sont dûment et entièrement couverts par des assurances de responsabilité professionnelle pertinentes, y compris contre les risques de faute et de négligence.","description_en": "Financial entities shall only use testers for the carrying out of TLPT, that:\n(a) are of the highest suitability and reputability;\n(b) possess technical and organisational capabilities and demonstrate specific expertise in threat intelligence, penetration testing and red team testing;\n(c) are certified by an accreditation body in a Member State or adhere to formal codes of conduct or ethical frameworks;\n(d) provide an independent assurance, or an audit report, in relation to the sound management of risks associated with the carrying out of TLPT, including the due protection of the financial entity’s confidential information and redress for the business risks of the financial entity;\n(e) are duly and fully covered by relevant professional indemnity insurances, including against risks of misconduct and negligence."},{"ref": "DORA-27.2","theme": "Exigences TLPT","theme_en": "TLPT Requirements","mesure": "Lorsque les entités financières recourent à des testeurs internes, elles veillent, outre le respect des exigences du paragraphe 1, à ce que les conditi","mesure_en": "When using internal testers, financial entities shall ensure that, in addition to the requirements in paragraph 1, the following conditions are met:","description": "Lorsque les entités financières recourent à des testeurs internes, elles veillent, outre le respect des exigences du paragraphe 1, à ce que les conditions suivantes soient remplies :\n(a) ce recours a été approuvé par l'autorité compétente concernée ou par l'autorité publique unique désignée conformément à l'article 26, paragraphes 9 et 10 ;\n(b) l'autorité compétente concernée a vérifié que l'entité financière dispose de ressources dédiées suffisantes et a assuré que les conflits d'intérêts sont évités tout au long des phases de conception et d'exécution du test ; et\n(c) le fournisseur de renseignements sur les menaces est externe à l'entité financière.","description_en": "When using internal testers, financial entities shall ensure that, in addition to the requirements in paragraph 1, the following conditions are met:\n(a) such use has been approved by the relevant competent authority or by the single public authority designated in accordance with Article 26(9) and (10);\n(b) the relevant competent authority has verified that the financial entity has sufficient dedicated resources and ensured that conflicts of interest are avoided throughout the design and execution phases of the test; and\n(c) the threat intelligence provider is external to the financial entity."},{"ref": "DORA-27.3","theme": "Exigences TLPT","theme_en": "TLPT Requirements","mesure": "Les entités financières veillent à ce que les contrats conclus avec des testeurs externes prévoient une gestion rigoureuse des résultats du TLPT et que","mesure_en": "Financial entities shall ensure that contracts concluded with external testers require a sound management of the TLPT results and that any data proces","description": "Les entités financières veillent à ce que les contrats conclus avec des testeurs externes prévoient une gestion rigoureuse des résultats du TLPT et que tout traitement de données y afférent, y compris toute génération, stockage, agrégation, rédaction, communication ou destruction, ne crée pas de risques pour l'entité financière.","description_en": "Financial entities shall ensure that contracts concluded with external testers require a sound management of the TLPT results and that any data processing thereof, including any generation, store, aggregation, draft, report, communication or destruction, do not create risks to the financial entity."},{"ref": "DORA-28.1","theme": "Gestion du risque tiers TIC","theme_en": "ICT Third-Party Risk","mesure": "Les entités financières gèrent le risque lié aux tiers TIC en tant que composante intégrante du risque TIC au sein de leur cadre de gestion du risque","mesure_en": "Financial entities shall manage ICT third-party risk as an integral component of ICT risk within their ICT risk management framework as referred to in","description": "Les entités financières gèrent le risque lié aux tiers TIC en tant que composante intégrante du risque TIC au sein de leur cadre de gestion du risque TIC visé à l'article 6, paragraphe 1, et conformément aux principes suivants :\n(a) les entités financières qui ont conclu des arrangements contractuels pour l'utilisation de services TIC dans le cadre de leurs opérations commerciales restent à tout moment pleinement responsables du respect et de l'exécution de toutes les obligations en vertu du présent règlement et du droit applicable en matière de services financiers ;\n(b) la gestion du risque lié aux tiers TIC par les entités financières est mise en œuvre à la lumière du principe de proportionnalité, en tenant compte de :\n(b.i) la nature, l'ampleur, la complexité et l'importance des dépendances liées aux TIC,\n(b.ii) les risques découlant des arrangements contractuels relatifs à l'utilisation de services TIC conclus avec des prestataires tiers de services TIC, en tenant compte de la criticité ou de l'importance du service, du processus ou de la fonction respectif, et de l'impact potentiel sur la continuité et la qualité des services financiers.","description_en": "Financial entities shall manage ICT third-party risk as an integral component of ICT risk within their ICT risk management framework as referred to in Article 6(1), and in accordance with the following principles:\n(a) financial entities that have in place contractual arrangements for the use of ICT services to run their business operations shall, at all times, remain fully responsible for compliance with, and the discharge of, all obligations under this Regulation and applicable financial services law;\n(b) financial entities’ management of ICT third-party risk shall be implemented in light of the principle of proportionality, taking into account:\n(b.i) the nature, scale, complexity and importance of ICT-related dependencies,\n(b.ii) the risks arising from contractual arrangements on the use of ICT services concluded with ICT third-party service providers, taking into account the criticality or importance of the respective service, process or function, and the potential impact on the con"},{"ref": "DORA-28.2","theme": "Gestion du risque tiers TIC","theme_en": "ICT Third-Party Risk","mesure": "Dans le cadre de leur cadre de gestion du risque TIC, les entités financières, autres que celles visées à l'article 16(1), premier alinéa, et autres q","mesure_en": "As part of their ICT risk management framework, financial entities, other than entities referred to in Article 16(1), first subparagraph, and other th","description": "Dans le cadre de leur cadre de gestion du risque TIC, les entités financières, autres que celles visées à l'article 16, paragraphe 1, premier alinéa, et autres que les micro-entreprises, adoptent et réexaminent régulièrement une stratégie en matière de risque lié aux tiers TIC, en tenant compte de la stratégie multi-fournisseurs visée à l'article 6, paragraphe 9, le cas échéant. La stratégie en matière de risque lié aux tiers TIC comprend une politique relative à l'utilisation de services TIC soutenant des fonctions critiques ou importantes fournis par des prestataires tiers de services TIC et s'applique sur une base individuelle et, le cas échéant, sur une base sous-consolidée et consolidée. L'organe de direction, sur la base d'une évaluation du profil de risque global de l'entité financière et de l'ampleur et de la complexité des services opérationnels, réexamine régulièrement les risques identifiés à l'égard des arrangements contractuels relatifs à l'utilisation de services TIC soutenant des fonctions critiques ou importantes.","description_en": "As part of their ICT risk management framework, financial entities, other than entities referred to in Article 16(1), first subparagraph, and other than microenterprises, shall adopt, and regularly review, a strategy on ICT third-party risk, taking into account the multi-vendor strategy referred to in Article 6(9), where applicable. The strategy on ICT third-party risk shall include a policy on the use of ICT services supporting critical or important functions provided by ICT third-party service providers and shall apply on an individual basis and, where relevant, on a sub-consolidated and consolidated basis. The management body shall, on the basis of an assessment of the overall risk profile of the financial entity and the scale and complexity of the business services, regularly review the risks identified in respect to contractual arrangements on the use of ICT services supporting critical or important functions."},{"ref": "DORA-28.3","theme": "Gestion du risque tiers TIC","theme_en": "ICT Third-Party Risk","mesure": "Dans le cadre de leur cadre de gestion du risque TIC, les entités financières tiennent et mettent à jour, au niveau de l'entité et aux niveaux sous-co","mesure_en": "As part of their ICT risk management framework, financial entities shall maintain and update at entity level, and at sub-consolidated and consolidated","description": "Dans le cadre de leur cadre de gestion du risque TIC, les entités financières tiennent et mettent à jour, au niveau de l'entité et aux niveaux sous-consolidé et consolidé, un registre d'informations relatif à tous les arrangements contractuels portant sur l'utilisation de services TIC fournis par des prestataires tiers de services TIC.","description_en": "As part of their ICT risk management framework, financial entities shall maintain and update at entity level, and at sub-consolidated and consolidated levels, a register of information in relation to all contractual arrangements on the use of ICT services provided by ICT third-party service providers."},{"ref": "DORA-28.4","theme": "Gestion du risque tiers TIC","theme_en": "ICT Third-Party Risk","mesure": "Avant de conclure un arrangement contractuel relatif à l'utilisation de services TIC, les entités financières doivent :","mesure_en": "Before entering into a contractual arrangement on the use of ICT services, financial entities shall:","description": "Avant de conclure un arrangement contractuel relatif à l'utilisation de services TIC, les entités financières doivent :\n(a) évaluer si l'arrangement contractuel couvre l'utilisation de services TIC soutenant une fonction critique ou importante ;\n(b) évaluer si les conditions prudentielles de contractualisation sont remplies ;\n(c) identifier et évaluer tous les risques pertinents liés à l'arrangement contractuel, y compris la possibilité que cet arrangement contractuel contribue à renforcer le risque de concentration TIC visé à l'article 29 ;\n(d) effectuer toutes les vérifications préalables (due diligence) concernant les prestataires tiers de services TIC potentiels et s'assurer, tout au long des processus de sélection et d'évaluation, que le prestataire tiers de services TIC est approprié ;\n(e) identifier et évaluer les conflits d'intérêts que l'arrangement contractuel peut engendrer.","description_en": "Before entering into a contractual arrangement on the use of ICT services, financial entities shall:\n(a) assess whether the contractual arrangement covers the use of ICT services supporting a critical or important function;\n(b) assess if supervisory conditions for contracting are met;\n(c) identify and assess all relevant risks in relation to the contractual arrangement, including the possibility that such contractual arrangement may contribute to reinforcing ICT concentration risk as referred to in Article 29;\n(d) undertake all due diligence on prospective ICT third-party service providers and ensure throughout the selection and assessment processes that the ICT third-party service provider is suitable;\n(e) identify and assess conflicts of interest that the contractual arrangement may cause."},{"ref": "DORA-28.5","theme": "Gestion du risque tiers TIC","theme_en": "ICT Third-Party Risk","mesure": "Les entités financières ne peuvent conclure des arrangements contractuels qu'avec des prestataires tiers de services TIC respectant des normes de sécur","mesure_en": "Financial entities may only enter into contractual arrangements with ICT third-party service providers that comply with appropriate information securi","description": "Les entités financières ne peuvent conclure des arrangements contractuels qu'avec des prestataires tiers de services TIC respectant des normes de sécurité de l'information appropriées. Lorsque ces arrangements contractuels concernent des fonctions critiques ou importantes, les entités financières tiennent dûment compte, avant de conclure les arrangements, de l'utilisation par les prestataires tiers de services TIC des normes de sécurité de l'information les plus récentes et de la plus haute qualité.","description_en": "Financial entities may only enter into contractual arrangements with ICT third-party service providers that comply with appropriate information security standards. When those contractual arrangements concern critical or important functions, financial entities shall, prior to concluding the arrangements, take due consideration of the use, by ICT third- party service providers, of the most up-to-date and highest quality information security standards."},{"ref": "DORA-28.6","theme": "Gestion du risque tiers TIC","theme_en": "ICT Third-Party Risk","mesure": "Dans l'exercice des droits d'accès, d'inspection et d'audit sur le prestataire tiers de services TIC, les entités financières prédéterminent, sur la b","mesure_en": "In exercising access, inspection and audit rights over the ICT third-party service provider, financial entities shall, on the basis of a risk-based ap","description": "Dans l'exercice des droits d'accès, d'inspection et d'audit sur le prestataire tiers de services TIC, les entités financières prédéterminent, sur la base d'une approche fondée sur les risques, la fréquence des audits et des inspections ainsi que les domaines à auditer, en se conformant aux normes d'audit communément acceptées, conformément aux éventuelles instructions prudentielles relatives à l'utilisation et à l'intégration de ces normes d'audit.","description_en": "In exercising access, inspection and audit rights over the ICT third-party service provider, financial entities shall, on the basis of a risk-based approach, pre-determine the frequency of audits and inspections as well as the areas to be audited through adhering to commonly accepted audit standards in line with any supervisory instruction on the use and incorporation of such audit standards."},{"ref": "DORA-28.7","theme": "Gestion du risque tiers TIC","theme_en": "ICT Third-Party Risk","mesure": "Les entités financières veillent à ce que les arrangements contractuels relatifs à l'utilisation de services TIC puissent être résiliés dans l'une des","mesure_en": "Financial entities shall ensure that contractual arrangements on the use of ICT services may be terminated in any of the following circumstances:","description": "Les entités financières veillent à ce que les arrangements contractuels relatifs à l'utilisation de services TIC puissent être résiliés dans l'une des circonstances suivantes :\n(a) violation significative par le prestataire tiers de services TIC des lois, réglementations ou clauses contractuelles applicables ;\n(b) circonstances identifiées dans le cadre du suivi du risque lié aux tiers TIC jugées susceptibles d'altérer l'exécution des fonctions fournies au titre de l'arrangement contractuel, y compris les modifications substantielles affectant l'arrangement ou la situation du prestataire tiers de services TIC ;\n(c) faiblesses avérées du prestataire tiers de services TIC en matière de gestion globale du risque TIC et notamment dans la manière dont il assure la disponibilité, l'authenticité, l'intégrité et la confidentialité des données, qu'elles soient à caractère personnel ou sensible, ou non personnelles ;\n(d) lorsque l'autorité compétente ne peut plus exercer efficacement sa surveillance sur l'entité financière en raison des conditions ou circonstances liées à l'arrangement contractuel.","description_en": "Financial entities shall ensure that contractual arrangements on the use of ICT services may be terminated in any of the following circumstances:\n(a) significant breach by the ICT third-party service provider of applicable laws, regulations or contractual terms;\n(b) circumstances identified throughout the monitoring of ICT third-party risk that are deemed capable of altering the performance of the functions provided through the contractual arrangement, including material changes that affect the arrangement or the situation of the ICT third-party service provider;\n(c) ICT third-party service provider’s evidenced weaknesses pertaining to its overall ICT risk management and in particular in the way it ensures the availability, authenticity, integrity and, confidentiality, of data, whether personal or otherwise sensitive data, or non-personal data;\n(d) where the competent authority can no longer effectively supervise the financial entity as a result of the conditions of, or circumstances r"},{"ref": "DORA-28.8","theme": "Gestion du risque tiers TIC","theme_en": "ICT Third-Party Risk","mesure": "Pour les services TIC soutenant des fonctions critiques ou importantes, les entités financières mettent en place des stratégies de sortie. Les stratégi","mesure_en": "For ICT services supporting critical or important functions, financial entities shall put in place exit strategies. The exit strategies shall take int","description": "Pour les services TIC soutenant des fonctions critiques ou importantes, les entités financières mettent en place des stratégies de sortie. Les stratégies de sortie tiennent compte des risques pouvant survenir au niveau des prestataires tiers de services TIC, notamment une défaillance éventuelle de leur part, une détérioration de la qualité des services TIC fournis, toute perturbation des activités due à une fourniture inappropriée ou défaillante de services TIC ou tout risque significatif lié au déploiement approprié et continu du service TIC concerné, ou la résiliation des arrangements contractuels avec les prestataires tiers de services TIC dans l'une des circonstances visées au paragraphe 7.\n(a) perturbation de leurs activités commerciales,\n(b) limitation de la conformité aux exigences réglementaires,\n(c) préjudice à la continuité et à la qualité des services fournis aux clients.","description_en": "For ICT services supporting critical or important functions, financial entities shall put in place exit strategies. The exit strategies shall take into account risks that may emerge at the level of ICT third-party service providers, in particular a possible failure on their part, a deterioration of the quality of the ICT services provided, any business disruption due to inappropriate or failed provision of ICT services or any material risk arising in relation to the appropriate and continuous deployment of the respective ICT service, or the termination of contractual arrangements with ICT third-party service providers under any of the circumstances listed in paragraph 7.\n(a) disruption to their business activities,\n(b) limiting compliance with regulatory requirements,\n(c) detriment to the continuity and quality of services provided to clients."},{"ref": "DORA-28.9","theme": "Gestion du risque tiers TIC","theme_en": "ICT Third-Party Risk","mesure": "Les AES, par l'intermédiaire du comité conjoint, élaborent des projets de normes techniques d'exécution pour établir les modèles standard aux fins du","mesure_en": "The ESAs shall, through the Joint Committee, develop draft implementing technical standards to establish the standard templates for the purposes of th","description": "Les AES, par l'intermédiaire du comité conjoint, élaborent des projets de normes techniques d'exécution pour établir les modèles standard aux fins du registre d'informations visé au paragraphe 3, y compris les informations communes à tous les arrangements contractuels relatifs à l'utilisation de services TIC. Les AES soumettent ces projets de normes techniques d'exécution à la Commission au plus tard le 17 janvier 2024.\nLa Commission est habilitée à adopter les normes techniques d'exécution visées au premier alinéa conformément à l'article 15 des règlements (UE) nº 1093/2010, (UE) nº 1094/2010 et (UE) nº 1095/2010.","description_en": "The ESAs shall, through the Joint Committee, develop draft implementing technical standards to establish the standard templates for the purposes of the register of information referred to in paragraph 3, including information that is common to all contractual arrangements on the use of ICT services. The ESAs shall submit those draft implementing technical standards to the Commission by 17 January 2024.\nPower is conferred on the Commission to adopt the implementing technical standards referred to in the first subparagraph in accordance with Article 15 of Regulations (EU) No 1093/2010, (EU) No 1094/2010 and (EU) No 1095/2010."},{"ref": "DORA-28.10","theme": "Gestion du risque tiers TIC","theme_en": "ICT Third-Party Risk","mesure": "Les AES, par l'intermédiaire du comité conjoint, élaborent des projets de normes techniques de réglementation pour préciser davantage le contenu détai","mesure_en": "The ESAs shall, through the Joint Committee, develop draft regulatory technical standards to further specify the detailed content of the policy referr","description": "Les AES, par l'intermédiaire du comité conjoint, élaborent des projets de normes techniques de réglementation pour préciser davantage le contenu détaillé de la politique visée au paragraphe 2 en ce qui concerne les arrangements contractuels relatifs à l'utilisation de services TIC soutenant des fonctions critiques ou importantes fournis par des prestataires tiers de services TIC.\nLors de l'élaboration de ces projets de normes techniques de réglementation, les AES tiennent compte de la taille et du profil de risque global de l'entité financière, ainsi que de la nature, de l'ampleur et de la complexité de ses services, activités et opérations. Les AES soumettent ces projets de normes techniques de réglementation à la Commission au plus tard le 17 janvier 2024.\nLa Commission est habilitée à compléter le présent règlement en adoptant les normes techniques de réglementation visées au premier alinéa conformément aux articles 10 à 14 des règlements (UE) nº 1093/2010, (UE) nº 1094/2010 et (UE) nº 1095/2010.","description_en": "The ESAs shall, through the Joint Committee, develop draft regulatory technical standards to further specify the detailed content of the policy referred to in paragraph 2 in relation to the contractual arrangements on the use of ICT services supporting critical or important functions provided by ICT third-party service providers.\nWhen developing those draft regulatory technical standards, the ESAs shall take into account the size and the overall risk profile of the financial entity, and the nature, scale and complexity of its services, activities and operations. The ESAs shall submit those draft regulatory technical standards to the Commission by 17 January 2024.\nPower is delegated to the Commission to supplement this Regulation by adopting the regulatory technical standards referred to in the first subparagraph in accordance with Articles 10 to 14 of Regulations (EU) No 1093/2010, (EU) No 1094/2010 and (EU) No 1095/2010."},{"ref": "DORA-29.1","theme": "Évaluation du risque de concentration","theme_en": "Concentration Risk Assessment","mesure": "Lors de l'identification et de l'évaluation des risques visés à l'article 28(4), point c), les entités financières tiennent également compte de la que","mesure_en": "When performing the identification and assessment of risks referred to in Article 28(4), point (c), financial entities shall also take into account wh","description": "Lors de l'identification et de l'évaluation des risques visés à l'article 28, paragraphe 4, point c), les entités financières tiennent également compte du fait que la conclusion envisagée d'un arrangement contractuel relatif à des services TIC soutenant des fonctions critiques ou importantes pourrait conduire à l'une des situations suivantes :\n(a) contracter avec un prestataire tiers de services TIC difficilement substituable ; ou\n(b) avoir en place de multiples arrangements contractuels relatifs à la fourniture de services TIC soutenant des fonctions critiques ou importantes avec le même prestataire tiers de services TIC ou avec des prestataires tiers de services TIC étroitement liés.","description_en": "When performing the identification and assessment of risks referred to in Article 28(4), point (c), financial entities shall also take into account whether the envisaged conclusion of a contractual arrangement in relation to ICT services supporting critical or important functions would lead to any of the following:\n(a) contracting an ICT third-party service provider that is not easily substitutable; or\n(b) having in place multiple contractual arrangements in relation to the provision of ICT services supporting critical or important functions with the same ICT third-party service provider or with closely connected ICT third-party service providers."},{"ref": "DORA-29.2","theme": "Évaluation du risque de concentration","theme_en": "Concentration Risk Assessment","mesure": "Lorsque les arrangements contractuels relatifs à l'utilisation de services TIC soutenant des fonctions critiques ou importantes prévoient la possibilit","mesure_en": "Where the contractual arrangements on the use of ICT services supporting critical or important functions include the possibility that an ICT third-par","description": "Lorsque les arrangements contractuels relatifs à l'utilisation de services TIC soutenant des fonctions critiques ou importantes prévoient la possibilité qu'un prestataire tiers de services TIC sous-traite à d'autres prestataires tiers de services TIC des services TIC soutenant une fonction critique ou importante, les entités financières évaluent les avantages et les risques pouvant découler de cette sous-traitance, en particulier dans le cas d'un sous-traitant TIC établi dans un pays tiers.","description_en": "Where the contractual arrangements on the use of ICT services supporting critical or important functions include the possibility that an ICT third-party service provider further subcontracts ICT services supporting a critical or important function to other ICT third-party service providers, financial entities shall weigh benefits and risks that may arise in connection with such subcontracting, in particular in the case of an ICT subcontractor established in a third-country."},{"ref": "DORA-30.1","theme": "Clauses contractuelles","theme_en": "Contractual Clauses","mesure": "Les droits et obligations de l'entité financière et du prestataire tiers de services TIC sont clairement répartis et consignés par écrit. Le contrat c","mesure_en": "The rights and obligations of the financial entity and of the ICT third-party service provider shall be clearly allocated and set out in writing. The ","description": "Les droits et obligations de l'entité financière et du prestataire tiers de services TIC sont clairement répartis et consignés par écrit. Le contrat complet comprend les accords de niveau de service et est documenté dans un document écrit unique disponible pour les parties sur papier ou dans un document sous un autre format téléchargeable, durable et accessible.","description_en": "The rights and obligations of the financial entity and of the ICT third-party service provider shall be clearly allocated and set out in writing. The full contract shall include the service level agreements and be documented in one written document which shall be available to the parties on paper, or in a document with another downloadable, durable and accessible format."},{"ref": "DORA-30.2","theme": "Clauses contractuelles","theme_en": "Contractual Clauses","mesure": "Les arrangements contractuels relatifs à l'utilisation de services TIC comprennent au minimum les éléments suivants :","mesure_en": "The contractual arrangements on the use of ICT services shall include at least the following elements:","description": "Les arrangements contractuels relatifs à l'utilisation de services TIC comprennent au minimum les éléments suivants :\n(a) une description claire et complète de toutes les fonctions et services TIC à fournir par le prestataire tiers de services TIC, indiquant si la sous-traitance d'un service TIC soutenant une fonction critique ou importante, ou de parties substantielles de celui-ci, est autorisée et, le cas échéant, les conditions applicables à cette sous-traitance ;\n(b) les lieux, à savoir les régions ou pays, où les fonctions et services TIC contractés ou sous-traités doivent être fournis et où les données doivent être traitées, y compris le lieu de stockage, et l'obligation pour le prestataire tiers de services TIC de notifier préalablement l'entité financière s'il envisage de modifier ces lieux ;\n(c) les dispositions relatives à la disponibilité, l'authenticité, l'intégrité et la confidentialité en matière de protection des données, y compris les données à caractère personnel ;\n(d) les dispositions garantissant l'accès, la récupération et la restitution dans un format facilement accessible.","description_en": "The contractual arrangements on the use of ICT services shall include at least the following elements:\n(a) a clear and complete description of all functions and ICT services to be provided by the ICT third-party service provider, indicating whether subcontracting of an ICT service supporting a critical or important function, or material parts thereof, is permitted and, when that is the case, the conditions applying to such subcontracting;\n(b) the locations, namely the regions or countries, where the contracted or subcontracted functions and ICT services are to be provided and where data is to be processed, including the storage location, and the requirement for the ICT third- party service provider to notify the financial entity in advance if it envisages changing such locations;\n(c) provisions on availability, authenticity, integrity and confidentiality in relation to the protection of data, including personal data;\n(d) provisions on ensuring access, recovery and return in an easily a"},{"ref": "DORA-30.3","theme": "Clauses contractuelles","theme_en": "Contractual Clauses","mesure": "Les arrangements contractuels relatifs à l'utilisation de services TIC soutenant des fonctions critiques ou importantes comprennent, outre les éléments","mesure_en": "The contractual arrangements on the use of ICT services supporting critical or important functions shall include, in addition to the elements referred","description": "Les arrangements contractuels relatifs à l'utilisation de services TIC soutenant des fonctions critiques ou importantes comprennent, outre les éléments visés au paragraphe 2, au minimum les éléments suivants :\n(a) des descriptions complètes des niveaux de service, y compris leurs mises à jour et révisions, avec des objectifs de performance quantitatifs et qualitatifs précis dans le cadre des niveaux de service convenus, permettant un suivi efficace par l'entité financière des services TIC et la prise de mesures correctives appropriées sans retard injustifié lorsque les niveaux de service convenus ne sont pas atteints ;\n(b) les délais de préavis et les obligations de notification du prestataire tiers de services TIC à l'entité financière, y compris la notification de tout développement susceptible d'avoir un impact significatif sur la capacité du prestataire tiers de services TIC à fournir efficacement les services TIC soutenant des fonctions critiques ou importantes conformément aux niveaux de service convenus ;\n(c) les exigences imposées au prestataire tiers de services TIC de mettre en œuvre et de tester des plans de continuité des activités.","description_en": "The contractual arrangements on the use of ICT services supporting critical or important functions shall include, in addition to the elements referred to in paragraph 2, at least the following:\n(a) full service level descriptions, including updates and revisions thereof with precise quantitative and qualitative performance targets within the agreed service levels to allow effective monitoring by the financial entity of ICT services and enable appropriate corrective actions to be taken, without undue delay, when agreed service levels are not met;\n(b) notice periods and reporting obligations of the ICT third-party service provider to the financial entity, including notification of any development that might have a material impact on the ICT third-party service provider’s ability to effectively provide the ICT services supporting critical or important functions in line with agreed service levels;\n(c) requirements for the ICT third-party service provider to implement and test business cont"},{"ref": "DORA-30.4","theme": "Clauses contractuelles","theme_en": "Contractual Clauses","mesure": "Lors de la négociation d'arrangements contractuels, les entités financières et les prestataires tiers de services TIC envisagent l'utilisation de claus","mesure_en": "When negotiating contractual arrangements, financial entities and ICT third-party service providers shall consider the use of standard contractual cla","description": "Lors de la négociation d'arrangements contractuels, les entités financières et les prestataires tiers de services TIC envisagent l'utilisation de clauses contractuelles types élaborées par les autorités publiques pour des services spécifiques.","description_en": "When negotiating contractual arrangements, financial entities and ICT third-party service providers shall consider the use of standard contractual clauses developed by public authorities for specific services."},{"ref": "DORA-30.5","theme": "Clauses contractuelles","theme_en": "Contractual Clauses","mesure": "Les AES, par l'intermédiaire du comité conjoint, élaborent des projets de normes techniques de réglementation pour préciser davantage les éléments visé","mesure_en": "The ESAs shall, through the Joint Committee, develop draft regulatory technical standards to specify further the elements referred to in paragraph 2, ","description": "Les AES, par l'intermédiaire du comité conjoint, élaborent des projets de normes techniques de réglementation pour préciser davantage les éléments visés au paragraphe 2, point a), qu'une entité financière doit déterminer et évaluer lors de la sous-traitance de services TIC soutenant des fonctions critiques ou importantes.\nLors de l'élaboration de ces projets de normes techniques de réglementation, les AES prennent en considération la taille et le profil de risque global de l'entité financière, ainsi que la nature, l'ampleur et la complexité de ses services, activités et opérations.\nLes AES soumettent ces projets de normes techniques de réglementation à la Commission au plus tard le 17 juillet 2024.\nLa Commission est habilitée à compléter le présent règlement en adoptant les normes techniques de réglementation visées au premier alinéa conformément aux articles 10 à 14 des règlements (UE) nº 1093/2010, (UE) nº 1094/2010 et (UE) nº 1095/2010.","description_en": "The ESAs shall, through the Joint Committee, develop draft regulatory technical standards to specify further the elements referred to in paragraph 2, point (a), which a financial entity needs to determine and assess when subcontracting ICT services supporting critical or important functions.\nWhen developing those draft regulatory technical standards, the ESAs shall take into consideration the size and overall risk profile of the financial entity, and the nature, scale and complexity of its services, activities and operations.\nThe ESAs shall submit those draft regulatory technical standards to the Commission by 17 July 2024.\nPower is delegated to the Commission to supplement this Regulation by adopting the regulatory technical standards referred to in the first subparagraph in accordance with Articles 10 to 14 of Regulations (EU) No 1093/2010, (EU) No 1094/2010 and (EU) No 1095/2010."},{"ref": "DORA-31.1","theme": "Désignation prestataires critiques","theme_en": "Critical Provider Designation","mesure": "Les AES, par l'intermédiaire du comité conjoint et sur recommandation du forum de surveillance établi conformément à l'article 32(1), doivent :","mesure_en": "The ESAs, through the Joint Committee and upon recommendation from the Oversight Forum established pursuant to Article 32(1), shall:","description": "Les AES, par l'intermédiaire du comité conjoint et sur recommandation du forum de surveillance établi conformément à l'article 32, paragraphe 1, doivent :\n(a) désigner les prestataires tiers de services TIC qui sont critiques pour les entités financières, à la suite d'une évaluation tenant compte des critères précisés au paragraphe 2 ;\n(b) nommer comme chef de file de la surveillance pour chaque prestataire tiers critique de services TIC l'AES qui est responsable, conformément aux règlements (UE) nº 1093/2010, (UE) nº 1094/2010 ou (UE) nº 1095/2010, des entités financières détenant ensemble la plus grande part du total des actifs sur la valeur totale des actifs de toutes les entités financières utilisant les services du prestataire tiers critique de services TIC concerné.","description_en": "The ESAs, through the Joint Committee and upon recommendation from the Oversight Forum established pursuant to Article 32(1), shall:\n(a)\tdesignate the ICT third-party service providers that are critical for financial entities, following an assessment that takes into account the criteria specified in paragraph 2;\n(b)\tappoint as Lead Overseer for each critical ICT third-party service provider the ESA that is responsible, in accordance with Regulations (EU) No 1093/2010, (EU) No 1094/2010 or (EU) No 1095/2010, for the financial entities having together the largest share of total assets out of the value of total assets of all financial entities using the services of the relevant critical ICT third-party service provider, as evidenced by the sum of the individual balance sheets of those financial entities."},{"ref": "DORA-31.2","theme": "Désignation prestataires critiques","theme_en": "Critical Provider Designation","mesure": "La désignation visée au paragraphe 1, point a), est fondée sur l'ensemble des critères suivants relatifs aux services TIC fournis par le prestataire t","mesure_en": "The designation referred to in paragraph 1, point (a), shall be based on all of the following criteria in relation to ICT services provided by the ICT","description": "La désignation visée au paragraphe 1, point a), est fondée sur l'ensemble des critères suivants relatifs aux services TIC fournis par le prestataire tiers de services TIC :\n(a) l'impact systémique sur la stabilité, la continuité ou la qualité de la fourniture de services financiers dans l'hypothèse où le prestataire tiers de services TIC concerné ferait face à une défaillance opérationnelle de grande ampleur, compte tenu du nombre d'entités financières et de la valeur totale des actifs des entités financières auxquelles le prestataire tiers de services TIC concerné fournit des services ;\n(b) le caractère ou l'importance systémique des entités financières qui dépendent du prestataire tiers de services TIC concerné, évalué selon les paramètres suivants :\n(i) le nombre d'établissements d'importance systémique mondiale (EISm) ou d'autres établissements d'importance systémique (autres EIS) qui dépendent du prestataire tiers de services TIC concerné ;\n(ii) l'interdépendance entre ces entités.","description_en": "The designation referred to in paragraph 1, point (a), shall be based on all of the following criteria in relation to ICT services provided by the ICT third-party service provider:\n(a)\tthe systemic impact on the stability, continuity or quality of the provision of financial services in the event that the relevant ICT third-party service provider would face a large scale operational failure to provide its services, taking into account the number of financial entities and the total value of assets of financial entities to which the relevant ICT third-party service provider provides services;\n(b)\tthe systemic character or importance of the financial entities that rely on the relevant ICT third-party service provider, assessed in accordance with the following parameters:\n(i)\tthe number of global systemically important institutions (G-SIIs) or other systemically important institutions (O-SIIs) that rely on the respective ICT third-party service provider;\n(ii)\tthe interdependence between the"},{"ref": "DORA-31.3","theme": "Désignation prestataires critiques","theme_en": "Critical Provider Designation","mesure": "Lorsque le prestataire tiers de services TIC appartient à un groupe, les critères visés au paragraphe 2 sont examinés au regard des services TIC fourn","mesure_en": "Where the ICT third-party service provider belongs to a group, the criteria referred to in paragraph 2 shall be considered in relation to the ICT serv","description": "Lorsque le prestataire tiers de services TIC appartient à un groupe, les critères visés au paragraphe 2 sont examinés au regard des services TIC fournis par le groupe dans son ensemble.","description_en": "Where the ICT third-party service provider belongs to a group, the criteria referred to in paragraph 2 shall be considered in relation to the ICT services provided by the group as a whole."},{"ref": "DORA-31.4","theme": "Désignation prestataires critiques","theme_en": "Critical Provider Designation","mesure": "Les prestataires tiers critiques de services TIC faisant partie d'un groupe désignent une personne morale comme point de coordination afin d'assurer un","mesure_en": "Critical ICT third-party service providers which are part of a group shall designate one legal person as a coordination point to ensure adequate repre","description": "Les prestataires tiers critiques de services TIC faisant partie d'un groupe désignent une personne morale comme point de coordination afin d'assurer une représentation et une communication adéquates avec le chef de file de la surveillance.","description_en": "Critical ICT third-party service providers which are part of a group shall designate one legal person as a coordination point to ensure adequate representation and communication with the Lead Overseer."},{"ref": "DORA-31.5","theme": "Désignation prestataires critiques","theme_en": "Critical Provider Designation","mesure": "Le chef de file de la surveillance notifie au prestataire tiers de services TIC le résultat de l'évaluation ayant conduit à la désignation visée au par","mesure_en": "The Lead Overseer shall notify the ICT third-party service provider of the outcome of the assessment leading to the designation referred in paragraph ","description": "Le chef de file de la surveillance notifie au prestataire tiers de services TIC le résultat de l'évaluation ayant conduit à la désignation visée au paragraphe 1, point a). Dans les 6 semaines suivant la date de la notification, le prestataire tiers de services TIC peut soumettre au chef de file de la surveillance une déclaration motivée contenant toute information pertinente aux fins de l'évaluation. Le chef de file de la surveillance examine la déclaration motivée et peut demander des informations supplémentaires dans les 30 jours calendaires suivant la réception de cette déclaration.\nAprès avoir désigné un prestataire tiers de services TIC comme critique, les AES, par l'intermédiaire du comité conjoint, notifient au prestataire tiers de services TIC cette désignation et la date de début à partir de laquelle il sera effectivement soumis aux activités de surveillance. Cette date de début n'est pas postérieure d'un mois à la notification.","description_en": "The Lead Overseer shall notify the ICT third-party service provider of the outcome of the assessment leading to the designation referred in paragraph 1, point (a). Within 6 weeks from the date of the notification, the ICT third-party service provider may submit to the Lead Overseer a reasoned statement with any relevant information for the purposes of the assessment. The Lead Overseer shall consider the reasoned statement and may request additional information to be submitted within 30 calendar days of the receipt of such statement.\nAfter designating an ICT third-party service provider as critical, the ESAs, through the Joint Committee, shall notify the ICT third-party service provider of such designation and the starting date as from which they will effectively be subject to oversight activities. That starting date shall be no later than one month after the notification. The ICT third-party service provider shall notify the financial entities to which they provide services of their de"},{"ref": "DORA-31.6","theme": "Désignation prestataires critiques","theme_en": "Critical Provider Designation","mesure": "La Commission est habilitée à adopter un acte délégué conformément à l'article 57 afin de compléter le présent règlement en précisant davantage les cr","mesure_en": "The Commission is empowered to adopt a delegated act in accordance with Article 57 to supplement this Regulation by specifying further the criteria re","description": "La Commission est habilitée à adopter un acte délégué conformément à l'article 57 afin de compléter le présent règlement en précisant davantage les critères visés au paragraphe 2 du présent article, d'ici le 17 juillet 2024.","description_en": "The Commission is empowered to adopt a delegated act in accordance with Article 57 to supplement this Regulation by specifying further the criteria referred to in paragraph 2 of this Article, by 17 July 2024."},{"ref": "DORA-31.7","theme": "Désignation prestataires critiques","theme_en": "Critical Provider Designation","mesure": "La désignation visée au paragraphe 1, point a), n'est pas utilisée tant que la Commission n'a pas adopté un acte délégué conformément au paragraphe 6","mesure_en": "The designation referred to in paragraph 1, point (a), shall not be used until the Commission has adopted a delegated act in accordance with paragraph","description": "La désignation visée au paragraphe 1, point a), n'est pas utilisée tant que la Commission n'a pas adopté un acte délégué conformément au paragraphe 6.","description_en": "The designation referred to in paragraph 1, point (a), shall not be used until the Commission has adopted a delegated act in accordance with paragraph 6."},{"ref": "DORA-31.8","theme": "Désignation prestataires critiques","theme_en": "Critical Provider Designation","mesure": "La désignation visée au paragraphe 1, point a), ne s'applique pas aux entités suivantes :","mesure_en": "The designation referred to in paragraph 1, point (a), shall not apply to the following:","description": "La désignation visée au paragraphe 1, point a), ne s'applique pas aux entités suivantes :\n(i) les entités financières fournissant des services TIC à d'autres entités financières ;\n(ii) les prestataires tiers de services TIC soumis à des cadres de surveillance établis aux fins des missions visées à l'article 127, paragraphe 2, du traité sur le fonctionnement de l'Union européenne ;\n(iii) les prestataires de services TIC intragroupe ;\n(iv) les prestataires tiers de services TIC fournissant des services TIC uniquement dans un État membre à des entités financières actives uniquement dans cet État membre.","description_en": "The designation referred to in paragraph 1, point (a), shall not apply to the following:\n(i)\tfinancial entities providing ICT services to other financial entities;\n(ii)\tICT third-party service providers that are subject to oversight frameworks established for the purposes of supporting the tasks referred to in Article 127(2) of the Treaty on the Functioning of the European Union;\n(iii)\tICT intra-group service providers;\n(iv)\tICT third-party service providers providing ICT services solely in one Member State to financial entities that are only active in that Member State."},{"ref": "DORA-31.9","theme": "Désignation prestataires critiques","theme_en": "Critical Provider Designation","mesure": "Les AES, par l'intermédiaire du comité conjoint, établissent, publient et mettent à jour chaque année la liste des prestataires tiers critiques de ser","mesure_en": "The ESAs, through the Joint Committee, shall establish, publish and update yearly the list of critical ICT third-party service providers at Union leve","description": "Les AES, par l'intermédiaire du comité conjoint, établissent, publient et mettent à jour chaque année la liste des prestataires tiers critiques de services TIC au niveau de l'Union.","description_en": "The ESAs, through the Joint Committee, shall establish, publish and update yearly the list of critical ICT third-party service providers at Union level."},{"ref": "DORA-31.10","theme": "Désignation prestataires critiques","theme_en": "Critical Provider Designation","mesure": "Aux fins du paragraphe 1, point a), les autorités compétentes transmettent, sur une base annuelle et agrégée, les rapports visés à l'article 28(3), tr","mesure_en": "For the purposes of paragraph 1, point (a), competent authorities shall, on a yearly and aggregated basis, transmit the reports referred to in Article","description": "Aux fins du paragraphe 1, point a), les autorités compétentes transmettent, sur une base annuelle et agrégée, les rapports visés à l'article 28, paragraphe 3, troisième alinéa, au forum de surveillance établi conformément à l'article 32. Le forum de surveillance évalue les dépendances TIC des entités financières vis-à-vis de prestataires tiers sur la base des informations reçues des autorités compétentes.","description_en": "For the purposes of paragraph 1, point (a), competent authorities shall, on a yearly and aggregated basis, transmit the reports referred to in Article 28(3), third subparagraph, to the Oversight Forum established pursuant to Article 32. The Oversight Forum shall assess the ICT third-party dependencies of financial entities based on the information received from the competent authorities."},{"ref": "DORA-31.11","theme": "Désignation prestataires critiques","theme_en": "Critical Provider Designation","mesure": "Les prestataires tiers de services TIC qui ne figurent pas sur la liste visée au paragraphe 9 peuvent demander à être désignés comme critiques conform","mesure_en": "The ICT third-party service providers that are not included in the list referred to in paragraph 9 may request to be designated as critical in accorda","description": "Les prestataires tiers de services TIC qui ne figurent pas sur la liste visée au paragraphe 9 peuvent demander à être désignés comme critiques conformément au paragraphe 1, point a).\nAux fins du premier alinéa, le prestataire tiers de services TIC soumet une demande motivée à l'ABE, à l'AEMF ou à l'AEAPP, qui, par l'intermédiaire du comité conjoint, décide de désigner ou non ce prestataire tiers de services TIC comme critique conformément au paragraphe 1, point a).\nLa décision visée au deuxième alinéa est adoptée et notifiée au prestataire tiers de services TIC dans les 6 mois suivant la réception de la demande.","description_en": "The ICT third-party service providers that are not included in the list referred to in paragraph 9 may request to be designated as critical in accordance with paragraph 1, point (a).\nFor the purpose of the first subparagraph, the ICT third-party service provider shall submit a reasoned application to EBA, ESMA or EIOPA, which, through the Joint Committee, shall decide whether to designate that ICT third-party service provider as critical in accordance with paragraph 1, point (a).\nThe decision referred to in the second subparagraph shall be adopted and notified to the ICT third-party service provider within 6 months of receipt of the application."},{"ref": "DORA-31.12","theme": "Désignation prestataires critiques","theme_en": "Critical Provider Designation","mesure": "Les entités financières n'utilisent les services d'un prestataire tiers de services TIC établi dans un pays tiers et désigné comme critique conforméme","mesure_en": "Financial entities shall only make use of the services of an ICT third-party service provider established in a third country and which has been design","description": "Les entités financières n'utilisent les services d'un prestataire tiers de services TIC établi dans un pays tiers et désigné comme critique conformément au paragraphe 1, point a), que si ce dernier a établi une filiale dans l'Union dans les 12 mois suivant la désignation.","description_en": "Financial entities shall only make use of the services of an ICT third-party service provider established in a third country and which has been designated as critical in accordance with paragraph 1, point (a), if the latter has established a subsidiary in the Union within the 12 months following the designation."},{"ref": "DORA-31.13","theme": "Désignation prestataires critiques","theme_en": "Critical Provider Designation","mesure": "Le prestataire tiers critique de services TIC visé au paragraphe 12 notifie au chef de file de la surveillance toute modification de la structure de di","mesure_en": "The critical ICT third-party service provider referred to in paragraph 12 shall notify the Lead Overseer of any changes to the structure of the manage","description": "Le prestataire tiers critique de services TIC visé au paragraphe 12 notifie au chef de file de la surveillance toute modification de la structure de direction de la filiale établie dans l'Union.","description_en": "The critical ICT third-party service provider referred to in paragraph 12 shall notify the Lead Overseer of any changes to the structure of the management of the subsidiary established in the Union."},{"ref": "DORA-32.1","theme": "Cadre de surveillance","theme_en": "Oversight Framework","mesure": "Le comité conjoint, conformément à l'article 57(1) des règlements (UE) nº 1093/2010, (UE) nº 1094/2010 et (UE) nº 1095/2010, établit le forum de surv","mesure_en": "The Joint Committee, in accordance with Article 57(1) of Regulations (EU) No 1093/2010, (EU) No 1094/2010 and (EU) No 1095/2010, shall establish the O","description": "Le comité conjoint, conformément à l'article 57, paragraphe 1, des règlements (UE) nº 1093/2010, (UE) nº 1094/2010 et (UE) nº 1095/2010, établit le forum de surveillance en tant que sous-comité aux fins de soutenir les travaux du comité conjoint et du chef de file de la surveillance visé à l'article 31, paragraphe 1, point b), dans le domaine du risque lié aux tiers TIC dans les secteurs financiers. Le forum de surveillance prépare les projets de positions conjointes et les projets d'actes communs du comité conjoint dans ce domaine.\nLe forum de surveillance examine régulièrement les évolutions pertinentes en matière de risque et de vulnérabilités TIC et promeut une approche cohérente du suivi du risque lié aux tiers TIC au niveau de l'Union.","description_en": "The Joint Committee, in accordance with Article 57(1) of Regulations (EU) No 1093/2010, (EU) No 1094/2010 and (EU) No 1095/2010, shall establish the Oversight Forum as a sub-committee for the purposes of supporting the work of the Joint Committee and of the Lead Overseer referred to in Article 31(1), point (b), in the area of ICT third-party risk across financial sectors. The Oversight Forum shall prepare the draft joint positions and the draft common acts of the Joint Committee in that area.\nThe Oversight Forum shall regularly discuss relevant developments on ICT risk and vulnerabilities and promote a consistent approach in the monitoring of ICT third-party risk at Union level."},{"ref": "DORA-32.2","theme": "Cadre de surveillance","theme_en": "Oversight Framework","mesure": "Le forum de surveillance procède chaque année à une évaluation collective des résultats et constatations des activités de surveillance menées pour tous","mesure_en": "The Oversight Forum shall, on a yearly basis, undertake a collective assessment of the results and findings of the oversight activities conducted for ","description": "Le forum de surveillance procède chaque année à une évaluation collective des résultats et constatations des activités de surveillance menées pour tous les prestataires tiers critiques de services TIC et promeut des mesures de coordination visant à renforcer la résilience opérationnelle numérique des entités financières, à favoriser les bonnes pratiques en matière de gestion du risque de concentration TIC et à explorer des mesures d'atténuation pour les transferts de risques intersectoriels.","description_en": "The Oversight Forum shall, on a yearly basis, undertake a collective assessment of the results and findings of the oversight activities conducted for all critical ICT third-party service providers and promote coordination measures to increase the digital operational resilience of financial entities, foster best practices on addressing ICT concentration risk and explore mitigants for cross-sector risk transfers."},{"ref": "DORA-32.3","theme": "Cadre de surveillance","theme_en": "Oversight Framework","mesure": "Le forum de surveillance soumet des référentiels complets pour les prestataires tiers critiques de services TIC, à adopter par le comité conjoint en ta","mesure_en": "The Oversight Forum shall submit comprehensive benchmarks for critical ICT third-party service providers to be adopted by the Joint Committee as joint","description": "Le forum de surveillance soumet des référentiels complets pour les prestataires tiers critiques de services TIC, à adopter par le comité conjoint en tant que positions conjointes des AES conformément à l'article 56, paragraphe 1, des règlements (UE) nº 1093/2010, (UE) nº 1094/2010 et (UE) nº 1095/2010.","description_en": "The Oversight Forum shall submit comprehensive benchmarks for critical ICT third-party service providers to be adopted by the Joint Committee as joint positions of the ESAs in accordance with Article 56(1) of Regulations (EU) No 1093/2010, (EU) No 1094/2010 and (EU) No 1095/2010."},{"ref": "DORA-32.4","theme": "Cadre de surveillance","theme_en": "Oversight Framework","mesure": "Le forum de surveillance est composé de :","mesure_en": "The Oversight Forum shall be composed of:","description": "Le forum de surveillance est composé de :\n(a) les présidents des AES ;\n(b) un représentant de haut niveau du personnel actuel de l'autorité compétente concernée visée à l'article 46 de chaque État membre ;\n(c) les directeurs exécutifs de chaque AES et un représentant de la Commission, du CERS, de la BCE et de l'ENISA en tant qu'observateurs ;\n(d) le cas échéant, un représentant supplémentaire d'une autorité compétente visée à l'article 46 de chaque État membre en tant qu'observateur ;\n(e) le cas échéant, un représentant des autorités compétentes désignées ou établies conformément à la directive (UE) 2022/2555 chargées de la surveillance d'une entité essentielle ou importante soumise à cette directive, désignée comme prestataire tiers critique de services TIC, en tant qu'observateur.\nLe forum de surveillance peut, le cas échéant, solliciter l'avis d'experts indépendants désignés conformément au paragraphe 6.","description_en": "The Oversight Forum shall be composed of:\n(a)\tthe Chairpersons of the ESAs;\n(b)\tone high-level representative from the current staff of the relevant competent authority referred to in Article 46 from each Member State;\n(c)\tthe Executive Directors of each ESA and one representative from the Commission, from the ESRB, from ECB and from ENISA as observers;\n(d)\twhere appropriate, one additional representative of a competent authority referred to in Article 46 from each Member State as observer;\n(e)\twhere applicable, one representative of the competent authorities designated or established in accordance with Directive (EU) 2022/2555 responsible for the supervision of an essential or important entity subject to that Directive, which has been designated as a critical ICT third-party service provider, as observer.\nThe Oversight Forum may, where appropriate, seek the advice of independent experts appointed in accordance with paragraph 6."},{"ref": "DORA-32.5","theme": "Cadre de surveillance","theme_en": "Oversight Framework","mesure": "Chaque État membre désigne l'autorité compétente dont le membre du personnel sera le représentant de haut niveau visé au paragraphe 4, premier alinéa,","mesure_en": "Each Member State shall designate the relevant competent authority whose staff member shall be the high-level representative referred in paragraph 4, ","description": "Chaque État membre désigne l'autorité compétente dont le membre du personnel sera le représentant de haut niveau visé au paragraphe 4, premier alinéa, point b), et en informe le chef de file de la surveillance.\nLes AES publient sur leur site internet la liste des représentants de haut niveau du personnel actuel de l'autorité compétente concernée désignés par les États membres.","description_en": "Each Member State shall designate the relevant competent authority whose staff member shall be the high-level representative referred in paragraph 4, first subparagraph, point (b), and shall inform the Lead Overseer thereof.\nThe ESAs shall publish on their website the list of high-level representatives from the current staff of the relevant competent authority designated by Member States."},{"ref": "DORA-32.6","theme": "Cadre de surveillance","theme_en": "Oversight Framework","mesure": "Les experts indépendants visés au paragraphe 4, deuxième alinéa, sont nommés par le forum de surveillance à partir d'un vivier d'experts sélectionnés","mesure_en": "The independent experts referred to in paragraph 4, second subparagraph, shall be appointed by the Oversight Forum from a pool of experts selected fol","description": "Les experts indépendants visés au paragraphe 4, deuxième alinéa, sont nommés par le forum de surveillance à partir d'un vivier d'experts sélectionnés à l'issue d'une procédure de candidature publique et transparente.\nLes experts indépendants sont nommés sur la base de leur expertise en matière de stabilité financière, de résilience opérationnelle numérique et de questions de sécurité TIC. Ils agissent de manière indépendante et objective dans le seul intérêt de l'Union dans son ensemble et ne sollicitent ni n'acceptent d'instructions des institutions ou organes de l'Union, d'aucun gouvernement d'un État membre ni d'aucun autre organisme public ou privé.","description_en": "The independent experts referred to in paragraph 4, second subparagraph, shall be appointed by the Oversight Forum from a pool of experts selected following a public and transparent application process.\nThe independent experts shall be appointed on the basis of their expertise in financial stability, digital operational resilience and ICT security matters. They shall act independently and objectively in the sole interest of the Union as a whole and shall neither seek nor take instructions from Union institutions or bodies, from any government of a Member State or from any other public or private body."},{"ref": "DORA-32.7","theme": "Cadre de surveillance","theme_en": "Oversight Framework","mesure": "Conformément à l'article 16 des règlements (UE) nº 1093/2010, (UE) nº 1094/2010 et (UE) nº 1095/2010, les AES émettent d'ici le 17 juillet 2024, aux","mesure_en": "In accordance with Article 16 of Regulations (EU) No 1093/2010, (EU) No 1094/2010 and (EU) No 1095/2010, the ESAs shall by 17 July 2024 issue, for the","description": "Conformément à l'article 16 des règlements (UE) nº 1093/2010, (UE) nº 1094/2010 et (UE) nº 1095/2010, les AES émettent d'ici le 17 juillet 2024, aux fins de la présente section, des orientations sur la coopération entre les AES et les autorités compétentes couvrant les procédures et conditions détaillées pour l'attribution et l'exécution des missions entre les autorités compétentes et les AES et les détails relatifs aux échanges d'informations nécessaires pour que les autorités compétentes assurent le suivi des recommandations adressées en vertu de l'article 35, paragraphe 1, point d), aux prestataires tiers critiques de services TIC.","description_en": "In accordance with Article 16 of Regulations (EU) No 1093/2010, (EU) No 1094/2010 and (EU) No 1095/2010, the ESAs shall by 17 July 2024 issue, for the purposes of this Section, guidelines on the cooperation between the ESAs and the competent authorities covering the detailed procedures and conditions for the allocation and execution of tasks between competent authorities and the ESAs and the details on the exchanges of information which are necessary for competent authorities to ensure the follow-up of recommendations pursuant to Article 35(1), point (d), addressed to critical ICT third-party service providers."},{"ref": "DORA-32.8","theme": "Cadre de surveillance","theme_en": "Oversight Framework","mesure": "Les exigences énoncées dans la présente section sont sans préjudice de l'application de la directive (UE) 2022/2555 et des autres règles de l'Union en","mesure_en": "The requirements set out in this Section shall be without prejudice to the application of Directive (EU) 2022/2555 and of other Union rules on oversig","description": "Les exigences énoncées dans la présente section sont sans préjudice de l'application de la directive (UE) 2022/2555 et des autres règles de l'Union en matière de surveillance applicables aux fournisseurs de services d'informatique en nuage.","description_en": "The requirements set out in this Section shall be without prejudice to the application of Directive (EU) 2022/2555 and of other Union rules on oversight applicable to providers of cloud computing services."},{"ref": "DORA-32.9","theme": "Cadre de surveillance","theme_en": "Oversight Framework","mesure": "Les AES, par l'intermédiaire du comité conjoint et sur la base des travaux préparatoires menés par le forum de surveillance, soumettent chaque année un","mesure_en": "The ESAs, through the Joint Committee and based on preparatory work conducted by the Oversight Forum, shall, on yearly basis, submit a report on the a","description": "Les AES, par l'intermédiaire du comité conjoint et sur la base des travaux préparatoires menés par le forum de surveillance, soumettent chaque année un rapport sur l'application de la présente section au Parlement européen, au Conseil et à la Commission.","description_en": "The ESAs, through the Joint Committee and based on preparatory work conducted by the Oversight Forum, shall, on yearly basis, submit a report on the application of this Section to the European Parliament, the Council and the Commission."},{"ref": "DORA-33.1","theme": "Superviseur principal","theme_en": "Lead Overseer","mesure": "Le chef de file de la surveillance, nommé conformément à l'article 31(1), point b), assure la surveillance des prestataires tiers critiques de services","mesure_en": "The Lead Overseer, appointed in accordance with Article 31(1), point (b), shall conduct the oversight of the assigned critical ICT third-party service","description": "Le chef de file de la surveillance, nommé conformément à l'article 31, paragraphe 1, point b), assure la surveillance des prestataires tiers critiques de services TIC qui lui sont attribués et constitue, aux fins de toutes les questions relatives à la surveillance, le point de contact principal de ces prestataires tiers critiques de services TIC.","description_en": "The Lead Overseer, appointed in accordance with Article 31(1), point (b), shall conduct the oversight of the assigned critical ICT third-party service providers and shall be, for the purposes of all matters related to the oversight, the primary point of contact for those critical ICT third-party service providers."},{"ref": "DORA-33.2","theme": "Superviseur principal","theme_en": "Lead Overseer","mesure": "Aux fins du paragraphe 1, le chef de file de la surveillance évalue si chaque prestataire tiers critique de services TIC a mis en place des règles, pro","mesure_en": "For the purposes of paragraph 1, the Lead Overseer shall assess whether each critical ICT third-party service provider has in place comprehensive, sou","description": "Aux fins du paragraphe 1, le chef de file de la surveillance évalue si chaque prestataire tiers critique de services TIC a mis en place des règles, procédures, mécanismes et dispositifs complets, solides et efficaces pour gérer le risque TIC qu'il peut faire peser sur les entités financières.\nL'évaluation visée au premier alinéa porte principalement sur les services TIC fournis par le prestataire tiers critique de services TIC soutenant les fonctions critiques ou importantes des entités financières. Si nécessaire, cette évaluation s'étend aux services TIC soutenant des fonctions autres que critiques ou importantes.","description_en": "For the purposes of paragraph 1, the Lead Overseer shall assess whether each critical ICT third-party service provider has in place comprehensive, sound and effective rules, procedures, mechanisms and arrangements to manage the ICT risk which it may pose to financial entities.\nThe assessment referred to in the first subparagraph shall focus mainly on ICT services provided by the critical ICT third- party service provider supporting the critical or important functions of financial entities. Where necessary to address all relevant risks, that assessment shall extend to ICT services supporting functions other than those that are critical or important."},{"ref": "DORA-33.3","theme": "Superviseur principal","theme_en": "Lead Overseer","mesure": "L'évaluation visée au paragraphe 2 porte sur :","mesure_en": "The assessment referred to in paragraph 2 shall cover:","description": "L'évaluation visée au paragraphe 2 porte sur :\n(a) les exigences TIC visant à garantir, en particulier, la sécurité, la disponibilité, la continuité, la scalabilité et la qualité des services que le prestataire tiers critique de services TIC fournit aux entités financières, ainsi que la capacité de maintenir en permanence des normes élevées de disponibilité, d'authenticité, d'intégrité ou de confidentialité des données ;\n(b) la sécurité physique contribuant à la sécurité TIC, y compris la sécurité des locaux, des installations et des centres de données ;\n(c) les processus de gestion des risques, y compris les politiques de gestion du risque TIC, la politique de continuité des activités TIC et les plans de réponse et de rétablissement TIC ;\n(d) les dispositifs de gouvernance, y compris une structure organisationnelle avec des lignes de responsabilité et des règles de redevabilité claires, transparentes et cohérentes permettant une gestion efficace du risque TIC ;\n(e) l'identification, le suivi et la notification rapide des incidents significatifs liés aux TIC aux entités financières, la gestion et la résolution de ces incidents.","description_en": "The assessment referred to in paragraph 2 shall cover:\n(a)\tICT requirements to ensure, in particular, the security, availability, continuity, scalability and quality of services which the critical ICT third-party service provider provides to financial entities, as well as the ability to maintain at all times high standards of availability, authenticity, integrity or confidentiality of data;\n(b)\tthe physical security contributing to ensuring the ICT security, including the security of premises, facilities, data centres;\n(c)\tthe risk management processes, including ICT risk management policies, ICT business continuity policy and ICT response and recovery plans;\n(d)\tthe governance arrangements, including an organisational structure with clear, transparent and consistent lines of responsibility and accountability rules enabling effective ICT risk management;\n(e)\tthe identification, monitoring and prompt reporting of material ICT-related incidents to financial entities, the management and r"},{"ref": "DORA-33.4","theme": "Superviseur principal","theme_en": "Lead Overseer","mesure": "Sur la base de l'évaluation visée au paragraphe 2, et en coordination avec le réseau conjoint de surveillance (JON) visé à l'article 34(1), le chef de","mesure_en": "Based on the assessment referred to in paragraph 2, and in coordination with the Joint Oversight Network (JON) referred to in Article 34(1), the Lead ","description": "Sur la base de l'évaluation visée au paragraphe 2, et en coordination avec le réseau conjoint de surveillance (JON) visé à l'article 34, paragraphe 1, le chef de file de la surveillance adopte un plan de surveillance individuel clair, détaillé et motivé décrivant les objectifs de surveillance annuels et les principales actions de surveillance prévues pour chaque prestataire tiers critique de services TIC. Ce plan est communiqué chaque année au prestataire tiers critique de services TIC.\nAvant l'adoption du plan de surveillance, le chef de file de la surveillance communique le projet de plan de surveillance au prestataire tiers critique de services TIC.\nDès réception du projet de plan de surveillance, le prestataire tiers critique de services TIC peut soumettre dans les 15 jours calendaires une déclaration motivée attestant de l'impact attendu sur les clients qui sont des entités ne relevant pas du champ d'application du présent règlement et formulant, le cas échéant, des solutions pour atténuer les risques.","description_en": "Based on the assessment referred to in paragraph 2, and in coordination with the Joint Oversight Network (JON) referred to in Article 34(1), the Lead Overseer shall adopt a clear, detailed and reasoned individual oversight plan describing the annual oversight objectives and the main oversight actions planned for each critical ICT third-party service provider. That plan shall be communicated yearly to the critical ICT third-party service provider.\nPrior to the adoption of the oversight plan, the Lead Overseer shall communicate the draft oversight plan to the critical ICT third-party service provider.\nUpon receipt of the draft oversight plan, the critical ICT third-party service provider may submit a reasoned statement within 15 calendar days evidencing the expected impact on customers which are entities falling outside of the scope of this Regulation and where appropriate, formulating solutions to mitigate risks."},{"ref": "DORA-33.5","theme": "Superviseur principal","theme_en": "Lead Overseer","mesure": "Une fois les plans de surveillance annuels visés au paragraphe 4 adoptés et notifiés aux prestataires tiers critiques de services TIC, les autorités co","mesure_en": "Once the annual oversight plans referred to in paragraph 4 have been adopted and notified to the critical ICT third- party service providers, competen","description": "Une fois les plans de surveillance annuels visés au paragraphe 4 adoptés et notifiés aux prestataires tiers critiques de services TIC, les autorités compétentes ne peuvent prendre de mesures à l'égard de ces prestataires tiers critiques de services TIC qu'en accord avec le chef de file de la surveillance.","description_en": "Once the annual oversight plans referred to in paragraph 4 have been adopted and notified to the critical ICT third- party service providers, competent authorities may take measures concerning such critical ICT third-party service providers only in agreement with the Lead Overseer."},{"ref": "DORA-34.1","theme": "Pouvoirs de surveillance","theme_en": "Oversight Powers","mesure": "Afin de garantir une approche cohérente des activités de surveillance et de permettre des stratégies générales de surveillance coordonnées et des appro","mesure_en": "To ensure a consistent approach to oversight activities and with a view to enabling coordinated general oversight strategies and cohesive operational ","description": "Afin de garantir une approche cohérente des activités de surveillance et de permettre des stratégies générales de surveillance coordonnées et des approches et méthodologies opérationnelles cohérentes, les trois chefs de file de la surveillance nommés conformément à l'article 31, paragraphe 1, point b), mettent en place un JON pour se coordonner entre eux aux stades préparatoires et pour coordonner la conduite des activités de surveillance sur leurs prestataires tiers critiques de services TIC respectifs surveillés, ainsi que dans le cadre de toute action pouvant être nécessaire en vertu de l'article 42.","description_en": "To ensure a consistent approach to oversight activities and with a view to enabling coordinated general oversight strategies and cohesive operational approaches and work methodologies, the three Lead Overseers appointed in accordance with Article 31(1), point (b), shall set up a JON to coordinate among themselves in the preparatory stages and to coordinate the conduct of oversight activities over their respective overseen critical ICT third-party service providers, as well as in the course of any action that may be needed pursuant to Article 42."},{"ref": "DORA-34.2","theme": "Pouvoirs de surveillance","theme_en": "Oversight Powers","mesure": "Aux fins du paragraphe 1, les chefs de file de la surveillance élaborent un protocole de surveillance commun précisant les procédures détaillées à suiv","mesure_en": "For the purposes of paragraph 1, the Lead Overseers shall draw up a common oversight protocol specifying the detailed procedures to be followed for ca","description": "Aux fins du paragraphe 1, les chefs de file de la surveillance élaborent un protocole de surveillance commun précisant les procédures détaillées à suivre pour la coordination quotidienne et pour garantir des échanges et des réactions rapides. Le protocole est révisé périodiquement pour refléter les besoins opérationnels, en particulier l'évolution des modalités pratiques de surveillance.","description_en": "For the purposes of paragraph 1, the Lead Overseers shall draw up a common oversight protocol specifying the detailed procedures to be followed for carrying out the day-to-day coordination and for ensuring swift exchanges and reactions. The protocol shall be periodically revised to reflect operational needs, in particular the evolution of practical oversight arrangements."},{"ref": "DORA-34.3","theme": "Pouvoirs de surveillance","theme_en": "Oversight Powers","mesure": "Les chefs de file de la surveillance peuvent, de manière ponctuelle, faire appel à la BCE et à l'ENISA pour fournir des conseils techniques, partager","mesure_en": "The Lead Overseers may, on an ad-hoc basis, call on the ECB and ENISA to provide technical advice, share hands-on experience or join specific coordina","description": "Les chefs de file de la surveillance peuvent, de manière ponctuelle, faire appel à la BCE et à l'ENISA pour fournir des conseils techniques, partager une expérience pratique ou participer à des réunions de coordination spécifiques du JON.","description_en": "The Lead Overseers may, on an ad-hoc basis, call on the ECB and ENISA to provide technical advice, share hands-on experience or join specific coordination meetings of the JON."},{"ref": "DORA-35.1","theme": "Exercice de la surveillance","theme_en": "Exercise of Oversight","mesure": "Aux fins de l'exécution des missions prévues dans la présente section, le chef de file de la surveillance dispose des pouvoirs suivants à l'égard des p","mesure_en": "For the purposes of carrying out the duties laid down in this Section, the Lead Overseer shall have the following powers in respect of the critical IC","description": "Aux fins de l'exécution des missions prévues dans la présente section, le chef de file de la surveillance dispose des pouvoirs suivants à l'égard des prestataires tiers critiques de services TIC :\n(a) demander toutes les informations et la documentation pertinentes conformément à l'article 37 ;\n(b) mener des enquêtes générales et des inspections conformément aux articles 38 et 39, respectivement ;\n(c) demander, après l'achèvement des activités de surveillance, des rapports précisant les actions prises ou les mesures correctives mises en œuvre par les prestataires tiers critiques de services TIC concernant les recommandations visées au point d) du présent paragraphe ;\n(d) émettre des recommandations sur les domaines visés à l'article 33, paragraphe 3, notamment concernant :\n(i) l'utilisation d'exigences spécifiques de sécurité et de qualité TIC ou de processus, en particulier en ce qui concerne le déploiement de correctifs, de mises à jour, de chiffrement et d'autres mesures de sécurité que le chef de file de la surveillance juge pertinentes pour garantir la sécurité TIC des services fournis aux entités financières.","description_en": "For the purposes of carrying out the duties laid down in this Section, the Lead Overseer shall have the following powers in respect of the critical ICT third-party service providers:\n(a)\tto request all relevant information and documentation in accordance with Article 37;\n(b)\tto conduct general investigations and inspections in accordance with Articles 38 and 39, respectively;\n(c)\tto request, after the completion of the oversight activities, reports specifying the actions that have been taken or the remedies that have been implemented by the critical ICT third-party service providers in relation to the recommendations referred to in point (d) of this paragraph;\n(d)\tto issue recommendations on the areas referred to in Article 33(3), in particular concerning the following:\n(i)\tthe use of specific ICT security and quality requirements or processes, in particular in relation to the roll-out of patches, updates, encryption and other security measures which the Lead Overseer deems relevant fo"},{"ref": "DORA-35.2","theme": "Exercice de la surveillance","theme_en": "Exercise of Oversight","mesure": "Dans l'exercice des pouvoirs visés au présent article, le chef de file de la surveillance doit :","mesure_en": "When exercising the powers referred to in this Article, the Lead Overseer shall:","description": "Dans l'exercice des pouvoirs visés au présent article, le chef de file de la surveillance doit :\n(a) assurer une coordination régulière au sein du JON et, en particulier, rechercher des approches cohérentes, le cas échéant, en matière de surveillance des prestataires tiers critiques de services TIC ;\n(b) tenir dûment compte du cadre établi par la directive (UE) 2022/2555 et, si nécessaire, consulter les autorités compétentes désignées ou établies conformément à cette directive, afin d'éviter la duplication de mesures techniques et organisationnelles pouvant s'appliquer aux prestataires tiers critiques de services TIC en vertu de cette directive ;\n(c) chercher à minimiser, dans la mesure du possible, le risque de perturbation des services fournis par les prestataires tiers critiques de services TIC à des clients qui sont des entités ne relevant pas du champ d'application du présent règlement.","description_en": "When exercising the powers referred to in this Article, the Lead Overseer shall:\n(a)\tensure regular coordination within the JON, and in particular shall seek consistent approaches, as appropriate, with regard to the oversight of critical ICT third-party service providers;\n(b)\ttake due account of the framework established by Directive (EU) 2022/2555 and, where necessary, consult the relevant competent authorities designated or established in accordance with that Directive, in order to avoid duplication of technical and organisational measures that might apply to critical ICT third-party service providers pursuant to that \nDirective;\n(c)\tseek to minimise, to the extent possible, the risk of disruption to services provided by critical ICT third-party service providers to customers that are entities falling outside the scope of this Regulation."},{"ref": "DORA-35.3","theme": "Exercice de la surveillance","theme_en": "Exercise of Oversight","mesure": "Le chef de file de la surveillance consulte le forum de surveillance avant d'exercer les pouvoirs visés au paragraphe 1.","mesure_en": "The Lead Overseer shall consult the Oversight Forum before exercising the powers referred to in paragraph 1.","description": "Le chef de file de la surveillance consulte le forum de surveillance avant d'exercer les pouvoirs visés au paragraphe 1.\nAvant d'émettre des recommandations conformément au paragraphe 1, point d), le chef de file de la surveillance donne au prestataire tiers de services TIC la possibilité de fournir, dans les 30 jours calendaires, des informations pertinentes attestant de l'impact attendu sur les clients qui sont des entités ne relevant pas du champ d'application du présent règlement et, le cas échéant, de formuler des solutions pour atténuer les risques.","description_en": "The Lead Overseer shall consult the Oversight Forum before exercising the powers referred to in paragraph 1.\nBefore issuing recommendations in accordance with paragraph 1, point (d), the Lead Overseer shall give the opportunity to the ICT third-party service provider to provide, within 30 calendar days, relevant information evidencing the expected impact on customers that are entities falling outside the scope of this Regulation and, where appropriate, formulating solutions to mitigate risks."},{"ref": "DORA-35.4","theme": "Exercice de la surveillance","theme_en": "Exercise of Oversight","mesure": "Le chef de file de la surveillance informe le JON du résultat de l'exercice des pouvoirs visés au paragraphe 1, points a) et b). Le chef de file de la","mesure_en": "The Lead Overseer shall inform the JON of the outcome of the exercise of the powers referred to in paragraph 1, points (a) and (b). The Lead Overseer ","description": "Le chef de file de la surveillance informe le JON du résultat de l'exercice des pouvoirs visés au paragraphe 1, points a) et b). Le chef de file de la surveillance transmet sans retard injustifié les rapports visés au paragraphe 1, point c), au JON et aux autorités compétentes des entités financières utilisant les services TIC de ce prestataire tiers critique de services TIC.","description_en": "The Lead Overseer shall inform the JON of the outcome of the exercise of the powers referred to in paragraph 1, points (a) and (b). The Lead Overseer shall, without undue delay, transmit the reports referred to in paragraph 1, point (c), to the JON and to the competent authorities of the financial entities using the ICT services of that critical ICT third-party service provider."},{"ref": "DORA-35.5","theme": "Exercice de la surveillance","theme_en": "Exercise of Oversight","mesure": "Les prestataires tiers critiques de services TIC coopèrent de bonne foi avec le chef de file de la surveillance et l'assistent dans l'accomplissement","mesure_en": "Critical ICT third-party service providers shall cooperate in good faith with the Lead Overseer, and assist it in the fulfilment of its tasks.","description": "Les prestataires tiers critiques de services TIC coopèrent de bonne foi avec le chef de file de la surveillance et l'assistent dans l'accomplissement de ses missions.","description_en": "Critical ICT third-party service providers shall cooperate in good faith with the Lead Overseer, and assist it in the fulfilment of its tasks."},{"ref": "DORA-35.6","theme": "Exercice de la surveillance","theme_en": "Exercise of Oversight","mesure": "En cas de non-conformité totale ou partielle aux mesures à prendre en vertu des pouvoirs visés au paragraphe 1, points a), b) et c), et après l'expira","mesure_en": "In the event of whole or partial non-compliance with the measures required to be taken pursuant to the exercise of the powers under paragraph 1, point","description": "En cas de non-conformité totale ou partielle aux mesures à prendre en vertu des pouvoirs visés au paragraphe 1, points a), b) et c), et après l'expiration d'un délai d'au moins 30 jours calendaires à compter de la date à laquelle le prestataire tiers critique de services TIC a reçu notification des mesures en question, le chef de file de la surveillance adopte une décision imposant une astreinte pour contraindre le prestataire tiers critique de services TIC à se conformer à ces mesures.","description_en": "In the event of whole or partial non-compliance with the measures required to be taken pursuant to the exercise of the powers under paragraph 1, points (a), (b) and (c), and after the expiry of a period of at least 30 calendar days from the date on which the critical ICT third-party service provider received notification of the respective measures, the Lead Overseer shall adopt a decision imposing a periodic penalty payment to compel the critical ICT third-party service provider to comply with those measures."},{"ref": "DORA-35.7","theme": "Exercice de la surveillance","theme_en": "Exercise of Oversight","mesure": "L'astreinte visée au paragraphe 6 est imposée quotidiennement jusqu'à ce que la conformité soit atteinte et pour une durée maximale de six mois suivant","mesure_en": "The periodic penalty payment referred to in paragraph 6 shall be imposed on a daily basis until compliance is achieved and for no more than a period o","description": "L'astreinte visée au paragraphe 6 est imposée quotidiennement jusqu'à ce que la conformité soit atteinte et pour une durée maximale de six mois suivant la notification de la décision d'imposition de l'astreinte au prestataire tiers critique de services TIC.","description_en": "The periodic penalty payment referred to in paragraph 6 shall be imposed on a daily basis until compliance is achieved and for no more than a period of six months following the notification of the decision to impose a periodic penalty payment to the critical ICT third-party service provider."},{"ref": "DORA-35.8","theme": "Exercice de la surveillance","theme_en": "Exercise of Oversight","mesure": "Le montant de l'astreinte, calculé à partir de la date fixée dans la décision d'imposition de l'astreinte, peut atteindre 1 % du chiffre d'affaires mo","mesure_en": "The amount of the periodic penalty payment, calculated from the date stipulated in the decision imposing the periodic penalty payment, shall be up to ","description": "Le montant de l'astreinte, calculé à partir de la date fixée dans la décision d'imposition de l'astreinte, peut atteindre 1 % du chiffre d'affaires mondial journalier moyen du prestataire tiers critique de services TIC au cours de l'exercice précédent. Pour déterminer le montant de l'astreinte, le chef de file de la surveillance tient compte des critères suivants concernant la non-conformité aux mesures visées au paragraphe 6 :\n(a) la gravité et la durée de la non-conformité ;\n(b) le caractère intentionnel ou négligent de la non-conformité ;\n(c) le niveau de coopération du prestataire tiers de services TIC avec le chef de file de la surveillance.\nAux fins du premier alinéa, afin de garantir une approche cohérente, le chef de file de la surveillance engage une consultation au sein du JON.","description_en": "The amount of the periodic penalty payment, calculated from the date stipulated in the decision imposing the periodic penalty payment, shall be up to 1 % of the average daily worldwide turnover of the critical ICT third-party service provider in the preceding business year. When determining the amount of the penalty payment, the Lead Overseer shall take into account the following criteria regarding non-compliance with the measures referred to in paragraph 6:\n(a)\tthe gravity and the duration of non-compliance;\n(b)\twhether non-compliance has been committed intentionally or negligently;\n(c)\tthe level of cooperation of the ICT third-party service provider with the Lead Overseer.\nFor the purposes of the first subparagraph, in order to ensure a consistent approach, the Lead Overseer shall engage in consultation within the JON."},{"ref": "DORA-35.9","theme": "Exercice de la surveillance","theme_en": "Exercise of Oversight","mesure": "Les astreintes sont de nature administrative et sont exécutoires. L'exécution est régie par les règles de procédure civile en vigueur dans l'État membr","mesure_en": "Penalty payments shall be of an administrative nature and shall be enforceable. Enforcement shall be governed by the rules of civil procedure in force","description": "Les astreintes sont de nature administrative et sont exécutoires. L'exécution est régie par les règles de procédure civile en vigueur dans l'État membre sur le territoire duquel les inspections et l'accès doivent être effectués. Les juridictions de l'État membre concerné sont compétentes pour les plaintes relatives à une conduite irrégulière de l'exécution. Les montants des astreintes sont affectés au budget général de l'Union européenne.","description_en": "Penalty payments shall be of an administrative nature and shall be enforceable. Enforcement shall be governed by the rules of civil procedure in force in the Member State on the territory of which inspections and access shall be carried out. Courts of the Member State concerned shall have jurisdiction over complaints related to irregular conduct of enforcement. The amounts of the penalty payments shall be allocated to the general budget of the European Union."},{"ref": "DORA-35.10","theme": "Exercice de la surveillance","theme_en": "Exercise of Oversight","mesure": "Le chef de file de la surveillance rend publique toute astreinte imposée, sauf si cette publication est de nature à porter gravement atteinte aux march","mesure_en": "The Lead Overseer shall disclose to the public every periodic penalty payment that has been imposed, unless such disclosure would seriously jeopardise","description": "Le chef de file de la surveillance rend publique toute astreinte imposée, sauf si cette publication est de nature à porter gravement atteinte aux marchés financiers ou à causer un préjudice disproportionné aux parties concernées.","description_en": "The Lead Overseer shall disclose to the public every periodic penalty payment that has been imposed, unless such disclosure would seriously jeopardise the financial markets or cause disproportionate damage to the parties involved."},{"ref": "DORA-35.11","theme": "Exercice de la surveillance","theme_en": "Exercise of Oversight","mesure": "Avant d'imposer une astreinte en vertu du paragraphe 6, le chef de file de la surveillance donne aux représentants du prestataire tiers critique de ser","mesure_en": "Before imposing a periodic penalty payment under paragraph 6, the Lead Overseer shall give the representatives of the critical ICT third-party service","description": "Avant d'imposer une astreinte en vertu du paragraphe 6, le chef de file de la surveillance donne aux représentants du prestataire tiers critique de services TIC faisant l'objet de la procédure la possibilité d'être entendus sur les constatations et ne fonde ses décisions que sur les constatations sur lesquelles le prestataire tiers critique de services TIC faisant l'objet de la procédure a eu la possibilité de formuler des observations.\nLes droits de la défense des personnes faisant l'objet de la procédure sont pleinement respectés au cours de la procédure. Le prestataire tiers critique de services TIC faisant l'objet de la procédure a le droit d'accéder au dossier, sous réserve de l'intérêt légitime d'autres personnes à la protection de leurs secrets d'affaires. Le droit d'accès au dossier ne s'étend pas aux informations confidentielles ni aux documents préparatoires internes du chef de file de la surveillance.","description_en": "Before imposing a periodic penalty payment under paragraph 6, the Lead Overseer shall give the representatives of the critical ICT third-party service provider subject to the proceedings the opportunity to be heard on the findings and shall base its decisions only on findings on which the critical ICT third-party service provider subject to the proceedings has had an opportunity to comment.\nThe rights of the defence of the persons subject to the proceedings shall be fully respected in the proceedings. The critical ICT third-party service provider subject to the proceedings shall be entitled to have access to the file, subject to the legitimate interest of other persons in the protection of their business secrets. The right of access to the file shall not extend to confidential information or to the Lead Overseer’s internal preparatory documents."},{"ref": "DORA-36.1","theme": "Rôle des autorités compétentes","theme_en": "Competent Authorities Role","mesure": "Lorsque les objectifs de surveillance ne peuvent être atteints en interagissant avec la filiale créée aux fins de l'article 31(12), ou en exerçant des","mesure_en": "When oversight objectives cannot be attained by means of interacting with the subsidiary set up for the purpose of Article 31(12), or by exercising ov","description": "Lorsque les objectifs de surveillance ne peuvent être atteints en interagissant avec la filiale créée aux fins de l'article 31, paragraphe 12, ou en exerçant des activités de surveillance dans des locaux situés dans l'Union, le chef de file de la surveillance peut exercer les pouvoirs visés dans les dispositions suivantes dans tout local situé dans un pays tiers qui est détenu ou utilisé de quelque manière que ce soit, aux fins de la fourniture de services aux entités financières de l'Union, par un prestataire tiers critique de services TIC, dans le cadre de ses opérations, fonctions ou services commerciaux, y compris tout bureau administratif, commercial ou opérationnel, local, terrain, bâtiment ou autre propriété : (a) à l'article 35, paragraphe 1, point a) ; et\n(b) à l'article 35, paragraphe 1, point b), conformément à l'article 38, paragraphe 2, points a), b) et d), et à l'article 39, paragraphes 1 et 2, point a).\nL'exercice des pouvoirs visés au premier alinéa est soumis à l'ensemble des conditions suivantes :\n(i) la conduite d'une inspection dans un pays tiers est jugée nécessaire.","description_en": "When oversight objectives cannot be attained by means of interacting with the subsidiary set up for the purpose of Article 31(12), or by exercising oversight activities on premises located in the Union, the Lead Overseer may exercise the powers, referred to in the following provisions, on any premises located in a third-country which is owned, or used in any way, for the purposes of providing services to Union financial entities, by a critical ICT third-party service provider, in connection with its business operations, functions or services, including any administrative, business or operational offices, premises, lands, buildings or other properties: (a) in Article 35(1), point (a); and\n(b) in Article 35(1), point (b), in accordance with Article 38(2), points (a), (b) and (d), and in Article 39(1) and (2), point (a).\nThe powers referred to in the first subparagraph may be exercised subject to all of the following conditions:\n(i)\tthe conduct of an inspection in a third-country is deeme"},{"ref": "DORA-36.2","theme": "Rôle des autorités compétentes","theme_en": "Competent Authorities Role","mesure": "Sans préjudice des compétences respectives des institutions de l'Union et des États membres, aux fins du paragraphe 1, l'ABE, l'AEMF ou l'AEAPP conclu","mesure_en": "Without prejudice to the respective competences of the Union institutions and of Member States, for the purposes of paragraph 1, EBA, ESMA or EIOPA sh","description": "Sans préjudice des compétences respectives des institutions de l'Union et des États membres, aux fins du paragraphe 1, l'ABE, l'AEMF ou l'AEAPP conclut des accords de coopération administrative avec l'autorité compétente du pays tiers concerné afin de permettre le bon déroulement des inspections dans le pays tiers concerné par le chef de file de la surveillance et son équipe désignée pour sa mission dans ce pays tiers. Ces accords de coopération ne créent pas d'obligations juridiques à l'égard de l'Union et de ses États membres et n'empêchent pas les États membres et leurs autorités compétentes de conclure des accords bilatéraux ou multilatéraux avec ces pays tiers et leurs autorités compétentes.\nCes accords de coopération précisent au minimum les éléments suivants :\n(a) les procédures de coordination des activités de surveillance menées en vertu du présent règlement et de tout suivi analogue du risque lié aux tiers TIC dans le secteur financier exercé par l'autorité compétente du pays tiers.","description_en": "Without prejudice to the respective competences of the Union institutions and of Member States, for the purposes of paragraph 1, EBA, ESMA or EIOPA shall conclude administrative cooperation arrangements with the relevant authority of the third country in order to enable the smooth conduct of inspections in the third country concerned by the Lead Overseer and its designated team for its mission in that third country. Those cooperation arrangements shall not create legal obligations in respect of the Union and its Member States nor shall they prevent Member States and their competent authorities from concluding bilateral or multilateral arrangements with those third countries and their relevant authorities.\nThose cooperation arrangements shall specify at least the following elements:\n(a)\tthe procedures for the coordination of oversight activities carried out under this Regulation and any analogous monitoring of ICT third-party risk in the financial sector exercised by the relevant author"},{"ref": "DORA-36.3","theme": "Rôle des autorités compétentes","theme_en": "Competent Authorities Role","mesure": "Lorsque le chef de file de la surveillance n'est pas en mesure de mener les activités de surveillance en dehors de l'Union visées aux paragraphes 1 et","mesure_en": "When the Lead Overseer is not able to conduct oversight activities outside the Union, referred to in paragraphs 1 and 2, the Lead Overseer shall:","description": "Lorsque le chef de file de la surveillance n'est pas en mesure de mener les activités de surveillance en dehors de l'Union visées aux paragraphes 1 et 2, le chef de file de la surveillance :\n(a) exerce ses pouvoirs en vertu de l'article 35 sur la base de l'ensemble des faits et documents dont il dispose ;\n(b) documente et explique les conséquences de son incapacité à mener les activités de surveillance envisagées visées au présent article.\nLes conséquences potentielles visées au point b) du présent paragraphe sont prises en considération dans les recommandations émises par le chef de file de la surveillance en vertu de l'article 35, paragraphe 1, point d).","description_en": "When the Lead Overseer is not able to conduct oversight activities outside the Union, referred to in paragraphs 1 and 2, the Lead Overseer shall:\n(a)\texercise its powers under Article 35 on the basis of all facts and documents available to it;\n(b)\tdocument and explain any consequence of its inability to conduct the envisaged oversight activities as referred to in this Article.\nThe potential consequences referred to in point (b) of this paragraph shall be taken into consideration in the Lead Overseer’s recommendations issued pursuant to Article 35(1), point (d)."},{"ref": "DORA-37.1","theme": "Coopération","theme_en": "Cooperation","mesure": "Le chef de file de la surveillance peut, par simple demande ou par décision, exiger des prestataires tiers critiques de services TIC qu'ils fournissent","mesure_en": "The Lead Overseer may, by simple request or by decision, require critical ICT third-party service providers to provide all information that is necessa","description": "Le chef de file de la surveillance peut, par simple demande ou par décision, exiger des prestataires tiers critiques de services TIC qu'ils fournissent toutes les informations nécessaires à l'exercice de ses missions en vertu du présent règlement, y compris tous les documents commerciaux ou opérationnels pertinents, les contrats, les politiques, la documentation, les rapports d'audit de sécurité TIC, les rapports d'incidents liés aux TIC, ainsi que toute information relative aux parties auxquelles le prestataire tiers critique de services TIC a sous-traité des fonctions ou activités opérationnelles.","description_en": "The Lead Overseer may, by simple request or by decision, require critical ICT third-party service providers to provide all information that is necessary for the Lead Overseer to carry out its duties under this Regulation, including all relevant business or operational documents, contracts, policies, documentation, ICT security audit reports, ICT-related incident reports, as well as any information relating to parties to whom the critical ICT third-party service provider has outsourced operational functions or activities."},{"ref": "DORA-37.2","theme": "Coopération","theme_en": "Cooperation","mesure": "Lorsqu'il envoie une simple demande d'informations en vertu du paragraphe 1, le chef de file de la surveillance doit :","mesure_en": "When sending a simple request for information under paragraph 1, the Lead Overseer shall:","description": "Lorsqu'il envoie une simple demande d'informations en vertu du paragraphe 1, le chef de file de la surveillance doit :\n(a) se référer au présent article comme base juridique de la demande ;\n(b) indiquer l'objet de la demande ;\n(c) préciser les informations demandées ;\n(d) fixer un délai dans lequel les informations doivent être fournies ;\n(e) informer le représentant du prestataire tiers critique de services TIC auprès duquel les informations sont demandées qu'il n'est pas tenu de fournir les informations, mais qu'en cas de réponse volontaire à la demande, les informations fournies ne doivent pas être incorrectes ou trompeuses.","description_en": "When sending a simple request for information under paragraph 1, the Lead Overseer shall:\n(a)\trefer to this Article as the legal basis of the request;\n(b)\tstate the purpose of the request;\n(c)\tspecify what information is required;\n(d)\tset a time limit within which the information is to be provided;\n(e)\tinform the representative of the critical ICT third-party service provider from whom the information is requested that he or she is not obliged to provide the information, but in the event of a voluntary reply to the request the information provided must not be incorrect or misleading."},{"ref": "DORA-37.3","theme": "Coopération","theme_en": "Cooperation","mesure": "Lorsqu'il exige par décision la fourniture d'informations en vertu du paragraphe 1, le chef de file de la surveillance doit :","mesure_en": "When requiring by decision to supply information under paragraph 1, the Lead Overseer shall:","description": "Lorsqu'il exige par décision la fourniture d'informations en vertu du paragraphe 1, le chef de file de la surveillance doit :\n(a) se référer au présent article comme base juridique de la demande ;\n(b) indiquer l'objet de la demande ;\n(c) préciser les informations demandées ;\n(d) fixer un délai dans lequel les informations doivent être fournies ;\n(e) indiquer les astreintes prévues à l'article 35, paragraphe 6, en cas de production incomplète des informations requises ou de non-fourniture des informations dans le délai visé au point d) du présent paragraphe ;\n(f) indiquer le droit de former un recours devant la commission de recours de l'AES et de faire réexaminer la décision par la Cour de justice de l'Union européenne (Cour de justice) conformément aux articles 60 et 61 des règlements (UE) nº 1093/2010, (UE) nº 1094/2010 et (UE) nº 1095/2010.","description_en": "When requiring by decision to supply information under paragraph 1, the Lead Overseer shall:\n(a)\trefer to this Article as the legal basis of the request;\n(b)\tstate the purpose of the request;\n(c)\tspecify what information is required;\n(d)\tset a time limit within which the information is to be provided;\n(e)\tindicate the periodic penalty payments provided for in Article 35(6) where the production of the required information is incomplete or when such information is not provided within the time limit referred to in point (d) of this paragraph;\n(f)\tindicate the right to appeal the decision to ESA’s Board of Appeal and to have the decision reviewed by the Court of Justice of the European Union (Court of Justice) in accordance with Articles 60 and 61 of Regulations (EU) No 1093/2010, (EU) No 1094/2010 and (EU) No 1095/2010."},{"ref": "DORA-37.4","theme": "Coopération","theme_en": "Cooperation","mesure": "Les représentants des prestataires tiers critiques de services TIC fournissent les informations demandées. Les avocats dûment mandatés peuvent fournir","mesure_en": "The representatives of the critical ICT third-party service providers shall supply the information requested. Lawyers duly authorised to act may suppl","description": "Les représentants des prestataires tiers critiques de services TIC fournissent les informations demandées. Les avocats dûment mandatés peuvent fournir les informations au nom de leurs clients. Le prestataire tiers critique de services TIC reste pleinement responsable si les informations fournies sont incomplètes, inexactes ou trompeuses.","description_en": "The representatives of the critical ICT third-party service providers shall supply the information requested. Lawyers duly authorised to act may supply the information on behalf of their clients. The critical ICT third-party service provider shall remain fully responsible if the information supplied is incomplete, incorrect or misleading."},{"ref": "DORA-37.5","theme": "Coopération","theme_en": "Cooperation","mesure": "Le chef de file de la surveillance transmet sans délai une copie de la décision de fourniture d'informations aux autorités compétentes des entités fina","mesure_en": "The Lead Overseer shall, without delay, transmit a copy of the decision to supply information to the competent authorities of the financial entities u","description": "Le chef de file de la surveillance transmet sans délai une copie de la décision de fourniture d'informations aux autorités compétentes des entités financières utilisant les services du prestataire tiers critique de services TIC concerné et au JON.","description_en": "The Lead Overseer shall, without delay, transmit a copy of the decision to supply information to the competent authorities of the financial entities using the services of the relevant critical ICT third-party service providers and to the JON."},{"ref": "DORA-38.1","theme": "Échange d'informations","theme_en": "Information Exchange","mesure": "Afin de s'acquitter de ses missions en vertu du présent règlement, le chef de file de la surveillance, assisté de l'équipe d'examen conjointe visée à l","mesure_en": "In order to carry out its duties under this Regulation, the Lead Overseer, assisted by the joint examination team referred to in Article 40(1), may, w","description": "Afin de s'acquitter de ses missions en vertu du présent règlement, le chef de file de la surveillance, assisté de l'équipe d'examen conjointe visée à l'article 40, paragraphe 1, peut, si nécessaire, mener des enquêtes auprès des prestataires tiers critiques de services TIC.","description_en": "In order to carry out its duties under this Regulation, the Lead Overseer, assisted by the joint examination team referred to in Article 40(1), may, where necessary, conduct investigations of critical ICT third-party service providers."},{"ref": "DORA-38.2","theme": "Échange d'informations","theme_en": "Information Exchange","mesure": "Le chef de file de la surveillance a le pouvoir de :","mesure_en": "The Lead Overseer shall have the power to:","description": "Le chef de file de la surveillance a le pouvoir de :\n(a) examiner les registres, données, procédures et tout autre matériel pertinent pour l'exécution de ses missions, quel que soit le support sur lequel ils sont stockés ;\n(b) prendre ou obtenir des copies ou des extraits certifiés conformes de ces registres, données, procédures documentées et de tout autre matériel ;\n(c) convoquer les représentants du prestataire tiers critique de services TIC pour des explications orales ou écrites sur des faits ou des documents relatifs à l'objet et à la finalité de l'enquête et enregistrer les réponses ;\n(d) interroger toute autre personne physique ou morale consentant à être interrogée aux fins de recueillir des informations relatives à l'objet d'une enquête ;\n(e) demander les registres du trafic téléphonique et de données.","description_en": "The Lead Overseer shall have the power to:\n(a)\texamine records, data, procedures and any other material relevant to the execution of its tasks, irrespective of the medium on which they are stored;\n(b)\ttake or obtain certified copies of, or extracts from, such records, data, documented procedures and any other material;\n(c)\tsummon representatives of the critical ICT third-party service provider for oral or written explanations on facts or documents relating to the subject matter and purpose of the investigation and to record the answers;\n(d)\tinterview any other natural or legal person who consents to be interviewed for the purpose of collecting information relating to the subject matter of an investigation;\n(e)\trequest records of telephone and data traffic."},{"ref": "DORA-38.3","theme": "Échange d'informations","theme_en": "Information Exchange","mesure": "Les fonctionnaires et autres personnes autorisés par le chef de file de la surveillance aux fins de l'enquête visée au paragraphe 1 exercent leurs pouv","mesure_en": "The officials and other persons authorised by the Lead Overseer for the purposes of the investigation referred to in paragraph 1 shall exercise their ","description": "Les fonctionnaires et autres personnes autorisés par le chef de file de la surveillance aux fins de l'enquête visée au paragraphe 1 exercent leurs pouvoirs sur présentation d'une autorisation écrite précisant l'objet et la finalité de l'enquête.\nCette autorisation indique également les astreintes prévues à l'article 35, paragraphe 6, en cas de production incomplète des registres, données, procédures documentées ou de tout autre matériel requis, ou lorsque les réponses aux questions posées aux représentants du prestataire tiers de services TIC sont incomplètes.","description_en": "The officials and other persons authorised by the Lead Overseer for the purposes of the investigation referred to in paragraph 1 shall exercise their powers upon production of a written authorisation specifying the subject matter and purpose of the investigation.\nThat authorisation shall also indicate the periodic penalty payments provided for in Article 35(6) where the production of the required records, data, documented procedures or any other material, or the answers to questions asked to representatives of the ICT third-party service provider are not provided or are incomplete."},{"ref": "DORA-38.4","theme": "Échange d'informations","theme_en": "Information Exchange","mesure": "Les représentants des prestataires tiers critiques de services TIC sont tenus de se soumettre aux enquêtes sur la base d'une décision du chef de file d","mesure_en": "The representatives of the critical ICT third-party service providers are required to submit to the investigations on the basis of a decision of the L","description": "Les représentants des prestataires tiers critiques de services TIC sont tenus de se soumettre aux enquêtes sur la base d'une décision du chef de file de la surveillance. La décision précise l'objet et la finalité de l'enquête, les astreintes prévues à l'article 35, paragraphe 6, les voies de recours disponibles en vertu des règlements (UE) nº 1093/2010, (UE) nº 1094/2010 et (UE) nº 1095/2010, et le droit de faire réexaminer la décision par la Cour de justice.","description_en": "The representatives of the critical ICT third-party service providers are required to submit to the investigations on the basis of a decision of the Lead Overseer. The decision shall specify the subject matter and purpose of the investigation, the periodic penalty payments provided for in Article 35(6), the legal remedies available under Regulations (EU) No 1093/2010, (EU) No 1094/2010 and (EU) No 1095/2010, and the right to have the decision reviewed by the Court of Justice."},{"ref": "DORA-38.5","theme": "Échange d'informations","theme_en": "Information Exchange","mesure": "En temps utile avant le début de l'enquête, le chef de file de la surveillance informe les autorités compétentes des entités financières utilisant les","mesure_en": "In good time before the start of the investigation, the Lead Overseer shall inform competent authorities of the financial entities using the ICT servi","description": "En temps utile avant le début de l'enquête, le chef de file de la surveillance informe les autorités compétentes des entités financières utilisant les services TIC de ce prestataire tiers critique de services TIC de l'enquête envisagée et de l'identité des personnes autorisées.\nLe chef de file de la surveillance communique au JON toutes les informations transmises conformément au premier alinéa.","description_en": "In good time before the start of the investigation, the Lead Overseer shall inform competent authorities of the financial entities using the ICT services of that critical ICT third-party service provider of the envisaged investigation and of the identity of the authorised persons.\nThe Lead Overseer shall communicate to the JON all information transmitted pursuant to the first subparagraph."},{"ref": "DORA-39.1","theme": "Partage d'informations","theme_en": "Information Sharing","mesure": "Afin de s'acquitter de ses missions en vertu du présent règlement, le chef de file de la surveillance, assisté des équipes d'examen conjointes visées à","mesure_en": "In order to carry out its duties under this Regulation, the Lead Overseer, assisted by the joint examination teams referred to in Article 40(1), may e","description": "Afin de s'acquitter de ses missions en vertu du présent règlement, le chef de file de la surveillance, assisté des équipes d'examen conjointes visées à l'article 40, paragraphe 1, peut accéder et mener toutes les inspections sur site nécessaires dans tous les locaux commerciaux, terrains ou propriétés des prestataires tiers de services TIC, tels que les sièges sociaux, les centres d'exploitation, les locaux secondaires, ainsi que mener des inspections hors site.\nAux fins de l'exercice des pouvoirs visés au premier alinéa, le chef de file de la surveillance consulte le JON.","description_en": "In order to carry out its duties under this Regulation, the Lead Overseer, assisted by the joint examination teams referred to in Article 40(1), may enter in, and conduct all necessary onsite inspections on, any business premises, land or property of the ICT third-party service providers, such as head offices, operation centres, secondary premises, as well as to conduct off-site inspections.\nFor the purposes of exercising the powers referred to in the first subparagraph, the Lead Overseer shall consult the JON."},{"ref": "DORA-39.2","theme": "Partage d'informations","theme_en": "Information Sharing","mesure": "Les fonctionnaires et autres personnes autorisés par le chef de file de la surveillance à effectuer une inspection sur site ont le pouvoir de :","mesure_en": "The officials and other persons authorised by the Lead Overseer to conduct an on-site inspection shall have the power to:","description": "Les fonctionnaires et autres personnes autorisés par le chef de file de la surveillance à effectuer une inspection sur site ont le pouvoir de :\n(a) accéder à ces locaux commerciaux, terrains ou propriétés ; et\n(b) apposer les scellés sur ces locaux commerciaux, livres ou registres, pour la durée et dans la mesure nécessaires à l'inspection.\nLes fonctionnaires et autres personnes autorisés par le chef de file de la surveillance exercent leurs pouvoirs sur présentation d'une autorisation écrite précisant l'objet et la finalité de l'inspection, ainsi que les astreintes prévues à l'article 35, paragraphe 6, en cas de refus des représentants des prestataires tiers critiques de services TIC concernés de se soumettre à l'inspection.","description_en": "The officials and other persons authorised by the Lead Overseer to conduct an on-site inspection shall have the power to:\n(a)\tenter any such business premises, land or property; and\n(b)\tseal any such business premises, books or records, for the period of, and to the extent necessary for, the inspection.\nThe officials and other persons authorised by the Lead Overseer shall exercise their powers upon production of a written authorisation specifying the subject matter and the purpose of the inspection, and the periodic penalty payments provided for in Article 35(6) where the representatives of the critical ICT third-party service providers concerned do not submit to the inspection"},{"ref": "DORA-39.3","theme": "Partage d'informations","theme_en": "Information Sharing","mesure": "En temps utile avant le début de l'inspection, le chef de file de la surveillance informe les autorités compétentes des entités financières utilisant c","mesure_en": "In good time before the start of the inspection, the Lead Overseer shall inform the competent authorities of the financial entities using that ICT thi","description": "En temps utile avant le début de l'inspection, le chef de file de la surveillance informe les autorités compétentes des entités financières utilisant ce prestataire tiers de services TIC.","description_en": "In good time before the start of the inspection, the Lead Overseer shall inform the competent authorities of the financial entities using that ICT third-party service provider."},{"ref": "DORA-39.4","theme": "Partage d'informations","theme_en": "Information Sharing","mesure": "Les inspections couvrent l'ensemble des systèmes TIC, réseaux, dispositifs, informations et données pertinents utilisés ou contribuant à la fourniture","mesure_en": "Inspections shall cover the full range of relevant ICT systems, networks, devices, information and data either used for, or contributing to, the provi","description": "Les inspections couvrent l'ensemble des systèmes TIC, réseaux, dispositifs, informations et données pertinents utilisés ou contribuant à la fourniture de services TIC aux entités financières.","description_en": "Inspections shall cover the full range of relevant ICT systems, networks, devices, information and data either used for, or contributing to, the provision of ICT services to financial entities."},{"ref": "DORA-39.5","theme": "Partage d'informations","theme_en": "Information Sharing","mesure": "Avant toute inspection sur site prévue, le chef de file de la surveillance donne un préavis raisonnable aux prestataires tiers critiques de services TI","mesure_en": "Before any planned on-site inspection, the Lead Overseer shall give reasonable notice to the critical ICT third-party service providers, unless such n","description": "Avant toute inspection sur site prévue, le chef de file de la surveillance donne un préavis raisonnable aux prestataires tiers critiques de services TIC, sauf si ce préavis n'est pas possible en raison d'une situation d'urgence ou de crise, ou s'il rendrait l'inspection ou l'audit inefficace.","description_en": "Before any planned on-site inspection, the Lead Overseer shall give reasonable notice to the critical ICT third-party service providers, unless such notice is not possible due to an emergency or crisis situation, or if it would lead to a situation where the inspection or audit would no longer be effective."},{"ref": "DORA-39.6","theme": "Partage d'informations","theme_en": "Information Sharing","mesure": "Le prestataire tiers critique de services TIC se soumet aux inspections sur site ordonnées par décision du chef de file de la surveillance. La décision","mesure_en": "The critical ICT third-party service provider shall submit to on-site inspections ordered by decision of the Lead Overseer. The decision shall specify","description": "Le prestataire tiers critique de services TIC se soumet aux inspections sur site ordonnées par décision du chef de file de la surveillance. La décision précise l'objet et la finalité de l'inspection, fixe la date à laquelle l'inspection doit débuter et indique les astreintes prévues à l'article 35, paragraphe 6, les voies de recours disponibles en vertu des règlements (UE) nº 1093/2010, (UE) nº 1094/2010 et (UE) nº 1095/2010, ainsi que le droit de faire réexaminer la décision par la Cour de justice.","description_en": "The critical ICT third-party service provider shall submit to on-site inspections ordered by decision of the Lead Overseer. The decision shall specify the subject matter and purpose of the inspection, fix the date on which the inspection shall begin and shall indicate the periodic penalty payments provided for in Article 35(6), the legal remedies available under Regulations (EU) No 1093/2010, (EU) No 1094/2010 and (EU) No 1095/2010, as well as the right to have the decision reviewed by the Court of Justice."},{"ref": "DORA-39.7","theme": "Partage d'informations","theme_en": "Information Sharing","mesure": "Lorsque les fonctionnaires et autres personnes autorisés par le chef de file de la surveillance constatent qu'un prestataire tiers critique de services","mesure_en": "Where the officials and other persons authorised by the Lead Overseer find that a critical ICT third-party service provider opposes an inspection orde","description": "Lorsque les fonctionnaires et autres personnes autorisés par le chef de file de la surveillance constatent qu'un prestataire tiers critique de services TIC s'oppose à une inspection ordonnée en vertu du présent article, le chef de file de la surveillance informe le prestataire tiers critique de services TIC des conséquences d'une telle opposition, y compris la possibilité pour les autorités compétentes des entités financières concernées d'exiger des entités financières qu'elles résilient les arrangements contractuels conclus avec ce prestataire tiers critique de services TIC.","description_en": "Where the officials and other persons authorised by the Lead Overseer find that a critical ICT third-party service provider opposes an inspection ordered pursuant to this Article, the Lead Overseer shall inform the critical ICT third-party service provider of the consequences of such opposition, including the possibility for competent authorities of the relevant financial entities to require financial entities to terminate the contractual arrangements concluded with that critical ICT third-party service provider."},{"ref": "DORA-40.1","theme": "Renseignements cyber","theme_en": "Cyber Threat Intelligence","mesure": "Lors de la conduite d'activités de surveillance, en particulier d'enquêtes générales ou d'inspections, le chef de file de la surveillance est assisté d","mesure_en": "When conducting oversight activities, in particular general investigations or inspections, the Lead Overseer shall be assisted by a joint examination ","description": "Lors de la conduite d'activités de surveillance, en particulier d'enquêtes générales ou d'inspections, le chef de file de la surveillance est assisté d'une équipe d'examen conjointe constituée pour chaque prestataire tiers critique de services TIC.","description_en": "When conducting oversight activities, in particular general investigations or inspections, the Lead Overseer shall be assisted by a joint examination team established for each critical ICT third-party service provider."},{"ref": "DORA-40.2","theme": "Renseignements cyber","theme_en": "Cyber Threat Intelligence","mesure": "L'équipe d'examen conjointe visée au paragraphe 1 est composée de membres du personnel de :","mesure_en": "The joint examination team referred to in paragraph 1 shall be composed of staff members from:","description": "L'équipe d'examen conjointe visée au paragraphe 1 est composée de membres du personnel de :\n(a) les AES ;\n(b) les autorités compétentes concernées supervisant les entités financières auxquelles le prestataire tiers critique de services TIC fournit des services TIC ;\n(c) l'autorité compétente nationale visée à l'article 32, paragraphe 4, point e), sur une base volontaire ;\n(d) une autorité compétente nationale de l'État membre dans lequel le prestataire tiers critique de services TIC est établi, sur une base volontaire.\nLes membres de l'équipe d'examen conjointe possèdent une expertise en matière de TIC et de risque opérationnel. L'équipe d'examen conjointe travaille sous la coordination d'un membre du personnel désigné du chef de file de la surveillance (le « coordinateur du chef de file de la surveillance »).","description_en": "The joint examination team referred to in paragraph 1 shall be composed of staff members from:\n(a)\tthe ESAs;\n(b)\tthe relevant competent authorities supervising the financial entities to which the critical ICT third-party service provider provides ICT services;\n(c)\tthe national competent authority referred to in Article 32(4), point (e), on a voluntary basis;\n(d)\tone national competent authority from the Member State where the critical ICT third-party service provider is established, on a voluntary basis.\nMembers of the joint examination team shall have expertise in ICT matters and in operational risk. The joint examination team shall work under the coordination of a designated Lead Overseer staff member (the ‘Lead Overseer coordinator’)."},{"ref": "DORA-40.3","theme": "Renseignements cyber","theme_en": "Cyber Threat Intelligence","mesure": "Dans les 3 mois suivant l'achèvement d'une enquête ou d'une inspection, le chef de file de la surveillance, après consultation du forum de surveillance","mesure_en": "Within 3 months of the completion of an investigation or inspection, the Lead Overseer, after consulting the Oversight Forum, shall adopt recommendati","description": "Dans les 3 mois suivant l'achèvement d'une enquête ou d'une inspection, le chef de file de la surveillance, après consultation du forum de surveillance, adopte des recommandations à adresser au prestataire tiers critique de services TIC en vertu des pouvoirs visés à l'article 35.","description_en": "Within 3 months of the completion of an investigation or inspection, the Lead Overseer, after consulting the Oversight Forum, shall adopt recommendations to be addressed to the critical ICT third-party service provider pursuant to the powers referred to in Article 35."},{"ref": "DORA-40.4","theme": "Renseignements cyber","theme_en": "Cyber Threat Intelligence","mesure": "Les recommandations visées au paragraphe 3 sont immédiatement communiquées au prestataire tiers critique de services TIC et aux autorités compétentes","mesure_en": "The recommendations referred to in paragraph 3 shall be immediately communicated to the critical ICT third-party service provider and to the competent","description": "Les recommandations visées au paragraphe 3 sont immédiatement communiquées au prestataire tiers critique de services TIC et aux autorités compétentes des entités financières auxquelles il fournit des services TIC.\nAux fins de l'exercice des activités de surveillance, le chef de file de la surveillance peut prendre en considération toute certification pertinente de tiers et tout rapport d'audit TIC interne ou externe mis à disposition par le prestataire tiers critique de services TIC.","description_en": "The recommendations referred to in paragraph 3 shall be immediately communicated to the critical ICT third-party service provider and to the competent authorities of the financial entities to which it provides ICT services.\nFor the purposes of fulfilling the oversight activities, the Lead Overseer may take into consideration any relevant third-party certifications and ICT third-party internal or external audit reports made available by the critical ICT third-party service provider."},{"ref": "DORA-41.1","theme": "Accords de partage","theme_en": "Sharing Arrangements","mesure": "Les AES, par l'intermédiaire du comité conjoint, élaborent des projets de normes techniques de réglementation pour préciser :","mesure_en": "The ESAs shall, through the Joint Committee, develop draft regulatory technical standards to specify:","description": "Les AES, par l'intermédiaire du comité conjoint, élaborent des projets de normes techniques de réglementation pour préciser :\n(a) les informations à fournir par un prestataire tiers de services TIC dans la demande de désignation volontaire comme critique en vertu de l'article 31, paragraphe 11 ;\n(b) le contenu, la structure et le format des informations à soumettre, divulguer ou communiquer par les prestataires tiers de services TIC conformément à l'article 35, paragraphe 1, y compris le modèle de fourniture d'informations sur les arrangements de sous-traitance ;\n(c) les critères de détermination de la composition de l'équipe d'examen conjointe garantissant une participation équilibrée des membres du personnel des AES et des autorités compétentes concernées, leur désignation, leurs missions et leurs modalités de travail ;\n(d) les détails de l'évaluation par les autorités compétentes des mesures prises par les prestataires tiers critiques de services TIC sur la base des recommandations du chef de file de la surveillance en vertu de l'article 42, paragraphe 3.","description_en": "The ESAs shall, through the Joint Committee, develop draft regulatory technical standards to specify:\n(a)\tthe information to be provided by an ICT third-party service provider in the application for a voluntary request to be designated as critical under Article 31(11);\n(b)\tthe content, structure and format of the information to be submitted, disclosed or reported by the ICT third-party service providers pursuant to Article 35(1), including the template for providing information on subcontracting arrangements;\n(c)\tthe criteria for determining the composition of the joint examination team ensuring a balanced participation of staff members from the ESAs and from the relevant competent authorities, their designation, tasks, and working arrangements.\n(d)\tthe details of the competent authorities’ assessment of the measures taken by critical ICT third-party service providers based on the recommendations of the Lead Overseer pursuant to Article 42(3)."},{"ref": "DORA-41.2","theme": "Accords de partage","theme_en": "Sharing Arrangements","mesure": "Les AES soumettent ces projets de normes techniques de réglementation à la Commission au plus tard le 17 juillet 2024.","mesure_en": "The ESAs shall submit those draft regulatory technical standards to the Commission by 17 July 2024.","description": "Les AES soumettent ces projets de normes techniques de réglementation à la Commission au plus tard le 17 juillet 2024.\nLa Commission est habilitée à compléter le présent règlement en adoptant les normes techniques de réglementation visées au paragraphe 1 conformément à la procédure prévue aux articles 10 à 14 des règlements (UE) nº 1093/2010, (UE) nº 1094/2010 et (UE) nº 1095/2010.","description_en": "The ESAs shall submit those draft regulatory technical standards to the Commission by 17 July 2024.\n\nPower is delegated to the Commission to supplement this Regulation by adopting the regulatory technical standards referred to in paragraph 1 in accordance with the procedure laid down in Articles 10 to 14 of Regulations (EU) No 1093/2010, (EU) No 1094/2010 and (EU) No 1095/2010."},{"ref": "DORA-42.1","theme": "Sanctions","theme_en": "Sanctions","mesure": "Dans les 60 jours calendaires suivant la réception des recommandations émises par le chef de file de la surveillance en vertu de l'article 35(1), point","mesure_en": "Within 60 calendar days of the receipt of the recommendations issued by the Lead Overseer pursuant to Article 35(1), point (d), critical ICT third-par","description": "Dans les 60 jours calendaires suivant la réception des recommandations émises par le chef de file de la surveillance en vertu de l'article 35, paragraphe 1, point d), les prestataires tiers critiques de services TIC notifient au chef de file de la surveillance leur intention de suivre les recommandations ou fournissent une explication motivée pour ne pas les suivre. Le chef de file de la surveillance transmet immédiatement ces informations aux autorités compétentes des entités financières concernées.","description_en": "Within 60 calendar days of the receipt of the recommendations issued by the Lead Overseer pursuant to Article 35(1), point (d), critical ICT third-party service providers shall either notify the Lead Overseer of their intention to follow the recommendations or provide a reasoned explanation for not following such recommendations. The Lead Overseer shall immediately transmit this information to the competent authorities of the financial entities concerned."},{"ref": "DORA-42.2","theme": "Sanctions","theme_en": "Sanctions","mesure": "Le chef de file de la surveillance rend publique la situation dans laquelle un prestataire tiers critique de services TIC ne notifie pas le chef de file","mesure_en": "The Lead Overseer shall publicly disclose where a critical ICT third-party service provider fails to notify the Lead Overseer in accordance with parag","description": "Le chef de file de la surveillance rend publique la situation dans laquelle un prestataire tiers critique de services TIC ne notifie pas le chef de file de la surveillance conformément au paragraphe 1 ou lorsque l'explication fournie par le prestataire tiers critique de services TIC n'est pas jugée suffisante. Les informations publiées divulguent l'identité du prestataire tiers critique de services TIC ainsi que des informations sur le type et la nature de la non-conformité. Ces informations sont limitées à ce qui est pertinent et proportionné aux fins de la sensibilisation du public, sauf si une telle publication causerait un préjudice disproportionné aux parties concernées ou pourrait compromettre gravement le fonctionnement ordonné et l'intégrité des marchés financiers ou la stabilité de tout ou partie du système financier de l'Union.\nLe chef de file de la surveillance notifie au prestataire tiers de services TIC cette publication.","description_en": "The Lead Overseer shall publicly disclose where a critical ICT third-party service provider fails to notify the Lead Overseer in accordance with paragraph 1 or where the explanation provided by the critical ICT third-party service provider is not deemed sufficient. The information published shall disclose the identity of the critical ICT third-party service provider as well as information on the type and nature of the non-compliance. Such information shall be limited to what is relevant and proportionate for the purpose of ensuring public awareness, unless such publication would cause disproportionate damage to the parties involved or could seriously jeopardise the orderly functioning and integrity of financial markets or the stability of the whole or part of the financial system of the Union.\nThe Lead Overseer shall notify the ICT third-party service provider of that public disclosure."},{"ref": "DORA-42.3","theme": "Sanctions","theme_en": "Sanctions","mesure": "Les autorités compétentes informent les entités financières concernées des risques identifiés dans les recommandations adressées aux prestataires tiers","mesure_en": "Competent authorities shall inform the relevant financial entities of the risks identified in the recommendations addressed to critical ICT third-part","description": "Les autorités compétentes informent les entités financières concernées des risques identifiés dans les recommandations adressées aux prestataires tiers critiques de services TIC conformément à l'article 35, paragraphe 1, point d).\nDans le cadre de la gestion du risque lié aux tiers TIC, les entités financières tiennent compte des risques visés au premier alinéa.","description_en": "Competent authorities shall inform the relevant financial entities of the risks identified in the recommendations addressed to critical ICT third-party service providers in accordance with Article 35(1), point (d).\nWhen managing ICT third-party risk, financial entities shall take into account the risks referred to in the first subparagraph."},{"ref": "DORA-42.4","theme": "Sanctions","theme_en": "Sanctions","mesure": "Lorsqu'une autorité compétente estime qu'une entité financière ne prend pas en compte ou ne traite pas suffisamment dans sa gestion du risque lié aux","mesure_en": "Where a competent authority deems that a financial entity fails to take into account or to sufficiently address within its management of ICT third-par","description": "Lorsqu'une autorité compétente estime qu'une entité financière ne prend pas en compte ou ne traite pas suffisamment dans sa gestion du risque lié aux tiers TIC les risques spécifiques identifiés dans les recommandations, elle notifie à l'entité financière la possibilité qu'une décision soit prise, dans les 60 jours calendaires suivant la réception de cette notification, en vertu du paragraphe 6, en l'absence d'arrangements contractuels appropriés visant à traiter ces risques.","description_en": "Where a competent authority deems that a financial entity fails to take into account or to sufficiently address within its management of ICT third-party risk the specific risks identified in the recommendations, it shall notify the financial entity of the possibility of a decision being taken, within 60 calendar days of the receipt of such notification, pursuant to paragraph 6, in the absence of appropriate contractual arrangements aiming to address such risks."},{"ref": "DORA-42.5","theme": "Sanctions","theme_en": "Sanctions","mesure": "Dès réception des rapports visés à l'article 35(1), point c), et avant de prendre une décision visée au paragraphe 6 du présent article, les autorités","mesure_en": "Upon receiving the reports referred to in Article 35(1), point (c), and prior to taking a decision as referred to in paragraph 6 of this Article, comp","description": "Dès réception des rapports visés à l'article 35, paragraphe 1, point c), et avant de prendre une décision visée au paragraphe 6 du présent article, les autorités compétentes peuvent, sur une base volontaire, consulter les autorités compétentes désignées ou établies conformément à la directive (UE) 2022/2555 chargées de la surveillance d'une entité essentielle ou importante soumise à cette directive, qui a été désignée comme prestataire tiers critique de services TIC.","description_en": "Upon receiving the reports referred to in Article 35(1), point (c), and prior to taking a decision as referred to in paragraph 6 of this Article, competent authorities may, on a voluntary basis, consult the competent authorities designated or established in accordance with Directive (EU) 2022/2555 responsible for the supervision of an essential or important entity subject to that Directive, which has been designated as a critical ICT third-party service provider."},{"ref": "DORA-42.6","theme": "Sanctions","theme_en": "Sanctions","mesure": "Les autorités compétentes peuvent, en dernier recours, à la suite de la notification et, le cas échéant, de la consultation visées aux paragraphes 4 et","mesure_en": "Competent authorities may, as a measure of last resort, following the notification and, if appropriate, the consultation as set out in paragraph 4 and","description": "Les autorités compétentes peuvent, en dernier recours, à la suite de la notification et, le cas échéant, de la consultation visées aux paragraphes 4 et 5 du présent article, conformément à l'article 50, prendre une décision exigeant des entités financières qu'elles suspendent temporairement, en tout ou en partie, l'utilisation ou le déploiement d'un service fourni par le prestataire tiers critique de services TIC jusqu'à ce que les risques identifiés dans les recommandations adressées aux prestataires tiers critiques de services TIC aient été traités. Si nécessaire, elles peuvent exiger des entités financières qu'elles résilient, en tout ou en partie, les arrangements contractuels pertinents conclus avec les prestataires tiers critiques de services TIC.","description_en": "Competent authorities may, as a measure of last resort, following the notification and, if appropriate, the consultation as set out in paragraph 4 and 5 of this Article, in accordance with Article 50, take a decision requiring financial entities to temporarily suspend, either in part or completely, the use or deployment of a service provided by the critical ICT third-party service provider until the risks identified in the recommendations addressed to critical ICT third-party service providers have been addressed. Where necessary, they may require financial entities to terminate, in part or completely, the relevant contractual arrangements concluded with the critical ICT third-party service providers."},{"ref": "DORA-42.7","theme": "Sanctions","theme_en": "Sanctions","mesure": "Lorsqu'un prestataire tiers critique de services TIC refuse d'adopter les recommandations, sur la base d'une approche divergente de celle conseillée p","mesure_en": "Where a critical ICT third-party service provider refuses to endorse recommendations, based on a divergent approach from the one advised by the Lead O","description": "Lorsqu'un prestataire tiers critique de services TIC refuse d'adopter les recommandations, sur la base d'une approche divergente de celle conseillée par le chef de file de la surveillance, et qu'une telle approche divergente peut avoir un impact négatif sur un grand nombre d'entités financières, ou sur une partie significative du secteur financier, et que les avertissements individuels émis par les autorités compétentes n'ont pas conduit à des approches cohérentes atténuant le risque potentiel pour la stabilité financière, le chef de file de la surveillance peut, après consultation du forum de surveillance, émettre des avis non contraignants et non publics à l'intention des autorités compétentes, afin de favoriser des mesures de suivi prudentiel cohérentes et convergentes, le cas échéant.","description_en": "Where a critical ICT third-party service provider refuses to endorse recommendations, based on a divergent approach from the one advised by the Lead Overseer, and such a divergent approach may adversely impact a large number of financial entities, or a significant part of the financial sector, and individual warnings issued by competent authorities have not resulted in consistent approaches mitigating the potential risk to financial stability, the Lead Overseer may, after consulting the Oversight Forum, issue non-binding and non-public opinions to competent authorities, in order to promote consistent and convergent supervisory follow-up measures, as appropriate."},{"ref": "DORA-42.8","theme": "Sanctions","theme_en": "Sanctions","mesure": "Dès réception des rapports visés à l'article 35(1), point c), les autorités compétentes, lorsqu'elles prennent une décision visée au paragraphe 6 du p","mesure_en": "Upon receiving the reports referred to in Article 35(1), point (c), competent authorities, when taking a decision as referred to in paragraph 6 of thi","description": "Dès réception des rapports visés à l'article 35, paragraphe 1, point c), les autorités compétentes, lorsqu'elles prennent une décision visée au paragraphe 6 du présent article, tiennent compte du type et de l'ampleur du risque qui n'est pas traité par le prestataire tiers critique de services TIC, ainsi que de la gravité de la non-conformité, eu égard aux critères suivants :\n(a) la gravité et la durée de la non-conformité ;\n(b) si la non-conformité a révélé des faiblesses graves dans les procédures, les systèmes de gestion, la gestion des risques et les contrôles internes du prestataire tiers critique de services TIC ;\n(c) si un délit financier a été facilité, provoqué ou est autrement imputable à la non-conformité ;\n(d) si la non-conformité est intentionnelle ou par négligence ;\n(e) si la suspension ou la résiliation des arrangements contractuels introduit un risque pour la continuité des opérations de l'entité financière malgré les efforts de l'entité financière pour éviter une telle perturbation.","description_en": "Upon receiving the reports referred to in Article 35(1), point (c), competent authorities, when taking a decision as referred to in paragraph 6 of this Article, shall take into account the type and magnitude of risk that is not addressed by the critical ICT third-party service provider, as well as the seriousness of the non-compliance, having regard to the following criteria:\n(a)\tthe gravity and the duration of the non-compliance;\n(b)\twhether the non-compliance has revealed serious weaknesses in the critical ICT third-party service provider’s procedures, management systems, risk management and internal controls;\n(c)\twhether a financial crime was facilitated, occasioned or is otherwise attributable to the non-compliance;\n(d)\twhether the non-compliance has been intentional or negligent;\n(e)\twhether the suspension or termination of the contractual arrangements introduces a risk for continuity of the financial entity’s business operations notwithstanding the financial entity’s efforts to a"},{"ref": "DORA-42.9","theme": "Sanctions","theme_en": "Sanctions","mesure": "La décision visée au paragraphe 6 du présent article est notifiée aux membres du forum de surveillance visés à l'article 32(4), points a), b) et c), e","mesure_en": "The decision referred to in paragraph 6 of this Article shall be notified to the members of the Oversight Forum referred to in Article 32(4), points (","description": "La décision visée au paragraphe 6 du présent article est notifiée aux membres du forum de surveillance visés à l'article 32, paragraphe 4, points a), b) et c), et au JON.\nLes prestataires tiers critiques de services TIC concernés par les décisions visées au paragraphe 6 coopèrent pleinement avec les entités financières impactées, notamment dans le cadre du processus de suspension ou de résiliation de leurs arrangements contractuels.","description_en": "The decision referred to in paragraph 6 of this Article shall be notified to the members of the Oversight Forum referred to in Article 32(4), points (a), (b) and (c), and to the JON.\nThe critical ICT third-party service providers affected by the decisions provided for in paragraph 6 shall fully cooperate with the financial entities impacted, in particular in the context of the process of suspension or termination of their contractual arrangements."},{"ref": "DORA-42.10","theme": "Sanctions","theme_en": "Sanctions","mesure": "Les autorités compétentes informent régulièrement le chef de file de la surveillance des approches et mesures prises dans le cadre de leurs missions pru","mesure_en": "Competent authorities shall regularly inform the Lead Overseer on the approaches and measures taken in their supervisory tasks in relation to financia","description": "Les autorités compétentes informent régulièrement le chef de file de la surveillance des approches et mesures prises dans le cadre de leurs missions prudentielles à l'égard des entités financières ainsi que des arrangements contractuels conclus par les entités financières lorsque les prestataires tiers critiques de services TIC n'ont pas adopté en tout ou en partie les recommandations qui leur ont été adressées par le chef de file de la surveillance.","description_en": "Competent authorities shall regularly inform the Lead Overseer on the approaches and measures taken in their supervisory tasks in relation to financial entities as well as on the contractual arrangements concluded by financial entities where critical ICT third-party service providers have not endorsed in part or entirely recommendations addressed to them by the Lead Overseer."},{"ref": "DORA-42.11","theme": "Sanctions","theme_en": "Sanctions","mesure": "Le chef de file de la surveillance peut, sur demande, fournir des éclaircissements supplémentaires sur les recommandations émises afin de guider les aut","mesure_en": "The Lead Overseer may, upon request, provide further clarifications on the recommendations issued to guide the competent authorities on the follow-up ","description": "Le chef de file de la surveillance peut, sur demande, fournir des éclaircissements supplémentaires sur les recommandations émises afin de guider les autorités compétentes sur les mesures de suivi.","description_en": "The Lead Overseer may, upon request, provide further clarifications on the recommendations issued to guide the competent authorities on the follow-up measures."},{"ref": "DORA-43.1","theme": "Pouvoir de sanction","theme_en": "Sanctioning Powers","mesure": "Le chef de file de la surveillance, conformément à l'acte délégué visé au paragraphe 2 du présent article, facture aux prestataires tiers critiques de","mesure_en": "The Lead Overseer shall, in accordance with the delegated act referred to in paragraph 2 of this Article, charge critical ICT third-party service prov","description": "Le chef de file de la surveillance, conformément à l'acte délégué visé au paragraphe 2 du présent article, facture aux prestataires tiers critiques de services TIC des redevances couvrant intégralement les dépenses nécessaires du chef de file de la surveillance pour la conduite des activités de surveillance en vertu du présent règlement, y compris le remboursement de tous les coûts pouvant résulter des travaux effectués par l'équipe d'examen conjointe visée à l'article 40, ainsi que les coûts des conseils fournis par les experts indépendants visés à l'article 32, paragraphe 4, deuxième alinéa, dans le cadre de questions relevant des activités de surveillance directe.\nLe montant de la redevance facturée à un prestataire tiers critique de services TIC couvre l'ensemble des coûts découlant de l'exécution des missions prévues dans la présente section et est proportionné à son chiffre d'affaires.","description_en": "The Lead Overseer shall, in accordance with the delegated act referred to in paragraph 2 of this Article, charge critical ICT third-party service providers fees that fully cover the Lead Overseer’s necessary expenditure in relation to the conduct of oversight tasks pursuant to this Regulation, including the reimbursement of any costs which may be incurred as a result of work carried out by the joint examination team referred to in Article 40, as well as the costs of advice provided by the independent experts as referred to in Article 32(4), second subparagraph, in relation to matters falling under the remit of direct oversight activities.\nThe amount of a fee charged to a critical ICT third-party service provider shall cover all costs derived from the execution of the duties set out in this Section and shall be proportionate to its turnover."},{"ref": "DORA-43.2","theme": "Pouvoir de sanction","theme_en": "Sanctioning Powers","mesure": "La Commission est habilitée à adopter un acte délégué conformément à l'article 57 afin de compléter le présent règlement en déterminant le montant des","mesure_en": "The Commission is empowered to adopt a delegated act in accordance with Article 57 to supplement this Regulation by determining the amount of the fees","description": "La Commission est habilitée à adopter un acte délégué conformément à l'article 57 afin de compléter le présent règlement en déterminant le montant des redevances et leurs modalités de paiement d'ici le 17 juillet 2024.","description_en": "The Commission is empowered to adopt a delegated act in accordance with Article 57 to supplement this Regulation by determining the amount of the fees and the way in which they are to be paid by 17 July 2024."},{"ref": "DORA-44.1","theme": "Publication des sanctions","theme_en": "Publication of Sanctions","mesure": "Sans préjudice de l'article 36, l'ABE, l'AEMF et l'AEAPP peuvent, conformément à l'article 33 des règlements (UE) nº 1093/2010, (UE) nº 1095/2010 et","mesure_en": "1.\tWithout prejudice to Article 36, EBA, ESMA and EIOPA may, in accordance with Article 33 of Regulations (EU) No 1093/2010, (EU) No 1095/2010 and (EU","description": "Sans préjudice de l'article 36, l'ABE, l'AEMF et l'AEAPP peuvent, conformément à l'article 33 des règlements (UE) nº 1093/2010, (UE) nº 1095/2010 et (UE) nº 1094/2010 respectivement, conclure des accords de coopération administrative avec les autorités réglementaires et de surveillance de pays tiers afin de favoriser la coopération internationale en matière de risque lié aux tiers TIC dans les différents secteurs financiers, notamment en élaborant les meilleures pratiques pour l'examen des pratiques et contrôles de gestion du risque TIC, des mesures d'atténuation et des réponses aux incidents.","description_en": "1.\tWithout prejudice to Article 36, EBA, ESMA and EIOPA may, in accordance with Article 33 of Regulations (EU) No 1093/2010, (EU) No 1095/2010 and (EU) No 1094/2010, respectively, conclude administrative arrangements with third-country regulatory and supervisory authorities to foster international cooperation on ICT third-party risk across different financial sectors, in particular by developing best practices for the review of ICT risk management practices and controls, mitigation measures and incident responses."},{"ref": "DORA-44.2","theme": "Publication des sanctions","theme_en": "Publication of Sanctions","mesure": "Les AES, par l'intermédiaire du comité conjoint, soumettent tous les cinq ans un rapport confidentiel conjoint au Parlement européen, au Conseil et à l","mesure_en": "2.\tThe ESAs shall, through the Joint Committee, submit every five years a joint confidential report to the European Parliament, to the Council and to ","description": "Les AES, par l'intermédiaire du comité conjoint, soumettent tous les cinq ans un rapport confidentiel conjoint au Parlement européen, au Conseil et à la Commission, résumant les conclusions des discussions pertinentes tenues avec les autorités de pays tiers visées au paragraphe 1, en se concentrant sur l'évolution du risque lié aux tiers TIC et les implications pour la stabilité financière, l'intégrité du marché, la protection des investisseurs et le fonctionnement du marché intérieur.","description_en": "2.\tThe ESAs shall, through the Joint Committee, submit every five years a joint confidential report to the European Parliament, to the Council and to the Commission, summarising the findings of relevant discussions held with the third countries’ authorities referred to in paragraph 1, focusing on the evolution of ICT third-party risk and the implications for financial stability, market integrity, investor protection and the functioning of the internal market."},{"ref": "DORA-45.1","theme": "Dispositions transitoires","theme_en": "Transitional Provisions","mesure": "Les entités financières peuvent échanger entre elles des informations et des renseignements sur les cybermenaces, y compris des indicateurs de compromi","mesure_en": "Financial entities may exchange amongst themselves cyber threat information and intelligence, including indicators of compromise, tactics, techniques,","description": "Les entités financières peuvent échanger entre elles des informations et des renseignements sur les cybermenaces, y compris des indicateurs de compromission, des tactiques, techniques et procédures, des alertes de cybersécurité et des outils de configuration, dans la mesure où ce partage d'informations et de renseignements :\n(a) vise à renforcer la résilience opérationnelle numérique des entités financières, notamment en sensibilisant aux cybermenaces, en limitant ou en empêchant la capacité de propagation des cybermenaces, en soutenant les capacités de défense, les techniques de détection des menaces, les stratégies d'atténuation ou les phases de réponse et de rétablissement ;\n(b) a lieu au sein de communautés de confiance d'entités financières ;\n(c) est mis en œuvre par le biais d'accords de partage d'informations qui protègent le caractère potentiellement sensible des informations partagées et sont régis par des règles de conduite dans le plein respect de la confidentialité des affaires, de la protection des données à caractère personnel conformément au règlement (UE) 2016/679 et des lignes directrices en matière de politique de concurrence.","description_en": "Financial entities may exchange amongst themselves cyber threat information and intelligence, including indicators of compromise, tactics, techniques, and procedures, cyber security alerts and configuration tools, to the extent that such information and intelligence sharing:\n(a) aims to enhance the digital operational resilience of financial entities, in particular through raising awareness in relation to cyber threats, limiting or impeding the cyber threats’ ability to spread, supporting defence capabilities, threat detection techniques, mitigation strategies or response and recovery stages;\n(b) takes places within trusted communities of financial entities;\n(c) is implemented through information-sharing arrangements that protect the potentially sensitive nature of the information shared, and that are governed by rules of conduct in full respect of business confidentiality, protection of personal data in accordance with Regulation (EU) 2016/679 and guidelines on competition policy."},{"ref": "DORA-45.2","theme": "Dispositions transitoires","theme_en": "Transitional Provisions","mesure": "Aux fins du paragraphe 1, point c), les accords de partage d'informations définissent les conditions de participation et, le cas échéant, fixent les mo","mesure_en": "For the purpose of paragraph 1, point (c), the information-sharing arrangements shall define the conditions for participation and, where appropriate, ","description": "Aux fins du paragraphe 1, point c), les accords de partage d'informations définissent les conditions de participation et, le cas échéant, fixent les modalités relatives à l'implication des autorités publiques et à la qualité en laquelle elles peuvent être associées aux accords de partage d'informations, à l'implication des prestataires tiers de services TIC, et aux éléments opérationnels, y compris l'utilisation de plateformes informatiques dédiées.","description_en": "For the purpose of paragraph 1, point (c), the information-sharing arrangements shall define the conditions for participation and, where appropriate, shall set out the details on the involvement of public authorities and the capacity in which they may be associated to the information-sharing arrangements, on the involvement of ICT third-party service providers, and on operational elements, including the use of dedicated IT platforms."},{"ref": "DORA-45.3","theme": "Dispositions transitoires","theme_en": "Transitional Provisions","mesure": "Les entités financières notifient aux autorités compétentes leur participation aux accords de partage d'informations visés au paragraphe 1, dès la vali","mesure_en": "Financial entities shall notify competent authorities of their participation in the information-sharing arrangements referred to in paragraph 1, upon ","description": "Les entités financières notifient aux autorités compétentes leur participation aux accords de partage d'informations visés au paragraphe 1, dès la validation de leur adhésion ou, le cas échéant, de la cessation de leur adhésion, une fois que celle-ci prend effet.","description_en": "Financial entities shall notify competent authorities of their participation in the information-sharing arrangements referred to in paragraph 1, upon validation of their membership, or, as applicable, of the cessation of their membership, once it takes effect."}]};
